import { useCallback, useEffect, useMemo, useRef, useState, type CSSProperties } from 'react';
import { Panel, ScrollArea } from '../primitives';
import { OrderBookRow } from '../financial';
import { OrderBookHeader } from './OrderBookHeader';
import { SpreadDisplay } from './SpreadDisplay';
import type { ViewMode } from './OrderBookViewMode';

/* -------------------------------------------------------------------------- */
/*  OrderBookPanel                                                             */
/*  Full order book display: asks (top), spread (center), bids (bottom).       */
/*  Uses --ts-ob-* tokens. Renders OrderBookRow from Phase 0 financial.        */
/* -------------------------------------------------------------------------- */

export interface OrderBookLevel {
  /** Price level. */
  price: number;
  /** Size at this level. */
  size: number;
  /** Cumulative total from best price to this level. */
  total: number;
  /** Whether this level's size recently changed (triggers flash). */
  sizeChanged?: boolean;
}

export interface OrderBookPanelProps {
  /** Instrument symbol. */
  symbol: string;
  /** Ask levels, sorted from best ask (lowest) to highest. */
  asks: OrderBookLevel[];
  /** Bid levels, sorted from best bid (highest) to lowest. */
  bids: OrderBookLevel[];
  /** Maximum cumulative total in the visible book (for depth bar scaling). */
  maxTotal: number;
  /** Current aggregation tick size. */
  aggregation: number;
  /** Available tick sizes. */
  tickSizes: number[];
  /** Called when aggregation changes. */
  onAggregationChange: (tickSize: number) => void;
  /** Current view mode. */
  viewMode: ViewMode;
  /** Called when view mode changes. */
  onViewModeChange: (mode: ViewMode) => void;
  /** Price precision. */
  precision?: number;
  /** Size/quantity precision. */
  sizePrecision?: number;
  /** Called when a price level is clicked. */
  onPriceClick: (price: number, side: 'bid' | 'ask') => void;
  /** Display density mode. */
  densityMode: 'compact' | 'expanded';
}

/* ----- Style injection --------------------------------------------------- */

const OB_PANEL_STYLE_ID = 'ts-order-book-panel-styles';

function ensureOrderBookPanelStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(OB_PANEL_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = OB_PANEL_STYLE_ID;
  sheet.textContent = `
    [data-ts-ob-flash] {
      animation: ts-ob-flash var(--ts-ob-flash-duration, 450ms) ease-out;
    }
    @keyframes ts-ob-flash {
      0% { background-color: var(--ts-depth-row-bg-hover); }
      100% { background-color: transparent; }
    }
    [data-ts-ob-row-wrapper] {
      transition: opacity 0.15s ease-out;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureOrderBookPanelStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const bodyStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
  overflow: 'hidden',
};

const columnHeaderRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-ob-column-header-height)',
  background: 'var(--ts-ob-column-header-bg)',
  color: 'var(--ts-ob-column-header-text)',
  fontSize: 'var(--ts-ob-column-header-font-size)',
  padding: '0 var(--ts-space-2)',
  textTransform: 'uppercase',
  userSelect: 'none',
  flexShrink: 0,
};

const colHeaderCellStyle: CSSProperties = {
  flex: 1,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const sectionStyle: CSSProperties = {
  flex: '1 1 0',
  overflow: 'hidden',
  display: 'flex',
  flexDirection: 'column',
};

const emptyStateStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: '100%',
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-font-sm)',
  fontStyle: 'italic',
  userSelect: 'none',
};

/* ----- Component --------------------------------------------------------- */

export function OrderBookPanel({
  symbol,
  asks,
  bids,
  maxTotal,
  aggregation,
  tickSizes,
  onAggregationChange,
  viewMode,
  onViewModeChange,
  precision = 2,
  sizePrecision = 4,
  onPriceClick,
  densityMode,
}: OrderBookPanelProps): React.JSX.Element {
  const asksBottomRef = useRef<HTMLDivElement>(null);

  const handleAskClick = useCallback(
    (price: number) => {
      onPriceClick(price, 'ask');
    },
    [onPriceClick],
  );

  const handleBidClick = useCallback(
    (price: number) => {
      onPriceClick(price, 'bid');
    },
    [onPriceClick],
  );

  const showTotal = viewMode === 'cumulative' || viewMode === 'depth-bars';

  const bestBid = bids.length > 0 ? bids[0]!.price : 0;
  const bestAsk = asks.length > 0 ? asks[0]!.price : 0;

  const totalBidVolume = useMemo(
    () => bids.reduce((sum, l) => sum + l.size, 0),
    [bids],
  );
  const totalAskVolume = useMemo(
    () => asks.reduce((sum, l) => sum + l.size, 0),
    [asks],
  );

  const reversedAsks = useMemo(() => [...asks].reverse(), [asks]);

  // Auto-scroll asks section so best ask is at the bottom (adjacent to spread).
  // Only scroll on initial data arrival or when asks length changes significantly
  // (e.g., symbol change), NOT on every price/size tick update.
  const prevAsksLenRef = useRef(0);
  const [hasInitialScroll, setHasInitialScroll] = useState(false);
  useEffect(() => {
    const lenDelta = Math.abs(asks.length - prevAsksLenRef.current);
    const isInitial = prevAsksLenRef.current === 0 && asks.length > 0;
    const isSignificantChange = lenDelta > 2;
    prevAsksLenRef.current = asks.length;

    if ((isInitial || isSignificantChange) && asksBottomRef.current?.scrollIntoView) {
      asksBottomRef.current.scrollIntoView({ block: 'end' });
      if (!hasInitialScroll) setHasInitialScroll(true);
    }
  }, [asks.length, hasInitialScroll]);

  const headerActions = (
    <OrderBookHeader
      symbol={symbol}
      aggregation={aggregation}
      tickSizes={tickSizes}
      onAggregationChange={onAggregationChange}
      viewMode={viewMode}
      onViewModeChange={onViewModeChange}
      precision={precision}
    />
  );

  const hasData = bids.length > 0 || asks.length > 0;

  return (
    <div
      data-ts-order-book-panel=""
      data-density={densityMode}
      style={{ display: 'flex', flexDirection: 'column', height: '100%' }}
      data-testid="order-book-panel"
    >
      {headerActions}

      <div style={columnHeaderRowStyle} data-testid="ob-column-headers">
        <span style={colHeaderCellStyle}>Price</span>
        <span style={{ ...colHeaderCellStyle, textAlign: 'right' }}>Size</span>
        {showTotal && (
          <span style={{ ...colHeaderCellStyle, textAlign: 'right' }}>Total</span>
        )}
      </div>

      {!hasData ? (
        <div style={emptyStateStyle} data-testid="ob-empty-state">
          Awaiting orderbook data...
        </div>
      ) : (
        <div style={bodyStyle}>
          <div data-ts-ob-asks="" style={sectionStyle} data-testid="ob-asks">
            <ScrollArea>
              <div style={{ display: 'flex', flexDirection: 'column', justifyContent: 'flex-end', minHeight: '100%' }}>
                {reversedAsks.map((level, index) => (
                  <div
                    key={level.price}
                    data-ts-ob-row-wrapper=""
                    {...(level.sizeChanged ? { 'data-ts-ob-flash': '' } : {})}
                  >
                    <OrderBookRow
                      price={level.price}
                      size={level.size}
                      total={level.total}
                      maxTotal={maxTotal}
                      side="ask"
                      precision={precision}
                      sizePrecision={sizePrecision}
                      isBest={index === reversedAsks.length - 1}
                      onClick={() => handleAskClick(level.price)}
                    />
                  </div>
                ))}
                <div ref={asksBottomRef} />
              </div>
            </ScrollArea>
          </div>

          <SpreadDisplay
            bidPrice={bestBid}
            askPrice={bestAsk}
            precision={precision}
            bidVolume={totalBidVolume}
            askVolume={totalAskVolume}
            showImbalance={densityMode === 'expanded'}
          />

          <div data-ts-ob-bids="" style={sectionStyle} data-testid="ob-bids">
            <ScrollArea>
              {bids.map((level, index) => (
                <div
                  key={level.price}
                  data-ts-ob-row-wrapper=""
                  {...(level.sizeChanged ? { 'data-ts-ob-flash': '' } : {})}
                >
                  <OrderBookRow
                    price={level.price}
                    size={level.size}
                    total={level.total}
                    maxTotal={maxTotal}
                    side="bid"
                    precision={precision}
                    sizePrecision={sizePrecision}
                    isBest={index === 0}
                    onClick={() => handleBidClick(level.price)}
                  />
                </div>
              ))}
            </ScrollArea>
          </div>
        </div>
      )}
    </div>
  );
}

OrderBookPanel.displayName = 'OrderBookPanel';
