import { forwardRef, type CSSProperties, type ReactNode, type ElementRef, type ComponentPropsWithoutRef } from 'react';
import { ContextMenu as ContextMenuPrimitive } from 'radix-ui';
import { ChevronRight } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  ContextMenu                                                               */
/*  Right-click context menu with items, submenus, separators, labels.        */
/*  Wraps Radix ContextMenu — uses --ts-menu-* and --ts-overlay-* tokens.     */
/* -------------------------------------------------------------------------- */

/* ----- Style injection --------------------------------------------------- */

const CONTEXT_MENU_STYLE_ID = 'ts-context-menu-styles';

function ensureContextMenuStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(CONTEXT_MENU_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = CONTEXT_MENU_STYLE_ID;
  sheet.textContent = `
    @keyframes ts-context-menu-fade-in {
      from { opacity: 0; transform: scale(0.96); }
      to { opacity: 1; transform: scale(1); }
    }
    [data-ts-context-menu-content][data-state="open"] {
      animation: ts-context-menu-fade-in 120ms ease-out;
    }
    @media (prefers-reduced-motion: reduce) {
      [data-ts-context-menu-content][data-state="open"] {
        animation: none;
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureContextMenuStyles();
}

/* ----- Shared styles ----------------------------------------------------- */

const menuContentStyle: CSSProperties = {
  background: 'var(--ts-overlay-bg)',
  border: '1px solid var(--ts-overlay-border)',
  borderRadius: 'var(--ts-overlay-radius)',
  boxShadow: 'var(--ts-overlay-shadow)',
  padding: 'var(--ts-menu-padding-y) 0',
  minWidth: 180,
  zIndex: 50,
  outline: 'none',
  boxSizing: 'border-box',
  fontFamily: 'inherit',
};

const menuItemStyle: CSSProperties = {
  all: 'unset',
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-menu-item-height)',
  padding: '0 var(--ts-menu-item-padding-x)',
  fontSize: 'var(--ts-font-md)',
  fontFamily: 'inherit',
  color: 'var(--ts-menu-item-text)',
  cursor: 'pointer',
  userSelect: 'none',
  gap: '8px',
  boxSizing: 'border-box',
  transition: 'background 100ms',
};

const menuItemDangerStyle: CSSProperties = {
  ...menuItemStyle,
  color: 'var(--ts-menu-item-text-danger)',
};

const separatorStyle: CSSProperties = {
  height: 1,
  background: 'var(--ts-menu-separator)',
  margin: 'var(--ts-menu-separator-margin) 0',
};

const labelStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-menu-item-height)',
  padding: '0 var(--ts-menu-item-padding-x)',
  fontSize: 'var(--ts-menu-label-font-size)',
  fontWeight: 'var(--ts-menu-label-font-weight)' as unknown as number,
  fontFamily: 'inherit',
  color: 'var(--ts-menu-label-text)',
  userSelect: 'none',
  boxSizing: 'border-box',
};

const iconSlotStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 16,
  height: 16,
  flexShrink: 0,
  color: 'var(--ts-menu-item-icon)',
};

const shortcutSlotStyle: CSSProperties = {
  marginLeft: 'auto',
  paddingLeft: '16px',
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-menu-item-shortcut)',
  fontFamily: 'inherit',
};

const subTriggerArrowStyle: CSSProperties = {
  marginLeft: 'auto',
  color: 'var(--ts-menu-item-shortcut)',
};

/* ----- ContextMenu.Root -------------------------------------------------- */

type ContextMenuRootProps = ComponentPropsWithoutRef<typeof ContextMenuPrimitive.Root>;

function Root(props: ContextMenuRootProps): React.JSX.Element {
  return <ContextMenuPrimitive.Root {...props} />;
}
Root.displayName = 'ContextMenu';

/* ----- ContextMenu.Trigger ----------------------------------------------- */

type ContextMenuTriggerProps = ComponentPropsWithoutRef<typeof ContextMenuPrimitive.Trigger>;

const ContextMenuTrigger = forwardRef<ElementRef<typeof ContextMenuPrimitive.Trigger>, ContextMenuTriggerProps>(
  (props, ref) => <ContextMenuPrimitive.Trigger ref={ref} asChild {...props} />,
);
ContextMenuTrigger.displayName = 'ContextMenu.Trigger';

/* ----- ContextMenu.Content ----------------------------------------------- */

type ContextMenuContentProps = ComponentPropsWithoutRef<typeof ContextMenuPrimitive.Content>;

const ContextMenuContent = forwardRef<ElementRef<typeof ContextMenuPrimitive.Content>, ContextMenuContentProps>(
  ({ style, ...props }, ref) => (
    <ContextMenuPrimitive.Portal>
      <ContextMenuPrimitive.Content
        ref={ref}
        data-ts-context-menu-content=""
        style={{ ...menuContentStyle, ...style }}
        {...props}
      />
    </ContextMenuPrimitive.Portal>
  ),
);
ContextMenuContent.displayName = 'ContextMenu.Content';

/* ----- ContextMenu.Item -------------------------------------------------- */

interface ContextMenuItemProps extends ComponentPropsWithoutRef<typeof ContextMenuPrimitive.Item> {
  /** Icon element rendered before the label. */
  icon?: ReactNode;
  /** Keyboard shortcut text rendered at the right edge. */
  shortcut?: string;
  /** Danger variant for destructive actions. */
  danger?: boolean;
}

const ContextMenuItem = forwardRef<ElementRef<typeof ContextMenuPrimitive.Item>, ContextMenuItemProps>(
  ({ icon, shortcut, danger, children, style, onMouseEnter, onMouseLeave, ...props }, ref) => (
    <ContextMenuPrimitive.Item
      ref={ref}
      style={{ ...(danger ? menuItemDangerStyle : menuItemStyle), ...style }}
      onMouseEnter={(e) => {
        e.currentTarget.style.background = 'var(--ts-menu-item-bg-hover)';
        onMouseEnter?.(e);
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.background = 'transparent';
        onMouseLeave?.(e);
      }}
      {...props}
    >
      {icon ? <span style={iconSlotStyle}>{icon}</span> : null}
      <span style={{ flex: 1 }}>{children}</span>
      {shortcut ? <span style={shortcutSlotStyle}>{shortcut}</span> : null}
    </ContextMenuPrimitive.Item>
  ),
);
ContextMenuItem.displayName = 'ContextMenu.Item';

/* ----- ContextMenu.Separator --------------------------------------------- */

type ContextMenuSeparatorProps = ComponentPropsWithoutRef<typeof ContextMenuPrimitive.Separator>;

const ContextMenuSeparator = forwardRef<ElementRef<typeof ContextMenuPrimitive.Separator>, ContextMenuSeparatorProps>(
  ({ style, ...props }, ref) => (
    <ContextMenuPrimitive.Separator
      ref={ref}
      style={{ ...separatorStyle, ...style }}
      {...props}
    />
  ),
);
ContextMenuSeparator.displayName = 'ContextMenu.Separator';

/* ----- ContextMenu.Label ------------------------------------------------- */

type ContextMenuLabelProps = ComponentPropsWithoutRef<typeof ContextMenuPrimitive.Label>;

const ContextMenuLabel = forwardRef<ElementRef<typeof ContextMenuPrimitive.Label>, ContextMenuLabelProps>(
  ({ style, ...props }, ref) => (
    <ContextMenuPrimitive.Label
      ref={ref}
      style={{ ...labelStyle, ...style }}
      {...props}
    />
  ),
);
ContextMenuLabel.displayName = 'ContextMenu.Label';

/* ----- ContextMenu.Sub --------------------------------------------------- */

type ContextMenuSubProps = ComponentPropsWithoutRef<typeof ContextMenuPrimitive.Sub>;

function ContextMenuSub(props: ContextMenuSubProps): React.JSX.Element {
  return <ContextMenuPrimitive.Sub {...props} />;
}
ContextMenuSub.displayName = 'ContextMenu.Sub';

/* ----- ContextMenu.SubTrigger -------------------------------------------- */

interface ContextMenuSubTriggerProps extends ComponentPropsWithoutRef<typeof ContextMenuPrimitive.SubTrigger> {
  /** Icon element rendered before the label. */
  icon?: ReactNode;
}

const ContextMenuSubTrigger = forwardRef<ElementRef<typeof ContextMenuPrimitive.SubTrigger>, ContextMenuSubTriggerProps>(
  ({ icon, children, style, onMouseEnter, onMouseLeave, ...props }, ref) => (
    <ContextMenuPrimitive.SubTrigger
      ref={ref}
      style={{ ...menuItemStyle, ...style }}
      onMouseEnter={(e) => {
        e.currentTarget.style.background = 'var(--ts-menu-item-bg-hover)';
        onMouseEnter?.(e);
      }}
      onMouseLeave={(e) => {
        e.currentTarget.style.background = 'transparent';
        onMouseLeave?.(e);
      }}
      {...props}
    >
      {icon ? <span style={iconSlotStyle}>{icon}</span> : null}
      <span style={{ flex: 1 }}>{children}</span>
      <ChevronRight size={14} style={subTriggerArrowStyle} aria-hidden />
    </ContextMenuPrimitive.SubTrigger>
  ),
);
ContextMenuSubTrigger.displayName = 'ContextMenu.SubTrigger';

/* ----- ContextMenu.SubContent -------------------------------------------- */

type ContextMenuSubContentProps = ComponentPropsWithoutRef<typeof ContextMenuPrimitive.SubContent>;

const ContextMenuSubContent = forwardRef<ElementRef<typeof ContextMenuPrimitive.SubContent>, ContextMenuSubContentProps>(
  ({ style, ...props }, ref) => (
    <ContextMenuPrimitive.Portal>
      <ContextMenuPrimitive.SubContent
        ref={ref}
        data-ts-context-menu-content=""
        sideOffset={2}
        alignOffset={-4}
        style={{ ...menuContentStyle, ...style }}
        {...props}
      />
    </ContextMenuPrimitive.Portal>
  ),
);
ContextMenuSubContent.displayName = 'ContextMenu.SubContent';

/* ----- Compound export --------------------------------------------------- */

export const ContextMenu = Object.assign(Root, {
  Root,
  Trigger: ContextMenuTrigger,
  Content: ContextMenuContent,
  Item: ContextMenuItem,
  Separator: ContextMenuSeparator,
  Label: ContextMenuLabel,
  Sub: ContextMenuSub,
  SubTrigger: ContextMenuSubTrigger,
  SubContent: ContextMenuSubContent,
});
