/** Standard FDC3 intents handled by Deskmodal apps. */
export const STANDARD_INTENTS = {
  /** Display a chart for the given instrument. */
  ViewChart: "ViewChart",
  /** Display a quote/watchlist entry for the given instrument. */
  ViewQuote: "ViewQuote",
  /** Display analysis data for the given instrument. */
  ViewAnalysis: "ViewAnalysis",
} as const;

/** Custom Deskmodal intents for crypto-specific workflows. */
export const CUSTOM_INTENTS = {
  /** Subscribe to real-time price data from the Feeds app. Returns a private channel. */
  SubscribePrices: "deskmodal.SubscribePrices",
  /** Unsubscribe from real-time price data. */
  UnsubscribePrices: "deskmodal.UnsubscribePrices",
  /** Connect to an exchange via the price-feed service. */
  ConnectExchange: "deskmodal.ConnectExchange",
  /** Disconnect from an exchange via the price-feed service. */
  DisconnectExchange: "deskmodal.DisconnectExchange",
  /** Query the status of the price-feed service. */
  GetStatus: "deskmodal.GetStatus",
  /** Request historical OHLCV data from the Feeds app. Returns a context with data. */
  GetHistory: "deskmodal.GetHistory",
  /** Store exchange API credentials in the OS keychain via the service. */
  SetCredentials: "deskmodal.SetCredentials",
  /** Display order book / depth of market for the given instrument. */
  ViewDepth: "deskmodal.ViewDepth",
  /** Display liquidation data for the given instrument. */
  ViewLiquidations: "deskmodal.ViewLiquidations",
  /** Display funding rate data for the given instrument. */
  ViewFunding: "deskmodal.ViewFunding",
  /** Create a new alert for the given instrument. */
  CreateAlert: "deskmodal.CreateAlert",
  /** Display on-chain metrics for the given instrument. */
  ViewOnChain: "deskmodal.ViewOnChain",
  /** Subscribe to real-time order book data from the Feeds app. Returns a private channel. */
  GetOrderbook: "deskmodal.GetOrderbook",
  /** Lightweight health check ping for the price-feed service. */
  HealthCheck: "deskmodal.HealthCheck",
  /** Fire-and-forget: prefetch historical data into cache for faster subsequent GetHistory calls. */
  PrepareHistory: "deskmodal.PrepareHistory",
  /** Run an OptiScript indicator on the chart. Raised by the editor app. */
  RunIndicator: "deskmodal.RunIndicator",
  /** Run an OptiScript strategy backtest. Raised by the editor app. */
  RunBacktest: "deskmodal.RunBacktest",
  /** Place a new order via the paper trading service. */
  PlaceOrder: "deskmodal.PlaceOrder",
  /** Cancel an existing order via the paper trading service. */
  CancelOrder: "deskmodal.CancelOrder",
  /** Modify an existing order (price, size, type) via the paper trading service. */
  ModifyOrder: "deskmodal.ModifyOrder",
  /** Query all orders (working + filled) from the paper trading service. */
  GetOrders: "deskmodal.GetOrders",
  /** Query open positions from the paper trading service. */
  GetPositions: "deskmodal.GetPositions",
  /** Query per-exchange balances from the paper trading service. */
  GetBalances: "deskmodal.GetBalances",
  /** Query performance analytics (equity curve, drawdown, Sharpe) from the paper trading service. */
  GetAnalytics: "deskmodal.GetAnalytics",
  /** Reset the paper trading engine — clears all orders, positions, and balances. */
  ResetPaperEngine: "deskmodal.ResetPaperEngine",
  /** Export trade history as CSV/JSON from the paper trading service. */
  ExportTrades: "deskmodal.ExportTrades",
} as const;

/** All Deskmodal intents — standard and custom combined. */
export const INTENTS = { ...STANDARD_INTENTS, ...CUSTOM_INTENTS } as const;

/** Type for any standard intent name. */
export type StandardIntentName =
  (typeof STANDARD_INTENTS)[keyof typeof STANDARD_INTENTS];

/** Type for any custom intent name. */
export type CustomIntentName =
  (typeof CUSTOM_INTENTS)[keyof typeof CUSTOM_INTENTS];

/** Type for any Deskmodal intent name. */
export type IntentName = (typeof INTENTS)[keyof typeof INTENTS];

/** Deskmodal app identifiers. */
export const APP_IDS = {
  FEEDS: "deskmodal.feeds",
  CHART: "deskmodal.chart",
  WATCHLIST: "deskmodal.watchlist",
  DEPTH: "deskmodal.depth",
  ANALYTICS: "deskmodal.analytics",
  SCREENER: "deskmodal.screener",
  ALERTS: "deskmodal.alerts",
  EDITOR: "deskmodal.editor",
} as const;

/** Type for any Deskmodal app identifier. */
export type AppId = (typeof APP_IDS)[keyof typeof APP_IDS];

/** Deskmodal service identifiers (background services, not apps). */
export const SERVICE_IDS = {
  PRICE_FEED: "deskmodal.price-feed",
  PAPER_TRADING: "deskmodal.paper-trading",
} as const;

/** Type for any Deskmodal service identifier. */
export type ServiceId = (typeof SERVICE_IDS)[keyof typeof SERVICE_IDS];

/** Maps each intent to the app or service ID that handles it. */
export const INTENT_HANDLERS: Record<IntentName, AppId | ServiceId> = {
  [INTENTS.ViewChart]: APP_IDS.CHART,
  [INTENTS.ViewQuote]: APP_IDS.WATCHLIST,
  [INTENTS.ViewAnalysis]: APP_IDS.ANALYTICS,
  [INTENTS.SubscribePrices]: SERVICE_IDS.PRICE_FEED,
  [INTENTS.UnsubscribePrices]: SERVICE_IDS.PRICE_FEED,
  [INTENTS.ConnectExchange]: SERVICE_IDS.PRICE_FEED,
  [INTENTS.DisconnectExchange]: SERVICE_IDS.PRICE_FEED,
  [INTENTS.GetStatus]: SERVICE_IDS.PRICE_FEED,
  [INTENTS.GetHistory]: SERVICE_IDS.PRICE_FEED,
  [INTENTS.SetCredentials]: SERVICE_IDS.PRICE_FEED,
  [INTENTS.ViewDepth]: APP_IDS.DEPTH,
  [INTENTS.ViewLiquidations]: APP_IDS.ANALYTICS,
  [INTENTS.ViewFunding]: APP_IDS.ANALYTICS,
  [INTENTS.CreateAlert]: APP_IDS.ALERTS,
  [INTENTS.ViewOnChain]: APP_IDS.ANALYTICS,
  [INTENTS.GetOrderbook]: SERVICE_IDS.PRICE_FEED,
  [INTENTS.HealthCheck]: SERVICE_IDS.PRICE_FEED,
  [INTENTS.PrepareHistory]: SERVICE_IDS.PRICE_FEED,
  [INTENTS.RunIndicator]: APP_IDS.CHART,
  [INTENTS.RunBacktest]: APP_IDS.CHART,
  [INTENTS.PlaceOrder]: SERVICE_IDS.PAPER_TRADING,
  [INTENTS.CancelOrder]: SERVICE_IDS.PAPER_TRADING,
  [INTENTS.ModifyOrder]: SERVICE_IDS.PAPER_TRADING,
  [INTENTS.GetOrders]: SERVICE_IDS.PAPER_TRADING,
  [INTENTS.GetPositions]: SERVICE_IDS.PAPER_TRADING,
  [INTENTS.GetBalances]: SERVICE_IDS.PAPER_TRADING,
  [INTENTS.GetAnalytics]: SERVICE_IDS.PAPER_TRADING,
  [INTENTS.ResetPaperEngine]: SERVICE_IDS.PAPER_TRADING,
  [INTENTS.ExportTrades]: SERVICE_IDS.PAPER_TRADING,
};
