import { useCallback, type CSSProperties } from 'react';
import { Panel, Tabs, IconButton } from '../../primitives';
import { LayoutGrid, Table2, Search } from 'lucide-react';
import {
  FilterBar,
  type FilterDefinition,
  type ActiveFilter,
} from './FilterBar';
import { ScreenerTable, type ScreenerColumnDef } from './ScreenerTable';
import { MiniChartGrid } from './MiniChartGrid';
import { ScreenerExport } from './ScreenerExport';
import { EmptyState } from '../../primitives';

/* -------------------------------------------------------------------------- */
/*  ScreenerPanel                                                             */
/*  Full crypto screener with filter bar, column presets, table/grid toggle.  */
/*  Composes Panel, Tabs, FilterBar, ScreenerTable, MiniChartGrid, Export.    */
/*  Uses --ts-screener-panel-* tokens.                                        */
/* -------------------------------------------------------------------------- */

export type ScreenerViewMode = 'table' | 'chart-grid';

export interface ColumnPreset {
  id: string;
  label: string;
  columns: ScreenerColumnDef[];
}

export interface ScreenerPanelProps {
  /** Screener title (e.g., "Crypto Coins Screener"). */
  title: string;
  /** Universe label (e.g., "Crypto universe"). */
  universe: string;
  /** View mode: table or chart grid. */
  viewMode: ScreenerViewMode;
  /** Called when view mode changes. */
  onViewModeChange: (mode: ScreenerViewMode) => void;
  /** Column presets (e.g., Overview, Performance, Valuation). */
  columnPresets: ColumnPreset[];
  /** Currently active column preset ID. */
  activePresetId: string;
  /** Called when column preset changes. */
  onColumnPresetChange: (presetId: string) => void;
  /** Filter definitions. */
  filters: FilterDefinition[];
  /** Active filters. */
  activeFilters: ActiveFilter[];
  /** Called when filters change. */
  onFiltersChange: (filters: ActiveFilter[]) => void;
  /** Data rows for the table. */
  data: Array<Record<string, unknown> & { id: string }>;
  /** Called when a row/card is clicked (broadcasts FDC3 instrument context). */
  onSymbolSelect: (row: Record<string, unknown>) => void;
  /** ID of the currently selected symbol. */
  selectedSymbolId?: string;
  /** Total result count. */
  resultCount?: number;
  /** Export callbacks. */
  onExportCsv?: () => void;
  onCopyToClipboard?: () => void;
  /** Filter presets. */
  filterPresets?: Array<{ id: string; name: string }>;
  selectedFilterPresetId?: string | null;
  onFilterPresetSelect?: (presetId: string) => void;
  onFilterPresetSave?: (name: string) => void;
  onFilterPresetDelete?: (presetId: string) => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-screener-panel-styles';

function ensureScreenerPanelStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-screener-panel] {
      display: flex;
      flex-direction: column;
      height: 100%;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureScreenerPanelStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const contentStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  flex: 1,
  overflow: 'hidden',
};

const tabBarStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  padding: '0 var(--ts-space-3)',
  borderBottom: '1px solid var(--ts-tab-border-bottom, var(--ts-panel-border))',
};

const viewModeToggleStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  marginRight: 'var(--ts-space-2)',
  flexShrink: 0,
};

const tabsContainerStyle: CSSProperties = {
  flex: 1,
  overflow: 'hidden',
};

const universeStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  marginLeft: 'var(--ts-space-2)',
};

const bodyStyle: CSSProperties = {
  flex: 1,
  overflow: 'hidden',
  display: 'flex',
  flexDirection: 'column',
};

/* ----- Component --------------------------------------------------------- */

export function ScreenerPanel({
  title,
  universe,
  viewMode,
  onViewModeChange,
  columnPresets,
  activePresetId,
  onColumnPresetChange,
  filters,
  activeFilters,
  onFiltersChange,
  data,
  onSymbolSelect,
  selectedSymbolId,
  resultCount,
  onExportCsv,
  onCopyToClipboard,
  filterPresets,
  selectedFilterPresetId,
  onFilterPresetSelect,
  onFilterPresetSave,
  onFilterPresetDelete,
}: ScreenerPanelProps): React.JSX.Element {
  const activePreset = columnPresets.find((p) => p.id === activePresetId);
  const activeColumns = activePreset?.columns ?? (columnPresets[0]?.columns ?? []);

  const handleRowClick = useCallback(
    (row: Record<string, unknown>) => {
      onSymbolSelect(row);
    },
    [onSymbolSelect],
  );

  const handleGridItemClick = useCallback(
    (id: string) => {
      const row = data.find((r) => r.id === id);
      if (row !== undefined) {
        onSymbolSelect(row);
      }
    },
    [data, onSymbolSelect],
  );

  const panelActions = (
    <div style={{ display: 'flex', alignItems: 'center', gap: 'var(--ts-space-1)' }}>
      {onExportCsv !== undefined && onCopyToClipboard !== undefined && (
        <ScreenerExport onExportCsv={onExportCsv} onCopyToClipboard={onCopyToClipboard} />
      )}
    </div>
  );

  const miniChartItems = data.map((row) => {
    const symbolVal = row.symbol as { ticker?: string; name?: string; iconUrl?: string } | string | undefined;
    const ticker = typeof symbolVal === 'string' ? symbolVal : (symbolVal?.ticker ?? row.id);
    const name = typeof symbolVal === 'object' && symbolVal !== null ? (symbolVal.name ?? '') : '';
    const iconUrl = typeof symbolVal === 'object' && symbolVal !== null ? symbolVal.iconUrl : undefined;

    return {
      id: row.id,
      ticker,
      name,
      iconUrl,
      price: Number(row.price ?? 0),
      previousPrice: row.previousPrice !== undefined ? Number(row.previousPrice) : undefined,
      change: Number(row.change ?? row.changePercent ?? 0),
      changePercent: Number(row.changePercent ?? 0),
      sparklineData: (row.sparklineData as number[] | undefined) ?? [],
      precision: row.precision !== undefined ? Number(row.precision) : 2,
    };
  });

  return (
    <div data-ts-screener-panel="" style={contentStyle}>
      <Panel
        title={title}
        actions={panelActions}
      >
        <div style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
          <FilterBar
            filters={filters}
            activeFilters={activeFilters}
            onFiltersChange={onFiltersChange}
            resultCount={resultCount}
            presets={filterPresets}
            selectedPresetId={selectedFilterPresetId}
            onPresetSelect={onFilterPresetSelect}
            onPresetSave={onFilterPresetSave}
            onPresetDelete={onFilterPresetDelete}
          />

          <div style={tabBarStyle}>
            <div style={viewModeToggleStyle}>
              <IconButton
                icon={<Table2 size={14} />}
                label="Table view"
                variant="ghost"
                size="sm"
                active={viewMode === 'table'}
                onClick={() => onViewModeChange('table')}
              />
              <IconButton
                icon={<LayoutGrid size={14} />}
                label="Chart grid view"
                variant="ghost"
                size="sm"
                active={viewMode === 'chart-grid'}
                onClick={() => onViewModeChange('chart-grid')}
              />
            </div>

            <div style={tabsContainerStyle}>
              <Tabs value={activePresetId} onValueChange={onColumnPresetChange}>
                <Tabs.List style={{ borderBottom: 'none' }}>
                  {columnPresets.map((preset) => (
                    <Tabs.Trigger key={preset.id} value={preset.id}>
                      {preset.label}
                    </Tabs.Trigger>
                  ))}
                </Tabs.List>
              </Tabs>
            </div>

            <span style={universeStyle}>{universe}</span>
          </div>

          <div style={bodyStyle}>
            {data.length === 0 ? (
              <EmptyState
                icon={<Search size={32} />}
                title="No results found"
                description="Try adjusting your filters to see more results."
              />
            ) : viewMode === 'table' ? (
              <ScreenerTable
                columns={activeColumns}
                data={data}
                onRowClick={handleRowClick}
                selectedRowId={selectedSymbolId}
                resultCount={resultCount}
              />
            ) : (
              <MiniChartGrid
                items={miniChartItems}
                onItemClick={handleGridItemClick}
                selectedItemId={selectedSymbolId}
              />
            )}
          </div>
        </div>
      </Panel>
    </div>
  );
}

ScreenerPanel.displayName = 'ScreenerPanel';
