import { forwardRef, useCallback, type CSSProperties } from 'react';
import { Magnet } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  MagnetControl                                                             */
/*  Toolbar button that cycles through magnet snap modes (none/weak/strong).  */
/*  Uses --ts-button-ghost-*, --ts-accent-* tokens.                           */
/* -------------------------------------------------------------------------- */

export type MagnetMode = 'none' | 'weak' | 'strong';

export interface MagnetControlProps {
  /** Current magnet mode. */
  value: MagnetMode;
  /** Called when magnet mode changes. */
  onValueChange: (mode: MagnetMode) => void;
}

/* ----- Style injection for hover/focus states ----------------------------- */

const MAGNET_STYLE_ID = 'ts-magnet-control-styles';

function ensureMagnetControlStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(MAGNET_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = MAGNET_STYLE_ID;
  sheet.textContent = `
    [data-ts-magnet-control]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-magnet-control]:not([data-active]):hover {
      background: var(--ts-button-ghost-bg-hover);
      color: var(--ts-button-ghost-text-hover);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureMagnetControlStyles();
}

/* ----- Mode label map ---------------------------------------------------- */

const MODE_LABELS: Record<MagnetMode, string> = {
  none: 'Magnet: Off',
  weak: 'Magnet: Weak',
  strong: 'Magnet: Strong',
};

const NEXT_MODE: Record<MagnetMode, MagnetMode> = {
  none: 'weak',
  weak: 'strong',
  strong: 'none',
};

/* ----- Styles ------------------------------------------------------------ */

const baseStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-icon-button-size-sm)',
  height: 'var(--ts-icon-button-size-sm)',
  borderRadius: 'var(--ts-button-radius)',
  cursor: 'pointer',
  flexShrink: 0,
  boxSizing: 'border-box',
  transition: 'background 150ms, color 150ms',
};

function getStyle(isActive: boolean): CSSProperties {
  return {
    ...baseStyle,
    background: isActive ? 'var(--ts-accent-subtle)' : 'var(--ts-button-ghost-bg)',
    color: isActive ? 'var(--ts-accent-default)' : 'var(--ts-button-ghost-text)',
    border: '1px solid var(--ts-button-ghost-border)',
  };
}

export const MagnetControl = forwardRef<HTMLButtonElement, MagnetControlProps>(
  function MagnetControl({ value, onValueChange }, ref) {
    const isActive = value !== 'none';
    const label = MODE_LABELS[value];

    const handleClick = useCallback(() => {
      onValueChange(NEXT_MODE[value]);
    }, [value, onValueChange]);

    return (
      <button
        ref={ref}
        type="button"
        data-ts-magnet-control=""
        {...(isActive ? { 'data-active': '' } : {})}
        style={getStyle(isActive)}
        aria-label={label}
        title={label}
        onClick={handleClick}
      >
        <Magnet size={16} />
      </button>
    );
  },
);

MagnetControl.displayName = 'MagnetControl';
