import { forwardRef, type CSSProperties } from 'react';
import { IconButton, Tooltip } from '../primitives';
import { Undo2, Redo2 } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  UndoRedoButtons                                                           */
/*  Two IconButtons for undo/redo actions with keyboard shortcut tooltips.   */
/*  Uses IconButton + Tooltip with --ts-button-ghost-* tokens.               */
/* -------------------------------------------------------------------------- */

export interface UndoRedoButtonsProps {
  /** Whether undo is available. */
  canUndo: boolean;
  /** Whether redo is available. */
  canRedo: boolean;
  /** Called when undo is triggered. */
  onUndo: () => void;
  /** Called when redo is triggered. */
  onRedo: () => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-undo-redo-styles';

function ensureUndoRedoStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-undo-redo] {
      display: inline-flex;
      align-items: center;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureUndoRedoStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '2px',
  flexShrink: 0,
};

/* ----- Component --------------------------------------------------------- */

export const UndoRedoButtons = forwardRef<HTMLDivElement, UndoRedoButtonsProps>(
  function UndoRedoButtons({ canUndo, canRedo, onUndo, onRedo }, ref) {
    return (
      <div ref={ref} data-ts-undo-redo="" style={containerStyle}>
        <Tooltip content="Undo" shortcut="Ctrl+Z" side="bottom">
          <IconButton
            icon={<Undo2 size={16} />}
            label="Undo"
            variant="ghost"
            size="sm"
            disabled={!canUndo}
            onClick={onUndo}
          />
        </Tooltip>
        <Tooltip content="Redo" shortcut="Ctrl+Y" side="bottom">
          <IconButton
            icon={<Redo2 size={16} />}
            label="Redo"
            variant="ghost"
            size="sm"
            disabled={!canRedo}
            onClick={onRedo}
          />
        </Tooltip>
      </div>
    );
  },
);

UndoRedoButtons.displayName = 'UndoRedoButtons';
