import { useEffect, useRef } from 'react';

/**
 * Debounce delay for session save (ms).
 * Balances responsiveness with localStorage write frequency.
 */
const SAVE_DEBOUNCE_MS = 500;

/**
 * Generic session persistence hook for dock/undock state survival.
 *
 * Persists arbitrary session state to localStorage on every meaningful
 * change (debounced), and restores it on mount. When DeskModal destroys
 * and recreates a WebView during dock/undock transitions, the React app
 * remounts from scratch — this hook ensures state continuity.
 *
 * Pre-public: no schema version field. If the shape of the saved
 * state can't be parsed against the current type, the corrupt blob
 * is silently discarded and defaults take over. Post-public we can
 * revisit adding a migration strategy, but right now every session
 * is built from the same tree and users don't carry persistent state
 * we need to preserve across breaking changes.
 *
 * @param storageKey - Unique localStorage key (e.g. 'deskmodal:depth:session')
 * @param currentState - The current state to persist (serializable to JSON).
 * @param restoreState - Callback to apply restored state on mount.
 * @param deps - Dependency array that triggers a save when changed.
 */
export function useSessionPersistence<T extends Record<string, unknown>>(
  storageKey: string,
  currentState: T,
  restoreState: (saved: T) => void,
  deps: readonly unknown[],
): void {
  const restoredRef = useRef(false);
  const restoreRef = useRef(restoreState);
  restoreRef.current = restoreState;

  // Restore on mount (once)
  useEffect(() => {
    if (restoredRef.current) return;
    restoredRef.current = true;

    try {
      const raw = localStorage.getItem(storageKey);
      if (!raw) return;
      const parsed = JSON.parse(raw) as T;
      restoreRef.current(parsed);
    } catch {
      // Corrupt or incompatible data — discard and fall back to defaults.
      localStorage.removeItem(storageKey);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  // Save on change (debounced)
  useEffect(() => {
    const timer = setTimeout(() => {
      try {
        localStorage.setItem(storageKey, JSON.stringify(currentState));
      } catch {
        // localStorage quota exceeded or unavailable — degrade silently
      }
    }, SAVE_DEBOUNCE_MS);
    return () => clearTimeout(timer);
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, deps);
}
