import { useState, useCallback } from "react";
import type { CryptoInstrumentContext } from "../contexts/instrument";
import { useContextListener } from "./use-context-listener";

/**
 * Hook that returns the current instrument from the user channel.
 * Updates automatically when the instrument context changes.
 *
 * Usage:
 *   const instrument = useInstrument();
 *   // instrument = { type: "fdc3.instrument", id: { ticker: "BTCUSDT" }, ... }
 */
export function useInstrument(): CryptoInstrumentContext | null {
  const [instrument, setInstrument] = useState<CryptoInstrumentContext | null>(
    null
  );

  const handleContext = useCallback(
    (context: CryptoInstrumentContext) => {
      // Guard: only accept well-formed instrument contexts with id.ticker
      if (context && context.id?.ticker) {
        setInstrument(context);
      }
    },
    []
  );

  useContextListener<CryptoInstrumentContext>("fdc3.instrument", handleContext);

  return instrument;
}
