import { useRef, useState, useCallback, useEffect, useMemo } from 'react';
import type { Trade, TradeSide } from '@deskmodal/ui-components';
import type { NormalizedTrade } from '@deskmodal/data-layer';
import {
  DeltaAggregator,
  type DeltaBucket,
  type DeltaAggregatorConfig,
  type BucketMode,
  type ResetMode,
} from '../services/delta-aggregator';
import {
  LargeTradeDetector,
  type SizeTier,
  DEFAULT_SIZE_TIERS,
} from '../services/large-trade-detector';
import type { ClassifiedTrade } from '../components/EnhancedTradeHistory';

/* -------------------------------------------------------------------------- */
/*  useDeltaAggregation                                                        */
/*  React hook wiring DeltaAggregator + LargeTradeDetector to the trade feed. */
/*  Processes incoming Trade objects, classifies them, and provides delta      */
/*  aggregation data to the EnhancedTradeHistory component.                   */
/* -------------------------------------------------------------------------- */

export interface DeltaAggregationState {
  /** Trades with tier classification applied. */
  readonly classifiedTrades: readonly ClassifiedTrade[];
  /** Completed delta buckets. */
  readonly buckets: readonly DeltaBucket[];
  /** In-progress bucket snapshot. */
  readonly currentBucket: DeltaBucket | null;
  /** Current cumulative volume delta. */
  readonly cvdValue: number;
  /** Reset CVD and buckets. */
  readonly resetCVD: () => void;
  /** Update aggregator configuration. */
  readonly setAggregatorConfig: (config: Partial<DeltaAggregatorConfig>) => void;
}

const MAX_CLASSIFIED_TRADES = 500;

/**
 * Batch processing interval for high-frequency trade updates.
 * Rather than re-rendering on every single trade, we batch them
 * and flush state updates at this interval.
 */
const BATCH_FLUSH_INTERVAL_MS = 200;

export function useDeltaAggregation(
  trades: readonly Trade[],
  symbol: string,
): DeltaAggregationState {
  const aggregatorRef = useRef<DeltaAggregator>(new DeltaAggregator());
  const detectorRef = useRef<LargeTradeDetector>(new LargeTradeDetector());

  // Classified trades state
  const [classifiedTrades, setClassifiedTrades] = useState<readonly ClassifiedTrade[]>([]);
  const [buckets, setBuckets] = useState<readonly DeltaBucket[]>([]);
  const [currentBucket, setCurrentBucket] = useState<DeltaBucket | null>(null);
  const [cvdValue, setCvdValue] = useState(0);

  // Track which trades we've already processed (by index into the trades array)
  const processedCountRef = useRef(0);
  const pendingTradesRef = useRef<ClassifiedTrade[]>([]);
  const flushTimerRef = useRef<ReturnType<typeof setInterval> | null>(null);

  // Reset on symbol change
  useEffect(() => {
    aggregatorRef.current.dispose();
    aggregatorRef.current = new DeltaAggregator();
    detectorRef.current.reset();
    processedCountRef.current = 0;
    pendingTradesRef.current = [];
    setClassifiedTrades([]);
    setBuckets([]);
    setCurrentBucket(null);
    setCvdValue(0);
  }, [symbol]);

  // Flush pending state updates to React
  const flush = useCallback(() => {
    const agg = aggregatorRef.current;
    const pending = pendingTradesRef.current;

    if (pending.length > 0) {
      setClassifiedTrades((prev) => {
        const combined = [...pending, ...prev];
        pendingTradesRef.current = [];
        if (combined.length > MAX_CLASSIFIED_TRADES) {
          combined.length = MAX_CLASSIFIED_TRADES;
        }
        return combined;
      });
    }

    setBuckets(agg.getBuckets());
    setCurrentBucket(agg.getCurrentBucket());
    setCvdValue(agg.getCVD());
  }, []);

  // Set up batch flush timer
  useEffect(() => {
    flushTimerRef.current = setInterval(flush, BATCH_FLUSH_INTERVAL_MS);
    return () => {
      if (flushTimerRef.current) {
        clearInterval(flushTimerRef.current);
      }
    };
  }, [flush]);

  // Process new trades as they arrive
  useEffect(() => {
    const agg = aggregatorRef.current;
    const detector = detectorRef.current;

    // trades are newest-first; we process from the end (oldest unprocessed) forward
    const totalTrades = trades.length;
    const alreadyProcessed = processedCountRef.current;

    // If trades array was reset (e.g., symbol change), reset our counter
    if (totalTrades < alreadyProcessed) {
      processedCountRef.current = 0;
    }

    const startIdx = processedCountRef.current;
    if (startIdx >= totalTrades) return;

    // Process new trades: trades array is newest-first,
    // so new trades are at indices 0...(totalTrades - startIdx - 1)
    // We want to process them in chronological order (oldest first)
    const newCount = totalTrades - startIdx;
    const newTrades: ClassifiedTrade[] = [];

    for (let i = newCount - 1; i >= 0; i--) {
      const trade = trades[i];
      if (!trade) continue;

      // Convert to NormalizedTrade for the aggregator
      const normalized: NormalizedTrade = {
        id: trade.id,
        timestamp: new Date(trade.time).getTime(),
        price: trade.price,
        quantity: trade.size,
        side: trade.side,
        buyerMaker: trade.side === 'sell',
      };

      agg.addTrade(normalized);
      const tier = detector.addTrade(trade.size);

      newTrades.push({
        ...trade,
        tier,
        significant: tier.highlight,
      });
    }

    processedCountRef.current = totalTrades;

    // Add to pending queue (newest first)
    newTrades.reverse();
    pendingTradesRef.current = [...newTrades, ...pendingTradesRef.current];
  }, [trades]);

  const resetCVD = useCallback(() => {
    aggregatorRef.current.resetCVD();
    setBuckets([]);
    setCurrentBucket(null);
    setCvdValue(0);
  }, []);

  const setAggregatorConfig = useCallback((config: Partial<DeltaAggregatorConfig>) => {
    aggregatorRef.current.setConfig(config);
    setBuckets(aggregatorRef.current.getBuckets());
    setCurrentBucket(aggregatorRef.current.getCurrentBucket());
    setCvdValue(aggregatorRef.current.getCVD());
  }, []);

  return useMemo(
    () => ({
      classifiedTrades,
      buckets,
      currentBucket,
      cvdValue,
      resetCVD,
      setAggregatorConfig,
    }),
    [classifiedTrades, buckets, currentBucket, cvdValue, resetCVD, setAggregatorConfig],
  );
}
