import { useState, useCallback, useEffect, useRef, type CSSProperties } from 'react';
import '@deskmodal/ui-components/tokens/brand.css';
import '@deskmodal/ui-components/tokens/brand-light.css';
import '@deskmodal/ui-components/tokens/deskmodal-bridge.css';
import '@deskmodal/ui-components/tokens/components.css';
import '@deskmodal/ui-components/tokens/components-light.css';
import {
  AppShell,
  AppHeader,
  OrderBookPanel,
  DepthChart,
  SplitPane,
  ErrorBoundary,
  Toaster,
  toast,
  type ViewMode,
  type TradeSide,
} from '@deskmodal/ui-components';
import { useStateResetNotification } from '../../shared/hooks/use-state-reset-notification';
import { useSessionPersistence } from '../../shared/hooks/use-session-persistence';
import { BarChart3 } from 'lucide-react';
import { useInstrumentListener } from './hooks/use-instrument-listener';
import { useDepthIntent } from './hooks/use-depth-intent';
import { useDeltaAggregation } from './hooks/use-delta-aggregation';
import { EnhancedTradeHistory } from './components/EnhancedTradeHistory';
import { useDropTarget, useFdc3 } from '@deskmodal/fdc3';
import type { Context } from '@deskmodal/fdc3';

/* -------------------------------------------------------------------------- */
/*  Styles                                                                    */
/* -------------------------------------------------------------------------- */

const contentStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
  overflow: 'hidden',
};

const orderBookSectionStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
  overflow: 'hidden',
};

const depthAndTradesSectionStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
  overflow: 'hidden',
};

const depthChartContainerStyle: CSSProperties = {
  flex: 1,
  minHeight: '120px',
  borderBottom: '1px solid var(--ts-panel-border)',
};

const tradesSectionStyle: CSSProperties = {
  flex: 1,
  minHeight: 0,
  overflow: 'hidden',
};

/* -------------------------------------------------------------------------- */
/*  App                                                                       */
/* -------------------------------------------------------------------------- */

export function App(): React.JSX.Element {
  useStateResetNotification((msg) => toast.info({ title: msg, duration: 3000 }));

  const depthData = useInstrumentListener();
  useDepthIntent();

  // Cross-app drop target: accept instrument drops and broadcast to update context.
  const fdc3Agent = useFdc3();

  // Auto-join first user channel so FDC3 broadcasts work in modal windows
  useEffect(() => {
    if (!fdc3Agent) return;
    fdc3Agent.getUserChannels().then((channels) => {
      if (channels && channels.length > 0) {
        fdc3Agent.joinUserChannel(channels[0]!.id).catch(() => {});
      }
    }).catch(() => {});
  }, [fdc3Agent]);

  useDropTarget({
    accepts: ['fdc3.instrument'],
    onDrop: (ctx: Context) => {
      fdc3Agent?.broadcast(ctx).catch(() => {});
    },
  });

  const [aggregation, setAggregation] = useState(depthData.defaultAggregation);
  const [viewMode, setViewMode] = useState<ViewMode>('depth-bars');
  const [sizeFilter, setSizeFilter] = useState(0);
  const [sideFilter, setSideFilter] = useState<TradeSide | null>(null);
  const [paused, setPaused] = useState(false);

  // Session persistence for dock/undock state survival
  useSessionPersistence<{
    viewMode: ViewMode;
    aggregation: number;
    sizeFilter: number;
    sideFilter: TradeSide | null;
  }>(
    'deskmodal:depth:session',
    { viewMode, aggregation, sizeFilter, sideFilter },
    (saved) => {
      if (saved.viewMode) setViewMode(saved.viewMode);
      if (typeof saved.aggregation === 'number') setAggregation(saved.aggregation);
      if (typeof saved.sizeFilter === 'number') setSizeFilter(saved.sizeFilter);
      if (saved.sideFilter !== undefined) setSideFilter(saved.sideFilter);
    },
    [viewMode, aggregation, sizeFilter, sideFilter],
  );

  // Delta aggregation + large trade detection
  const deltaAgg = useDeltaAggregation(depthData.trades, depthData.symbol);

  // BUG 5 fix: sync aggregation when defaultAggregation changes (e.g., new symbol)
  useEffect(() => {
    if (depthData.defaultAggregation) {
      setAggregation(depthData.defaultAggregation);
    }
  }, [depthData.defaultAggregation]);

  // BUG 4 fix: measure container width for DepthChart via ResizeObserver
  const depthChartContainerRef = useRef<HTMLDivElement>(null);
  const [depthChartWidth, setDepthChartWidth] = useState<number | undefined>(undefined);

  useEffect(() => {
    const el = depthChartContainerRef.current;
    if (!el) return;

    const observer = new ResizeObserver((entries) => {
      for (const entry of entries) {
        const w = entry.contentRect.width;
        if (w > 0) setDepthChartWidth(Math.round(w));
      }
    });
    observer.observe(el);
    return () => { observer.disconnect(); };
  }, []);

  const handlePriceClick = useCallback((_price: number, _side: 'bid' | 'ask') => {
    /* Price level click — order entry integration in future phase */
  }, []);

  return (
    <ErrorBoundary level="app">
    <AppShell
      header={
        <AppHeader
          title={`Depth / DOM — ${depthData.symbol}`}
          icon={<BarChart3 size={16} />}
        />
      }
    >
      <div style={contentStyle}>
        <SplitPane direction="vertical" defaultSize={55} minSize={20} maxSize={80}>
          <div style={orderBookSectionStyle}>
            <OrderBookPanel
              symbol={depthData.symbol}
              asks={depthData.asks}
              bids={depthData.bids}
              maxTotal={depthData.maxTotal}
              aggregation={aggregation}
              tickSizes={depthData.tickSizes}
              onAggregationChange={setAggregation}
              viewMode={viewMode}
              onViewModeChange={setViewMode}
              precision={depthData.precision}
              sizePrecision={4}
              onPriceClick={handlePriceClick}
              densityMode="compact"
            />
          </div>
          <div style={depthAndTradesSectionStyle}>
            <div ref={depthChartContainerRef} style={depthChartContainerStyle}>
              <DepthChart
                bids={depthData.depthBids}
                asks={depthData.depthAsk}
                midPrice={depthData.midPrice ?? 0}
                width={depthChartWidth}
                height={200}
                precision={depthData.precision}
              />
            </div>
            <div style={tradesSectionStyle}>
              <EnhancedTradeHistory
                symbol={depthData.symbol}
                trades={deltaAgg.classifiedTrades}
                buckets={deltaAgg.buckets}
                currentBucket={deltaAgg.currentBucket}
                cvdValue={deltaAgg.cvdValue}
                onResetCVD={deltaAgg.resetCVD}
                precision={depthData.precision}
                sizePrecision={4}
                sizeFilter={sizeFilter}
                onSizeFilterChange={setSizeFilter}
                sideFilter={sideFilter}
                onSideFilterChange={setSideFilter}
                paused={paused}
                onPausedChange={setPaused}
                densityMode="compact"
              />
            </div>
          </div>
        </SplitPane>
      </div>
      <Toaster position="bottom-right" theme="dark" />
    </AppShell>
    </ErrorBoundary>
  );
}
