import { forwardRef, type CSSProperties, type ReactNode } from 'react';
import { IconButton } from '../primitives';
import { StatusLine } from '../financial';
import { ChevronUp, ChevronDown } from 'lucide-react';
import { StatusLineGroup } from './StatusLineGroup';

/* -------------------------------------------------------------------------- */
/*  StatusLineOverlay                                                         */
/*  Overlay at top-left of chart showing OHLCV + indicator legends.           */
/*  Uses --ts-status-line-* tokens.                                           */
/* -------------------------------------------------------------------------- */

export interface IndicatorValue {
  /** Indicator identifier. */
  id: string;
  /** Indicator display name (e.g., "Vol", "RSI(14)", "EMA(20)"). */
  name: string;
  /** Key-value pairs for the indicator output (e.g., { value: 14523.5 }). */
  values: Record<string, number>;
  /** Color for the indicator label (matches the chart plot color). */
  color?: string;
  /** Whether this indicator is currently visible. */
  visible?: boolean;
}

export interface StatusLineOverlayProps {
  /** Symbol label shown in the first row. */
  symbol?: string;
  /** Timeframe label (e.g., "1D"). */
  timeframe?: string;
  /** Exchange name. */
  exchange?: string;
  /** OHLCV data for the current bar. */
  ohlcv?: {
    open: number;
    high: number;
    low: number;
    close: number;
    volume: number;
    previousClose: number;
  };
  /** Price display precision. */
  precision?: number;
  /** Active indicators with their current values. */
  indicators?: IndicatorValue[];
  /** Called when the symbol label is clicked (change symbol). */
  onSymbolClick?: () => void;
  /** Called when the timeframe label is clicked (change interval). */
  onTimeframeClick?: () => void;
  /** Called when an indicator's visibility is toggled. */
  onIndicatorVisibilityToggle?: (indicatorId: string) => void;
  /** Called when an indicator's settings button is clicked. */
  onIndicatorSettings?: (indicatorId: string) => void;
  /** Called when an indicator's remove button is clicked. */
  onIndicatorRemove?: (indicatorId: string) => void;
  /** Whether the status line is collapsed. */
  collapsed?: boolean;
  /** Called when the collapse toggle is clicked. */
  onCollapsedChange?: (collapsed: boolean) => void;
  /** Whether the data feeding the status line is stale. */
  stale?: boolean;
  /** Show a performance-reduced warning (LOD 3 emergency mode). */
  performanceWarning?: boolean;
}

/* ----- Style injection for hover/focus states ----------------------------- */

const STATUS_OVERLAY_STYLE_ID = 'ts-status-line-overlay-styles';

function ensureStatusLineOverlayStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STATUS_OVERLAY_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STATUS_OVERLAY_STYLE_ID;
  sheet.textContent = `
    [data-ts-status-line-overlay] [data-ts-header-link]:hover {
      color: var(--ts-text-primary);
      text-decoration: underline;
    }
    [data-ts-status-line-overlay] [data-ts-header-link]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureStatusLineOverlayStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: '2px',
  padding: 'var(--ts-space-2)',
  fontFamily: 'var(--ts-status-line-font)',
  fontSize: 'var(--ts-status-line-font-size)',
  lineHeight: 1.4,
  maxWidth: '100%',
  pointerEvents: 'none',
};

const headerRowStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  flexWrap: 'wrap',
};

const headerLinkStyle: CSSProperties = {
  all: 'unset',
  cursor: 'pointer',
  color: 'var(--ts-text-secondary)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  transition: 'color 150ms',
  pointerEvents: 'auto',
};

const dotSeparatorStyle: CSSProperties = {
  color: 'var(--ts-text-tertiary)',
  userSelect: 'none',
};

const collapseButtonWrapperStyle: CSSProperties = {
  marginLeft: 'var(--ts-space-1)',
  pointerEvents: 'auto',
};

const performanceWarningStyle: CSSProperties = {
  color: 'var(--ts-text-warning, #f59e0b)',
  fontSize: 'var(--ts-status-line-font-size)',
  fontWeight: 500,
  whiteSpace: 'nowrap',
};

export const StatusLineOverlay = forwardRef<HTMLDivElement, StatusLineOverlayProps>(
  function StatusLineOverlay(
    {
      symbol,
      timeframe,
      exchange,
      ohlcv,
      precision = 2,
      indicators,
      onSymbolClick,
      onTimeframeClick,
      onIndicatorVisibilityToggle,
      onIndicatorSettings,
      onIndicatorRemove,
      collapsed = false,
      onCollapsedChange,
      stale = false,
      performanceWarning = false,
    },
    ref,
  ) {
    const headerParts: ReactNode[] = [];

    if (symbol !== undefined) {
      headerParts.push(
        <button
          key="symbol"
          type="button"
          data-ts-header-link=""
          style={headerLinkStyle}
          onClick={onSymbolClick}
          aria-label={`Symbol: ${symbol}`}
        >
          {symbol}
        </button>,
      );
    }

    if (timeframe !== undefined) {
      if (headerParts.length > 0) {
        headerParts.push(
          <span key="sep-tf" style={dotSeparatorStyle} aria-hidden>
            {'·'}
          </span>,
        );
      }
      headerParts.push(
        <button
          key="timeframe"
          type="button"
          data-ts-header-link=""
          style={headerLinkStyle}
          onClick={onTimeframeClick}
          aria-label={`Timeframe: ${timeframe}`}
        >
          {timeframe}
        </button>,
      );
    }

    if (exchange !== undefined) {
      if (headerParts.length > 0) {
        headerParts.push(
          <span key="sep-ex" style={dotSeparatorStyle} aria-hidden>
            {'·'}
          </span>,
        );
      }
      headerParts.push(
        <span key="exchange" style={{ color: 'var(--ts-text-tertiary)' }}>
          {exchange}
        </span>,
      );
    }

    return (
      <div ref={ref} data-ts-status-line-overlay="" style={containerStyle}>
        {/* Row 1: Symbol / Timeframe / Exchange + collapse toggle */}
        {headerParts.length > 0 && (
          <div style={headerRowStyle}>
            {headerParts}
            {performanceWarning && (
              <span
                key="perf-warn"
                style={performanceWarningStyle}
                role="status"
                aria-live="polite"
              >
                Performance reduced
              </span>
            )}
            {onCollapsedChange !== undefined && (
              <span style={collapseButtonWrapperStyle}>
                <IconButton
                  icon={collapsed ? <ChevronDown size={12} /> : <ChevronUp size={12} />}
                  label={collapsed ? 'Expand status line' : 'Collapse status line'}
                  variant="ghost"
                  size="sm"
                  onClick={() => onCollapsedChange(!collapsed)}
                />
              </span>
            )}
          </div>
        )}

        {/* Collapsed: only header visible */}
        {collapsed ? null : (
          <>
            {/* Row 2: OHLCV */}
            {ohlcv !== undefined && (
              <StatusLine
                open={ohlcv.open}
                high={ohlcv.high}
                low={ohlcv.low}
                close={ohlcv.close}
                volume={ohlcv.volume}
                previousClose={ohlcv.previousClose}
                precision={precision}
                stale={stale}
              />
            )}

            {/* Row 3+: Indicator legends */}
            {indicators !== undefined && indicators.length > 0 && (
              <div data-ts-indicator-legend="" style={{ display: 'flex', flexDirection: 'column', gap: '2px' }}>
                {indicators.map((indicator) => (
                  <div key={indicator.id} data-ts-indicator-legend-item="">
                    <StatusLineGroup
                      name={indicator.name}
                      color={indicator.color}
                      values={indicator.values}
                      precision={precision}
                      visible={indicator.visible}
                      onVisibilityToggle={
                        onIndicatorVisibilityToggle
                          ? () => onIndicatorVisibilityToggle(indicator.id)
                          : undefined
                      }
                      onSettings={
                        onIndicatorSettings
                          ? () => onIndicatorSettings(indicator.id)
                          : undefined
                      }
                      onRemove={
                        onIndicatorRemove
                          ? () => onIndicatorRemove(indicator.id)
                          : undefined
                      }
                    />
                  </div>
                ))}
              </div>
            )}
          </>
        )}
      </div>
    );
  },
);

StatusLineOverlay.displayName = 'StatusLineOverlay';
