/* -------------------------------------------------------------------------- */
/*  DeltaAggregator                                                           */
/*  Time- or count-based bucketing of trade flow with delta aggregation,      */
/*  cumulative volume delta (CVD), and per-price-level tracking.              */
/* -------------------------------------------------------------------------- */

import type { NormalizedTrade } from '@deskmodal/data-layer';

/** A single aggregated delta bucket. */
export interface DeltaBucket {
  /** Bucket start timestamp (ms). */
  readonly timestamp: number;
  /** Total buy-side volume in this bucket. */
  readonly buyVolume: number;
  /** Total sell-side volume in this bucket. */
  readonly sellVolume: number;
  /** Net delta: buyVolume - sellVolume. */
  readonly netDelta: number;
  /** Running cumulative volume delta at end of this bucket. */
  readonly cumulativeDelta: number;
  /** Total trades in this bucket. */
  readonly tradeCount: number;
  /** Buy trade count. */
  readonly buyCount: number;
  /** Sell trade count. */
  readonly sellCount: number;
  /** VWAP for this bucket. */
  readonly avgPrice: number;
  /** Largest single trade size in this bucket. */
  readonly maxTradeSize: number;
}

export type BucketMode = 'time' | 'count';
export type ResetMode = 'manual' | 'symbol-change' | 'session';

export interface DeltaAggregatorConfig {
  /** Bucketing strategy: time-based or count-based. */
  readonly mode: BucketMode;
  /** Time bucket duration in ms (default 5000 = 5s). */
  readonly timeBucketMs: number;
  /** Number of trades per count bucket (default 100). */
  readonly countBucketSize: number;
  /** When to reset CVD (default 'manual'). */
  readonly resetMode: ResetMode;
  /** Maximum number of completed buckets to retain (default 500). */
  readonly maxBuckets: number;
}

const DEFAULT_CONFIG: DeltaAggregatorConfig = {
  mode: 'time',
  timeBucketMs: 5000,
  countBucketSize: 100,
  resetMode: 'manual',
  maxBuckets: 500,
};

/** Mutable bucket accumulator used during aggregation. */
interface MutableBucket {
  timestamp: number;
  buyVolume: number;
  sellVolume: number;
  tradeCount: number;
  buyCount: number;
  sellCount: number;
  priceVolumeSum: number;
  totalVolume: number;
  maxTradeSize: number;
}

/** Per-price-level delta tracking for future footprint charts. */
interface PriceLevelDelta {
  buyVolume: number;
  sellVolume: number;
}

function createMutableBucket(timestamp: number): MutableBucket {
  return {
    timestamp,
    buyVolume: 0,
    sellVolume: 0,
    tradeCount: 0,
    buyCount: 0,
    sellCount: 0,
    priceVolumeSum: 0,
    totalVolume: 0,
    maxTradeSize: 0,
  };
}

function sealBucket(bucket: MutableBucket, cumulativeDelta: number): DeltaBucket {
  const netDelta = bucket.buyVolume - bucket.sellVolume;
  const avgPrice = bucket.totalVolume > 0
    ? bucket.priceVolumeSum / bucket.totalVolume
    : 0;

  return {
    timestamp: bucket.timestamp,
    buyVolume: bucket.buyVolume,
    sellVolume: bucket.sellVolume,
    netDelta,
    cumulativeDelta,
    tradeCount: bucket.tradeCount,
    buyCount: bucket.buyCount,
    sellCount: bucket.sellCount,
    avgPrice,
    maxTradeSize: bucket.maxTradeSize,
  };
}

/**
 * Quantize a price to a fixed precision key for the price-level map.
 * Using 8 decimal places to accommodate crypto micro-caps while
 * keeping key granularity manageable.
 */
function priceKey(price: number): number {
  return Math.round(price * 1e8) / 1e8;
}

export class DeltaAggregator {
  private config: DeltaAggregatorConfig;
  private completedBuckets: DeltaBucket[] = [];
  private currentBucket: MutableBucket | null = null;
  private cvd = 0;
  private currentBucketTradeCount = 0;
  private priceLevelDeltas = new Map<number, PriceLevelDelta>();
  private disposed = false;

  constructor(config?: Partial<DeltaAggregatorConfig>) {
    this.config = { ...DEFAULT_CONFIG, ...config };
  }

  /** Process a single trade into the current bucket. */
  addTrade(trade: NormalizedTrade): void {
    if (this.disposed) return;

    const bucketTs = this.computeBucketTimestamp(trade.timestamp);

    // Check if we need to close the current bucket and start a new one
    if (this.currentBucket !== null && this.shouldCloseBucket(bucketTs)) {
      this.closeBucket();
    }

    // Create a new bucket if needed
    if (this.currentBucket === null) {
      this.currentBucket = createMutableBucket(bucketTs);
      this.currentBucketTradeCount = 0;
    }

    // Accumulate trade data
    const qty = trade.quantity;
    if (trade.side === 'buy') {
      this.currentBucket.buyVolume += qty;
      this.currentBucket.buyCount += 1;
    } else {
      this.currentBucket.sellVolume += qty;
      this.currentBucket.sellCount += 1;
    }
    this.currentBucket.tradeCount += 1;
    this.currentBucket.priceVolumeSum += trade.price * qty;
    this.currentBucket.totalVolume += qty;
    if (qty > this.currentBucket.maxTradeSize) {
      this.currentBucket.maxTradeSize = qty;
    }

    this.currentBucketTradeCount += 1;

    // Track per-price-level delta
    const pk = priceKey(trade.price);
    let levelDelta = this.priceLevelDeltas.get(pk);
    if (!levelDelta) {
      levelDelta = { buyVolume: 0, sellVolume: 0 };
      this.priceLevelDeltas.set(pk, levelDelta);
    }
    if (trade.side === 'buy') {
      levelDelta.buyVolume += qty;
    } else {
      levelDelta.sellVolume += qty;
    }

    // For count mode, close bucket when trade count threshold reached
    if (
      this.config.mode === 'count' &&
      this.currentBucketTradeCount >= this.config.countBucketSize
    ) {
      this.closeBucket();
    }
  }

  /** Get all completed (sealed) buckets. */
  getBuckets(): readonly DeltaBucket[] {
    return this.completedBuckets;
  }

  /** Get the in-progress bucket as a sealed snapshot, or null. */
  getCurrentBucket(): DeltaBucket | null {
    if (!this.currentBucket) return null;
    const netDelta = this.currentBucket.buyVolume - this.currentBucket.sellVolume;
    return sealBucket(this.currentBucket, this.cvd + netDelta);
  }

  /** Get the current cumulative volume delta. */
  getCVD(): number {
    if (this.currentBucket) {
      return this.cvd + (this.currentBucket.buyVolume - this.currentBucket.sellVolume);
    }
    return this.cvd;
  }

  /** Reset the cumulative volume delta to zero. */
  resetCVD(): void {
    this.cvd = 0;
    this.completedBuckets = [];
    if (this.currentBucket) {
      this.currentBucket = createMutableBucket(this.currentBucket.timestamp);
      this.currentBucketTradeCount = 0;
    }
  }

  /** Update configuration. Resets all state when mode or bucket size changes. */
  setConfig(config: Partial<DeltaAggregatorConfig>): void {
    const prev = this.config;
    this.config = { ...this.config, ...config };

    // Reset if bucketing mode or size changed
    if (
      config.mode !== undefined && config.mode !== prev.mode ||
      config.timeBucketMs !== undefined && config.timeBucketMs !== prev.timeBucketMs ||
      config.countBucketSize !== undefined && config.countBucketSize !== prev.countBucketSize
    ) {
      this.completedBuckets = [];
      this.currentBucket = null;
      this.currentBucketTradeCount = 0;
      this.cvd = 0;
    }
  }

  /**
   * Get delta at a specific price level (for future footprint charts).
   * Returns buy/sell volume and net delta at that price.
   */
  getDeltaAtPrice(price: number): { buyVolume: number; sellVolume: number; netDelta: number } | undefined {
    const pk = priceKey(price);
    const level = this.priceLevelDeltas.get(pk);
    if (!level) return undefined;
    return {
      buyVolume: level.buyVolume,
      sellVolume: level.sellVolume,
      netDelta: level.buyVolume - level.sellVolume,
    };
  }

  /** Clear all price-level delta tracking data. */
  clearPriceLevelDeltas(): void {
    this.priceLevelDeltas.clear();
  }

  /** Release all resources. */
  dispose(): void {
    this.disposed = true;
    this.completedBuckets = [];
    this.currentBucket = null;
    this.priceLevelDeltas.clear();
  }

  private computeBucketTimestamp(tradeTimestamp: number): number {
    if (this.config.mode === 'time') {
      // Quantize to bucket boundary
      return Math.floor(tradeTimestamp / this.config.timeBucketMs) * this.config.timeBucketMs;
    }
    // For count mode, use the trade's timestamp as-is for the bucket
    return this.currentBucket?.timestamp ?? tradeTimestamp;
  }

  private shouldCloseBucket(newBucketTs: number): boolean {
    if (!this.currentBucket) return false;

    if (this.config.mode === 'time') {
      return newBucketTs !== this.currentBucket.timestamp;
    }

    // Count mode: closed via addTrade when threshold is reached
    return false;
  }

  private closeBucket(): void {
    if (!this.currentBucket) return;

    const netDelta = this.currentBucket.buyVolume - this.currentBucket.sellVolume;
    this.cvd += netDelta;

    const sealed = sealBucket(this.currentBucket, this.cvd);
    this.completedBuckets.push(sealed);

    // Evict oldest buckets if over limit
    if (this.completedBuckets.length > this.config.maxBuckets) {
      this.completedBuckets = this.completedBuckets.slice(
        this.completedBuckets.length - this.config.maxBuckets,
      );
    }

    this.currentBucket = null;
    this.currentBucketTradeCount = 0;
  }
}
