import { forwardRef, type CSSProperties } from 'react';
import { BarChart3 } from 'lucide-react';
import { Panel, Toolbar, Select, Slider, EmptyState } from '../../primitives';
import { ColorScaleLegend, type ColorStop } from './ColorScaleLegend';

/* -------------------------------------------------------------------------- */
/*  LiquidationHeatmapShell                                                   */
/*  Control surface for liquidation heatmap visualization.                    */
/*  Provides all controls + EmptyState placeholder for WebGL canvas.          */
/*  Uses --ts-viz-shell-* tokens.                                             */
/* -------------------------------------------------------------------------- */

export type LiquidationTimeframe = '12h' | '24h' | '7d' | '30d' | '1y';
export type LiquidationModel = 'model-1' | 'model-2' | 'model-3';

export interface LiquidationHeatmapShellProps {
  /** Panel title. */
  title?: string;
  /** Currently selected timeframe. */
  timeframe: LiquidationTimeframe;
  /** Called when timeframe changes. */
  onTimeframeChange: (timeframe: LiquidationTimeframe) => void;
  /** Currently selected exchange. */
  exchange: string;
  /** Available exchanges. */
  availableExchanges: Array<{ value: string; label: string }>;
  /** Called when exchange changes. */
  onExchangeChange: (exchange: string) => void;
  /** Currently selected model. */
  model: LiquidationModel;
  /** Called when model changes. */
  onModelChange: (model: LiquidationModel) => void;
  /** Liquidity threshold value (0-1 range). */
  liquidityThreshold: number;
  /** Called when threshold slider changes. */
  onLiquidityThresholdChange: (value: number) => void;
  /** Color scale configuration for the legend. */
  colorScale: ColorStop[];
  /** Trading pair (e.g., "BTCUSDT"). */
  pair: string;
  /** Available pairs. */
  availablePairs: Array<{ value: string; label: string }>;
  /** Called when pair changes. */
  onPairChange: (pair: string) => void;
  /** Toggle filters: Long, Short, All. */
  liquidationType: 'long' | 'short' | 'all';
  /** Called when liquidation type filter changes. */
  onLiquidationTypeChange: (type: 'long' | 'short' | 'all') => void;
  /** Called when a cell in the heatmap is clicked. */
  onCellClick?: (price: number, time: number) => void;
}

/* ----- Style injection --------------------------------------------------- */

const LIQ_HEATMAP_STYLE_ID = 'ts-liquidation-heatmap-shell-styles';

function ensureLiquidationHeatmapShellStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(LIQ_HEATMAP_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = LIQ_HEATMAP_STYLE_ID;
  sheet.textContent = `
    [data-ts-liquidation-heatmap-shell] [data-ts-liq-type-btn]:hover {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-liquidation-heatmap-shell] [data-ts-liq-type-btn][data-active]:hover {
      background: var(--ts-accent-subtle);
    }
    [data-ts-liquidation-heatmap-shell] [data-ts-liq-type-btn]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureLiquidationHeatmapShellStyles();
}

/* ----- Constants --------------------------------------------------------- */

const TIMEFRAME_OPTIONS: Array<{ value: LiquidationTimeframe; label: string }> = [
  { value: '12h', label: '12H' },
  { value: '24h', label: '24H' },
  { value: '7d', label: '7D' },
  { value: '30d', label: '30D' },
  { value: '1y', label: '1Y' },
];

const MODEL_OPTIONS: Array<{ value: LiquidationModel; label: string }> = [
  { value: 'model-1', label: 'Model 1' },
  { value: 'model-2', label: 'Model 2' },
  { value: 'model-3', label: 'Model 3' },
];

const LIQ_TYPE_OPTIONS: Array<{ value: 'long' | 'short' | 'all'; label: string }> = [
  { value: 'all', label: 'All' },
  { value: 'long', label: 'Long' },
  { value: 'short', label: 'Short' },
];

/* ----- Styles ------------------------------------------------------------ */

const shellStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
};

const controlsRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  flexWrap: 'wrap',
};

const vizContainerStyle: CSSProperties = {
  flex: 1,
  display: 'flex',
  flexDirection: 'column',
  alignItems: 'center',
  justifyContent: 'center',
  background: 'var(--ts-viz-shell-bg)',
  minHeight: 200,
  position: 'relative',
};

const legendContainerStyle: CSSProperties = {
  padding: 'var(--ts-space-2) var(--ts-space-3)',
};

const typeButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: 'var(--ts-button-height-sm)',
  padding: '0 var(--ts-space-2)',
  fontSize: 'var(--ts-font-sm)',
  fontFamily: 'inherit',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  borderRadius: 'var(--ts-radius-sm)',
  cursor: 'pointer',
  transition: 'background 150ms, color 150ms',
  boxSizing: 'border-box',
};

const typeButtonInactiveStyle: CSSProperties = {
  ...typeButtonStyle,
  background: 'transparent',
  color: 'var(--ts-text-secondary)',
};

const typeButtonActiveStyle: CSSProperties = {
  ...typeButtonStyle,
  background: 'var(--ts-accent-subtle)',
  color: 'var(--ts-accent-default)',
};

const sliderLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-secondary)',
  whiteSpace: 'nowrap',
};

const sliderWrapperStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  minWidth: 140,
};

export const LiquidationHeatmapShell = forwardRef<HTMLDivElement, LiquidationHeatmapShellProps>(
  function LiquidationHeatmapShell(
    {
      title = 'Liquidation Heatmap',
      timeframe,
      onTimeframeChange,
      exchange,
      availableExchanges,
      onExchangeChange,
      model,
      onModelChange,
      liquidityThreshold,
      onLiquidityThresholdChange,
      colorScale,
      pair,
      availablePairs,
      onPairChange,
      liquidationType,
      onLiquidationTypeChange,
    },
    ref,
  ) {
    return (
      <div ref={ref} data-ts-liquidation-heatmap-shell="" style={shellStyle}>
        <Panel
          title={title}
          actions={
            <Select
              options={availablePairs}
              value={pair}
              onValueChange={onPairChange}
              size="sm"
              label="Trading pair"
            />
          }
        >
          <Toolbar>
            <Toolbar.Group>
              {TIMEFRAME_OPTIONS.map((opt) => (
                <Toolbar.Item
                  key={opt.value}
                  active={timeframe === opt.value}
                  onClick={() => onTimeframeChange(opt.value)}
                  aria-label={`Timeframe ${opt.label}`}
                >
                  {opt.label}
                </Toolbar.Item>
              ))}
            </Toolbar.Group>

            <Toolbar.Separator />

            <Toolbar.Group>
              <Select
                options={availableExchanges}
                value={exchange}
                onValueChange={onExchangeChange}
                size="sm"
                label="Exchange"
              />
            </Toolbar.Group>

            <Toolbar.Separator />

            <Toolbar.Group>
              {MODEL_OPTIONS.map((opt) => (
                <Toolbar.Item
                  key={opt.value}
                  active={model === opt.value}
                  onClick={() => onModelChange(opt.value)}
                  aria-label={`${opt.label}`}
                >
                  {opt.label}
                </Toolbar.Item>
              ))}
            </Toolbar.Group>

            <Toolbar.Separator />

            <Toolbar.Group>
              <div style={controlsRowStyle}>
                {LIQ_TYPE_OPTIONS.map((opt) => (
                  <button
                    key={opt.value}
                    type="button"
                    data-ts-liq-type-btn=""
                    data-active={liquidationType === opt.value ? '' : undefined}
                    style={
                      liquidationType === opt.value
                        ? typeButtonActiveStyle
                        : typeButtonInactiveStyle
                    }
                    onClick={() => onLiquidationTypeChange(opt.value)}
                    aria-label={`Liquidation type: ${opt.label}`}
                    aria-pressed={liquidationType === opt.value}
                  >
                    {opt.label}
                  </button>
                ))}
              </div>
            </Toolbar.Group>

            <Toolbar.Separator />

            <Toolbar.Group>
              <div style={sliderWrapperStyle}>
                <span style={sliderLabelStyle}>Threshold</span>
                <Slider
                  value={[liquidityThreshold]}
                  onValueChange={(v) => onLiquidityThresholdChange(v[0]!)}
                  min={0}
                  max={1}
                  step={0.01}
                  label="Liquidity threshold"
                />
              </div>
            </Toolbar.Group>
          </Toolbar>

          {/* Visualization area */}
          <div style={vizContainerStyle}>
            <div data-ts-viz-canvas="" style={{ width: '100%', height: '100%', position: 'absolute', top: 0, left: 0 }} />
            <EmptyState
              icon={<BarChart3 size={40} />}
              title="Connect to data source"
              description="Liquidation heatmap visualization will render here when connected to market data."
            />
          </div>

          {/* Color scale legend */}
          <div style={legendContainerStyle}>
            <ColorScaleLegend
              stops={colorScale}
              title="Liquidation Density"
            />
          </div>
        </Panel>
      </div>
    );
  },
);

LiquidationHeatmapShell.displayName = 'LiquidationHeatmapShell';
