import { forwardRef, type ComponentPropsWithoutRef, type CSSProperties, type ElementRef } from 'react';
import { Tabs as RadixTabs } from 'radix-ui';

/* -------------------------------------------------------------------------- */
/*  Tabs                                                                      */
/*  Content switching with tab bar and optional overflow scroll.              */
/*  Wraps Radix Tabs — uses --ts-tab-* tokens.                               */
/* -------------------------------------------------------------------------- */

/* ----- Tabs.Root --------------------------------------------------------- */

type TabsRootProps = ComponentPropsWithoutRef<typeof RadixTabs.Root>;

const Root = forwardRef<ElementRef<typeof RadixTabs.Root>, TabsRootProps>(
  (props, ref) => <RadixTabs.Root ref={ref} {...props} />,
);
Root.displayName = 'Tabs';

/* ----- Tabs.List --------------------------------------------------------- */

const listStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-tab-gap)',
  borderBottom: '1px solid var(--ts-tab-border-bottom)',
  overflowX: 'auto',
  scrollbarWidth: 'none',
};

type TabsListProps = ComponentPropsWithoutRef<typeof RadixTabs.List>;

const List = forwardRef<ElementRef<typeof RadixTabs.List>, TabsListProps>(
  ({ style, ...props }, ref) => (
    <RadixTabs.List
      ref={ref}
      style={{ ...listStyle, ...style }}
      {...props}
    />
  ),
);
List.displayName = 'Tabs.List';

/* ----- Tabs.Trigger ------------------------------------------------------ */

const triggerStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: 'var(--ts-tab-height)',
  padding: `0 var(--ts-tab-padding-x)`,
  fontSize: 'var(--ts-tab-font-size)',
  fontWeight: 'var(--ts-tab-font-weight)' as unknown as number,
  fontFamily: 'inherit',
  color: 'var(--ts-tab-text)',
  background: 'var(--ts-tab-bg)',
  borderBottom: 'var(--ts-tab-indicator-height) solid transparent',
  cursor: 'pointer',
  whiteSpace: 'nowrap',
  userSelect: 'none',
  transition: 'color 150ms, background 150ms, border-color 150ms',
  boxSizing: 'border-box',
};

type TabsTriggerProps = ComponentPropsWithoutRef<typeof RadixTabs.Trigger>;

const Trigger = forwardRef<ElementRef<typeof RadixTabs.Trigger>, TabsTriggerProps>(
  ({ style, onMouseEnter, onMouseLeave, ...props }, ref) => (
    <RadixTabs.Trigger
      ref={ref}
      style={{ ...triggerStyle, ...style }}
      onMouseEnter={(e) => {
        const el = e.currentTarget;
        if (!el.hasAttribute('data-state') || el.getAttribute('data-state') !== 'active') {
          el.style.color = 'var(--ts-tab-text-hover)';
          el.style.background = 'var(--ts-tab-bg-hover)';
        }
        onMouseEnter?.(e);
      }}
      onMouseLeave={(e) => {
        const el = e.currentTarget;
        if (!el.hasAttribute('data-state') || el.getAttribute('data-state') !== 'active') {
          el.style.color = 'var(--ts-tab-text)';
          el.style.background = 'var(--ts-tab-bg)';
        }
        onMouseLeave?.(e);
      }}
      {...props}
    />
  ),
);
Trigger.displayName = 'Tabs.Trigger';

/* ----- Style injection for active state ---------------------------------- */

const TABS_STYLE_ID = 'ts-tabs-styles';

function ensureTabStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(TABS_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = TABS_STYLE_ID;
  sheet.textContent = `
    [data-radix-collection-item][data-state="active"] {
      color: var(--ts-tab-text-active) !important;
      border-bottom-color: var(--ts-tab-indicator) !important;
      background: var(--ts-tab-bg) !important;
    }
    [data-radix-collection-item]:focus-visible {
      outline: 2px solid var(--ts-tab-indicator);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureTabStyles();
}

/* ----- Tabs.Content ------------------------------------------------------ */

const contentStyle: CSSProperties = {
  outline: 'none',
};

type TabsContentProps = ComponentPropsWithoutRef<typeof RadixTabs.Content>;

const Content = forwardRef<ElementRef<typeof RadixTabs.Content>, TabsContentProps>(
  ({ style, ...props }, ref) => (
    <RadixTabs.Content
      ref={ref}
      style={{ ...contentStyle, ...style }}
      {...props}
    />
  ),
);
Content.displayName = 'Tabs.Content';

/* ----- Compound export --------------------------------------------------- */

export const Tabs = Object.assign(Root, {
  List,
  Trigger,
  Content,
});
