import { memo, useMemo, type CSSProperties } from 'react';
import { formatPrice } from '@deskmodal/ui-components';
import type { DeltaBucket } from '../services/delta-aggregator';

/* -------------------------------------------------------------------------- */
/*  DeltaBarRow                                                                */
/*  Horizontal delta bar centered on zero: green extends right (positive),     */
/*  red extends left (negative). Jigsaw/Bookmap style delta visualization.     */
/* -------------------------------------------------------------------------- */

export interface DeltaBarRowProps {
  /** The delta bucket to render. */
  readonly bucket: DeltaBucket;
  /** Maximum absolute net delta in the visible range (for normalization). */
  readonly maxAbsDelta: number;
  /** Price precision (decimal places). */
  readonly precision: number;
  /** Row height in pixels. */
  readonly height: number;
}

/* ----- Style injection --------------------------------------------------- */

const DELTA_BAR_STYLE_ID = 'ts-delta-bar-row-styles';

function ensureDeltaBarStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(DELTA_BAR_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = DELTA_BAR_STYLE_ID;
  sheet.textContent = `
    [data-ts-delta-bar-row]:hover {
      background-color: var(--ts-depth-row-bg-hover);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureDeltaBarStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  padding: '0 var(--ts-space-2)',
  boxSizing: 'border-box',
  fontFamily: 'var(--ts-font-data)',
  fontSize: 'var(--ts-font-xs)',
  fontVariantNumeric: 'tabular-nums',
  userSelect: 'none',
  gap: 'var(--ts-space-1)',
};

const timeCellStyle: CSSProperties = {
  width: '48px',
  flexShrink: 0,
  color: 'var(--ts-text-tertiary)',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const barContainerStyle: CSSProperties = {
  flex: 1,
  position: 'relative',
  height: '14px',
  minWidth: 0,
};

const barCenterStyle: CSSProperties = {
  position: 'absolute',
  top: 0,
  bottom: 0,
  left: '50%',
  width: '1px',
  background: 'rgba(255, 255, 255, 0.1)',
};

const priceCellStyle: CSSProperties = {
  width: '60px',
  flexShrink: 0,
  textAlign: 'right',
  color: 'var(--ts-text-secondary)',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const deltaCellStyle: CSSProperties = {
  width: '52px',
  flexShrink: 0,
  textAlign: 'right',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

/* ----- Helpers ----------------------------------------------------------- */

function formatTime(timestamp: number): string {
  const d = new Date(timestamp);
  const h = String(d.getHours()).padStart(2, '0');
  const m = String(d.getMinutes()).padStart(2, '0');
  const s = String(d.getSeconds()).padStart(2, '0');
  return `${h}:${m}:${s}`;
}

function formatDelta(value: number): string {
  const sign = value >= 0 ? '+' : '';
  const abs = Math.abs(value);
  if (abs >= 1_000_000) return `${sign}${(value / 1_000_000).toFixed(1)}M`;
  if (abs >= 1_000) return `${sign}${(value / 1_000).toFixed(1)}K`;
  if (abs >= 1) return `${sign}${value.toFixed(2)}`;
  return `${sign}${value.toFixed(4)}`;
}

/* ----- Component --------------------------------------------------------- */

function DeltaBarRowInner({
  bucket,
  maxAbsDelta,
  precision,
  height,
}: DeltaBarRowProps): React.JSX.Element {
  const { timestamp, netDelta, avgPrice } = bucket;

  const barWidthPercent = maxAbsDelta > 0
    ? (Math.abs(netDelta) / maxAbsDelta) * 50
    : 0;

  const isPositive = netDelta >= 0;

  const barStyle = useMemo<CSSProperties>(() => {
    const bgColor = isPositive
      ? 'var(--ts-color-bullish)'
      : 'var(--ts-color-bearish)';

    if (isPositive) {
      return {
        position: 'absolute',
        top: '1px',
        bottom: '1px',
        left: '50%',
        width: `${barWidthPercent}%`,
        background: bgColor,
        opacity: 0.7,
        borderRadius: '0 2px 2px 0',
      };
    }
    return {
      position: 'absolute',
      top: '1px',
      bottom: '1px',
      right: '50%',
      width: `${barWidthPercent}%`,
      background: bgColor,
      opacity: 0.7,
      borderRadius: '2px 0 0 2px',
    };
  }, [isPositive, barWidthPercent]);

  const deltaColor = isPositive
    ? 'var(--ts-color-bullish)'
    : 'var(--ts-color-bearish)';

  return (
    <div
      data-ts-delta-bar-row=""
      data-delta-sign={isPositive ? 'positive' : 'negative'}
      style={{ ...rowStyle, height: `${height}px` }}
      role="row"
      data-testid="delta-bar-row"
    >
      <span style={timeCellStyle} role="cell" data-testid="delta-time">
        {formatTime(timestamp)}
      </span>
      <div style={barContainerStyle} data-testid="delta-bar-container">
        <div style={barCenterStyle} />
        <div style={barStyle} data-testid="delta-bar" />
      </div>
      <span style={priceCellStyle} role="cell" data-testid="delta-avg-price">
        {formatPrice(avgPrice, precision)}
      </span>
      <span style={{ ...deltaCellStyle, color: deltaColor }} role="cell" data-testid="delta-value">
        {formatDelta(netDelta)}
      </span>
    </div>
  );
}

export const DeltaBarRow = memo(DeltaBarRowInner);

DeltaBarRow.displayName = 'DeltaBarRow';
