import {
  createContext,
  forwardRef,
  useContext,
  type CSSProperties,
  type ReactNode,
} from 'react';

/* =====================================================
   Context — passes orientation down to sub-components
   ===================================================== */

type ToolbarOrientation = 'horizontal' | 'vertical';

const ToolbarContext = createContext<ToolbarOrientation>('horizontal');

/* =====================================================
   Toolbar (root)
   ===================================================== */

export interface ToolbarProps {
  /** Layout direction */
  orientation?: ToolbarOrientation;
  /** Toolbar items, groups, and separators */
  children: ReactNode;
  /** Additional class name */
  className?: string;
}

function getToolbarStyle(orientation: ToolbarOrientation): CSSProperties {
  const isHorizontal = orientation === 'horizontal';
  return {
    display: 'flex',
    flexDirection: isHorizontal ? 'row' : 'column',
    alignItems: isHorizontal ? 'center' : 'stretch',
    background: 'var(--ts-toolbar-bg)',
    borderBottom: isHorizontal ? '1px solid var(--ts-toolbar-border)' : undefined,
    borderRight: isHorizontal ? undefined : '1px solid var(--ts-toolbar-border)',
    [isHorizontal ? 'height' : 'width']: 'var(--ts-toolbar-height)',
    padding: isHorizontal
      ? `0 var(--ts-toolbar-padding-x)`
      : `var(--ts-toolbar-padding-x) 0`,
    gap: 'var(--ts-toolbar-item-gap)',
    flexShrink: 0,
  };
}

const ToolbarRoot = forwardRef<HTMLDivElement, ToolbarProps>(
  function ToolbarRoot({ orientation = 'horizontal', children, className }, ref) {
    return (
      <ToolbarContext.Provider value={orientation}>
        <div
          ref={ref}
          role="toolbar"
          aria-orientation={orientation}
          className={className}
          style={getToolbarStyle(orientation)}
        >
          {children}
        </div>
      </ToolbarContext.Provider>
    );
  },
);

/* =====================================================
   Toolbar.Group
   ===================================================== */

export interface ToolbarGroupProps {
  /** Group items */
  children: ReactNode;
  /** Additional class name */
  className?: string;
}

const ToolbarGroup = forwardRef<HTMLDivElement, ToolbarGroupProps>(
  function ToolbarGroup({ children, className }, ref) {
    const orientation = useContext(ToolbarContext);
    const isHorizontal = orientation === 'horizontal';

    const style: CSSProperties = {
      display: 'flex',
      flexDirection: isHorizontal ? 'row' : 'column',
      alignItems: isHorizontal ? 'center' : 'stretch',
      gap: 'var(--ts-toolbar-item-gap)',
    };

    return (
      <div ref={ref} role="group" className={className} style={style}>
        {children}
      </div>
    );
  },
);

/* =====================================================
   Toolbar.Separator
   ===================================================== */

export interface ToolbarSeparatorProps {
  /** Additional class name */
  className?: string;
}

const ToolbarSeparator = forwardRef<HTMLDivElement, ToolbarSeparatorProps>(
  function ToolbarSeparator({ className }, ref) {
    const orientation = useContext(ToolbarContext);
    const isHorizontal = orientation === 'horizontal';

    const style: CSSProperties = {
      [isHorizontal ? 'width' : 'height']: '1px',
      [isHorizontal ? 'height' : 'width']: isHorizontal ? '60%' : undefined,
      alignSelf: isHorizontal ? 'center' : undefined,
      background: 'var(--ts-toolbar-separator-color)',
      margin: isHorizontal
        ? `0 var(--ts-toolbar-separator-margin)`
        : `var(--ts-toolbar-separator-margin) 0`,
      flexShrink: 0,
    };

    return (
      <div
        ref={ref}
        role="separator"
        aria-orientation={isHorizontal ? 'vertical' : 'horizontal'}
        className={className}
        style={style}
      />
    );
  },
);

/* =====================================================
   Toolbar.Item
   ===================================================== */

export interface ToolbarItemProps {
  /** Item content (icon, label, etc.) */
  children: ReactNode;
  /** Whether this item is currently active */
  active?: boolean;
  /** Whether this item is disabled */
  disabled?: boolean;
  /** Click handler */
  onClick?: () => void;
  /** Accessible label */
  'aria-label'?: string;
  /** Additional class name */
  className?: string;
}

const ToolbarItem = forwardRef<HTMLButtonElement, ToolbarItemProps>(
  function ToolbarItem(
    {
      children,
      active = false,
      disabled = false,
      onClick,
      'aria-label': ariaLabel,
      className,
    },
    ref,
  ) {
    const style: CSSProperties = {
      display: 'inline-flex',
      alignItems: 'center',
      justifyContent: 'center',
      minWidth: 'var(--ts-icon-button-size-sm)',
      height: 'var(--ts-icon-button-size-sm)',
      padding: `0 var(--ts-space-1)`,
      border: 'none',
      borderRadius: 'var(--ts-button-radius)',
      background: active
        ? 'var(--ts-button-ghost-bg-active)'
        : 'var(--ts-button-ghost-bg)',
      color: active
        ? 'var(--ts-text-primary)'
        : disabled
          ? 'var(--ts-text-disabled)'
          : 'var(--ts-text-secondary)',
      cursor: disabled ? 'default' : 'pointer',
      transition: `background var(--ts-duration-micro) ease, color var(--ts-duration-micro) ease`,
      fontSize: 'var(--ts-font-md)',
      lineHeight: 1,
      outline: 'none',
    };

    return (
      <button
        ref={ref}
        type="button"
        role="button"
        className={className}
        style={style}
        disabled={disabled}
        aria-label={ariaLabel}
        aria-pressed={active}
        onClick={onClick}
        onMouseEnter={(e) => {
          if (!disabled && !active) {
            e.currentTarget.style.background = 'var(--ts-button-ghost-bg-hover)';
            e.currentTarget.style.color = 'var(--ts-button-ghost-text-hover)';
          }
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.background = active
            ? 'var(--ts-button-ghost-bg-active)'
            : 'var(--ts-button-ghost-bg)';
          e.currentTarget.style.color = active
            ? 'var(--ts-text-primary)'
            : disabled
              ? 'var(--ts-text-disabled)'
              : 'var(--ts-text-secondary)';
        }}
      >
        {children}
      </button>
    );
  },
);

/* =====================================================
   Compound export
   ===================================================== */

export const Toolbar = Object.assign(ToolbarRoot, {
  Group: ToolbarGroup,
  Separator: ToolbarSeparator,
  Item: ToolbarItem,
});
