/* -------------------------------------------------------------------------- */
/*  LargeTradeDetector                                                        */
/*  Adaptive EMA-based trade size classification into configurable tiers.      */
/*  Uses EMA(tradeSize, period) * multiplier to set dynamic thresholds.       */
/* -------------------------------------------------------------------------- */

/** A configurable trade size tier. */
export interface SizeTier {
  /** Human-readable tier name. */
  readonly name: string;
  /** Minimum EMA multiplier to qualify for this tier. */
  readonly minMultiplier: number;
  /** CSS color or token for this tier. */
  readonly color: string;
  /** Whether to visually highlight trades in this tier. */
  readonly highlight: boolean;
  /** Whether to play an audio alert for trades in this tier. */
  readonly sound: boolean;
}

/** Default 4-tier classification aligned to the Jigsaw/Bookmap pattern. */
export const DEFAULT_SIZE_TIERS: readonly SizeTier[] = [
  { name: 'Normal', minMultiplier: 0, color: 'var(--ts-text-secondary)', highlight: false, sound: false },
  { name: 'Notable', minMultiplier: 3, color: 'var(--ts-text-primary)', highlight: false, sound: false },
  { name: 'Large', minMultiplier: 10, color: 'var(--ts-accent-default)', highlight: true, sound: false },
  { name: 'Whale', minMultiplier: 50, color: 'var(--ts-color-warning)', highlight: true, sound: true },
] as const;

export class LargeTradeDetector {
  private ema = 0;
  private emaCount = 0;
  private readonly emaPeriod: number;
  private readonly k: number;
  private tiers: readonly SizeTier[];

  constructor(emaPeriod = 100, tiers?: readonly SizeTier[]) {
    this.emaPeriod = emaPeriod;
    this.k = 2 / (emaPeriod + 1);
    this.tiers = tiers ?? DEFAULT_SIZE_TIERS;
  }

  /**
   * Process a trade size and return the matching tier.
   * Classifies against the current EMA, then updates the EMA.
   * This ensures a whale trade is classified relative to the
   * average *before* the whale trade inflates the EMA.
   */
  addTrade(size: number): SizeTier {
    // Classify against current EMA first
    const tier = this.classifySize(size);

    // Then update EMA
    if (this.emaCount === 0) {
      this.ema = size;
    } else {
      this.ema = size * this.k + this.ema * (1 - this.k);
    }
    this.emaCount += 1;

    return tier;
  }

  /** Classify a size without updating the EMA. */
  classifySize(size: number): SizeTier {
    if (this.ema === 0) {
      return this.tiers[0]!;
    }

    const multiplier = size / this.ema;

    // Walk tiers in reverse (highest first) to find the matching tier
    for (let i = this.tiers.length - 1; i >= 0; i--) {
      const tier = this.tiers[i]!;
      if (multiplier >= tier.minMultiplier) {
        return tier;
      }
    }

    return this.tiers[0]!;
  }

  /** Get the current EMA average trade size. */
  getAverageSize(): number {
    return this.ema;
  }

  /** Get the number of trades processed. */
  getTradeCount(): number {
    return this.emaCount;
  }

  /** Update the tier configuration. */
  setTiers(tiers: readonly SizeTier[]): void {
    this.tiers = tiers;
  }

  /** Get current tiers. */
  getTiers(): readonly SizeTier[] {
    return this.tiers;
  }

  /** Reset the EMA and trade count. */
  reset(): void {
    this.ema = 0;
    this.emaCount = 0;
  }
}
