import { useEffect, useRef } from "react";
import type { Context, Listener } from "../fdc3-types";
import { useFdc3 } from "./use-fdc3";

/**
 * Hook that subscribes to a specific context type on the current user channel.
 * Automatically cleans up the listener on unmount or when dependencies change.
 *
 * The handler is stored in a ref to avoid re-subscribing when the handler
 * reference changes (common with inline arrow functions).
 *
 * Usage:
 *   useContextListener("fdc3.instrument", (context) => {
 *     setSymbol(context.id?.ticker);
 *   });
 */
export function useContextListener<T extends Context>(
  contextType: string,
  handler: (context: T) => void
): void {
  const fdc3 = useFdc3();
  const handlerRef = useRef(handler);
  handlerRef.current = handler;

  useEffect(() => {
    if (!fdc3) {
      return;
    }

    let listener: Listener | undefined;
    let cancelled = false;

    fdc3
      .addContextListener(contextType, (context) => {
        if (!cancelled) {
          handlerRef.current(context as T);
        }
      })
      .then(
        (l) => {
          if (cancelled) {
            l.unsubscribe();
          } else {
            listener = l;
          }
        },
        () => {
          // Listener registration failed — nothing to clean up
        }
      );

    return () => {
      cancelled = true;
      if (listener) {
        listener.unsubscribe();
      }
    };
  }, [fdc3, contextType]);
}
