import {
  useRef,
  useEffect,
  useCallback,
  useMemo,
  forwardRef,
  type CSSProperties,
} from 'react';
import { RotateCcw, ChevronDown, ChevronRight } from 'lucide-react';
import type { DeltaBucket } from '../services/delta-aggregator';

/* -------------------------------------------------------------------------- */
/*  CVDPanel                                                                   */
/*  60px tall collapsible panel rendering a cumulative volume delta line chart. */
/*  Zero baseline with dashed line; above zero = bullish, below = bearish.     */
/* -------------------------------------------------------------------------- */

export interface CVDPanelProps {
  /** Completed delta buckets. */
  readonly buckets: readonly DeltaBucket[];
  /** In-progress bucket (may be null). */
  readonly currentBucket: DeltaBucket | null;
  /** Current cumulative volume delta value. */
  readonly cvdValue: number;
  /** Called when user clicks the reset button. */
  readonly onReset: () => void;
  /** Whether the panel is collapsed. */
  readonly collapsed: boolean;
  /** Called when collapse state toggles. */
  readonly onCollapsedChange: (collapsed: boolean) => void;
}

/* ----- Style injection --------------------------------------------------- */

const CVD_PANEL_STYLE_ID = 'ts-cvd-panel-styles';

function ensureCVDPanelStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(CVD_PANEL_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = CVD_PANEL_STYLE_ID;
  sheet.textContent = `
    [data-ts-cvd-reset-btn]:hover {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-cvd-reset-btn]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-cvd-toggle-btn]:hover {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-cvd-toggle-btn]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureCVDPanelStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  borderBottom: '1px solid var(--ts-panel-border)',
  background: 'var(--ts-panel-bg)',
  flexShrink: 0,
  overflow: 'hidden',
};

const headerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: '22px',
  padding: '0 var(--ts-space-2)',
  gap: 'var(--ts-space-1)',
  userSelect: 'none',
  flexShrink: 0,
};

const toggleBtnStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: '16px',
  height: '16px',
  borderRadius: 'var(--ts-radius-sm)',
  color: 'var(--ts-text-tertiary)',
  cursor: 'pointer',
  flexShrink: 0,
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  textTransform: 'uppercase',
  letterSpacing: '0.04em',
  whiteSpace: 'nowrap',
};

const cvdValueStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  fontFamily: 'var(--ts-font-data)',
  fontVariantNumeric: 'tabular-nums',
  whiteSpace: 'nowrap',
  marginLeft: 'auto',
};

const resetBtnStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: '16px',
  height: '16px',
  borderRadius: 'var(--ts-radius-sm)',
  color: 'var(--ts-text-tertiary)',
  cursor: 'pointer',
  flexShrink: 0,
};

const canvasContainerStyle: CSSProperties = {
  height: '60px',
  width: '100%',
  position: 'relative',
};

/* ----- Helpers ----------------------------------------------------------- */

function formatCVD(value: number): string {
  const abs = Math.abs(value);
  const sign = value >= 0 ? '+' : '-';
  if (abs >= 1_000_000) return `${sign}${(abs / 1_000_000).toFixed(2)}M`;
  if (abs >= 1_000) return `${sign}${(abs / 1_000).toFixed(2)}K`;
  return `${sign}${abs.toFixed(4)}`;
}

function getCVDColor(value: number): string {
  if (value > 0) return 'var(--ts-color-bullish)';
  if (value < 0) return 'var(--ts-color-bearish)';
  return 'var(--ts-text-secondary)';
}

/* ----- Canvas rendering -------------------------------------------------- */

function renderCVDChart(
  canvas: HTMLCanvasElement,
  buckets: readonly DeltaBucket[],
  currentBucket: DeltaBucket | null,
): void {
  const ctx = canvas.getContext('2d');
  if (!ctx) return;

  const dpr = window.devicePixelRatio || 1;
  const rect = canvas.getBoundingClientRect();
  const w = rect.width;
  const h = rect.height;

  canvas.width = Math.round(w * dpr);
  canvas.height = Math.round(h * dpr);
  ctx.scale(dpr, dpr);
  ctx.clearRect(0, 0, w, h);

  // Collect all CVD values
  const allBuckets = currentBucket
    ? [...buckets, currentBucket]
    : buckets;

  if (allBuckets.length < 2) {
    // Draw zero line only
    drawZeroLine(ctx, w, h);
    return;
  }

  const cvdValues = allBuckets.map((b) => b.cumulativeDelta);
  const minVal = Math.min(0, ...cvdValues);
  const maxVal = Math.max(0, ...cvdValues);
  const range = maxVal - minVal || 1;
  const padding = 2;

  // Map value to y coordinate (inverted: higher value = lower y)
  const yOf = (v: number) => padding + ((maxVal - v) / range) * (h - 2 * padding);

  // Zero line
  const zeroY = yOf(0);
  drawZeroLine(ctx, w, h, zeroY);

  // Draw filled area and line
  const step = (w - 2) / (allBuckets.length - 1);

  // Fill area between line and zero
  ctx.beginPath();
  ctx.moveTo(1, zeroY);
  for (let i = 0; i < cvdValues.length; i++) {
    ctx.lineTo(1 + i * step, yOf(cvdValues[i]!));
  }
  ctx.lineTo(1 + (cvdValues.length - 1) * step, zeroY);
  ctx.closePath();

  const lastVal = cvdValues[cvdValues.length - 1] ?? 0;
  if (lastVal >= 0) {
    ctx.fillStyle = 'rgba(34, 197, 94, 0.12)';
  } else {
    ctx.fillStyle = 'rgba(239, 68, 68, 0.12)';
  }
  ctx.fill();

  // Draw the CVD line
  ctx.beginPath();
  for (let i = 0; i < cvdValues.length; i++) {
    const x = 1 + i * step;
    const y = yOf(cvdValues[i]!);
    if (i === 0) {
      ctx.moveTo(x, y);
    } else {
      ctx.lineTo(x, y);
    }
  }
  ctx.strokeStyle = lastVal >= 0 ? '#22c55e' : '#ef4444';
  ctx.lineWidth = 1.5;
  ctx.stroke();
}

function drawZeroLine(
  ctx: CanvasRenderingContext2D,
  w: number,
  h: number,
  zeroY?: number,
): void {
  const y = zeroY ?? h / 2;
  ctx.setLineDash([3, 3]);
  ctx.strokeStyle = 'rgba(255, 255, 255, 0.15)';
  ctx.lineWidth = 1;
  ctx.beginPath();
  ctx.moveTo(0, y);
  ctx.lineTo(w, y);
  ctx.stroke();
  ctx.setLineDash([]);
}

/* ----- Component --------------------------------------------------------- */

export const CVDPanel = forwardRef<HTMLDivElement, CVDPanelProps>(
  function CVDPanel(
    { buckets, currentBucket, cvdValue, onReset, collapsed, onCollapsedChange },
    ref,
  ) {
    const canvasRef = useRef<HTMLCanvasElement>(null);

    // Re-render canvas when data changes
    useEffect(() => {
      const canvas = canvasRef.current;
      if (!canvas || collapsed) return;
      renderCVDChart(canvas, buckets, currentBucket);
    }, [buckets, currentBucket, collapsed]);

    // Handle resize
    useEffect(() => {
      const canvas = canvasRef.current;
      if (!canvas || collapsed) return;

      const observer = new ResizeObserver(() => {
        renderCVDChart(canvas, buckets, currentBucket);
      });
      observer.observe(canvas);
      return () => observer.disconnect();
    }, [buckets, currentBucket, collapsed]);

    const handleToggle = useCallback(() => {
      onCollapsedChange(!collapsed);
    }, [collapsed, onCollapsedChange]);

    const handleReset = useCallback(() => {
      onReset();
    }, [onReset]);

    const valueColor = useMemo(() => getCVDColor(cvdValue), [cvdValue]);
    const formattedValue = useMemo(() => formatCVD(cvdValue), [cvdValue]);

    return (
      <div
        ref={ref}
        data-ts-cvd-panel=""
        data-collapsed={collapsed ? '' : undefined}
        style={rootStyle}
        data-testid="cvd-panel"
      >
        <div style={headerStyle}>
          <button
            type="button"
            data-ts-cvd-toggle-btn=""
            style={toggleBtnStyle}
            onClick={handleToggle}
            aria-label={collapsed ? 'Expand CVD panel' : 'Collapse CVD panel'}
            data-testid="cvd-toggle-btn"
          >
            {collapsed ? <ChevronRight size={12} aria-hidden /> : <ChevronDown size={12} aria-hidden />}
          </button>
          <span style={labelStyle}>CVD</span>
          <span
            style={{ ...cvdValueStyle, color: valueColor }}
            data-testid="cvd-value"
          >
            {formattedValue}
          </span>
          <button
            type="button"
            data-ts-cvd-reset-btn=""
            style={resetBtnStyle}
            onClick={handleReset}
            aria-label="Reset CVD"
            data-testid="cvd-reset-btn"
          >
            <RotateCcw size={10} aria-hidden />
          </button>
        </div>
        {!collapsed && (
          <div style={canvasContainerStyle} data-testid="cvd-canvas-container">
            <canvas
              ref={canvasRef}
              style={{ width: '100%', height: '100%', display: 'block' }}
              data-testid="cvd-canvas"
            />
          </div>
        )}
      </div>
    );
  },
);

CVDPanel.displayName = 'CVDPanel';
