import { forwardRef, useMemo, useCallback, type CSSProperties } from 'react';
import {
  useReactTable,
  getCoreRowModel,
  getSortedRowModel,
  flexRender,
  type ColumnDef,
  type SortingState,
} from '@tanstack/react-table';
import { useState } from 'react';
import { ArrowUp, ArrowDown, ArrowUpDown } from 'lucide-react';
import { Panel, Toolbar, Select } from '../../primitives';
import { FundingRateCell } from './FundingRateCell';

/* -------------------------------------------------------------------------- */
/*  FundingRatePanel                                                          */
/*  Multi-exchange funding rate table with time period + margin type controls.*/
/*  Uses --ts-funding-rate-* tokens via FundingRateCell.                      */
/* -------------------------------------------------------------------------- */

export type FundingTimePeriod = 'current' | '1d' | '7d' | '30d' | '1y';
export type MarginType = 'usd' | 'token';

export interface FundingRatePanelProps {
  /** Exchange names for column headers. */
  exchanges: string[];
  /** Data rows: each row has a symbol and rates per exchange. */
  data: Array<{
    id: string;
    symbol: string;
    iconUrl?: string;
    rates: Record<string, number | null>;
  }>;
  /** Currently selected time period. */
  timePeriod: FundingTimePeriod;
  /** Called when time period changes. */
  onTimePeriodChange: (period: FundingTimePeriod) => void;
  /** Currently selected margin type. */
  marginType: MarginType;
  /** Called when margin type changes. */
  onMarginTypeChange: (type: MarginType) => void;
  /** Called when a row is clicked (symbol selection). */
  onSymbolSelect?: (symbol: string) => void;
  /** Called when a specific exchange cell is clicked. */
  onCellClick?: (symbol: string, exchange: string) => void;
  /** Weighted average funding rate to display in header. */
  weightedAverageRate?: number;
  /** Whether to show the background color tint in cells. */
  showCellBackground?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const FUNDING_PANEL_STYLE_ID = 'ts-funding-rate-panel-styles';

function ensureFundingRatePanelStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(FUNDING_PANEL_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = FUNDING_PANEL_STYLE_ID;
  sheet.textContent = `
    [data-ts-funding-rate-panel] [data-ts-fr-row]:hover {
      background: var(--ts-data-row-bg-hover);
    }
    [data-ts-funding-rate-panel] [data-ts-fr-header-cell][data-sortable]:hover {
      cursor: pointer;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureFundingRatePanelStyles();
}

/* ----- Constants --------------------------------------------------------- */

const TIME_PERIOD_OPTIONS = [
  { value: 'current', label: 'Current' },
  { value: '1d', label: '1D' },
  { value: '7d', label: '7D' },
  { value: '30d', label: '30D' },
  { value: '1y', label: '1Y' },
];

const MARGIN_TYPE_OPTIONS = [
  { value: 'usd', label: 'USD Margined' },
  { value: 'token', label: 'Token Margined' },
];

/* ----- Styles ------------------------------------------------------------ */

const tableContainerStyle: CSSProperties = {
  overflowX: 'auto',
  scrollbarWidth: 'thin',
};

const tableStyle: CSSProperties = {
  width: '100%',
  borderCollapse: 'collapse',
  fontFamily: 'var(--ts-font-data)',
  fontSize: 'var(--ts-data-cell-font-size)',
};

const headerCellStyle: CSSProperties = {
  background: 'var(--ts-data-header-bg)',
  color: 'var(--ts-data-header-text)',
  fontSize: 'var(--ts-data-header-font-size)',
  fontWeight: 'var(--ts-data-header-font-weight)' as unknown as number,
  height: 'var(--ts-data-header-height)',
  padding: '0 var(--ts-data-header-padding-x)',
  textAlign: 'right',
  borderBottom: '1px solid var(--ts-data-header-border)',
  userSelect: 'none',
  whiteSpace: 'nowrap',
  position: 'relative',
};

const symbolHeaderStyle: CSSProperties = {
  ...headerCellStyle,
  textAlign: 'left',
  position: 'sticky',
  left: 0,
  zIndex: 1,
};

const rowStyle: CSSProperties = {
  borderBottom: '1px solid var(--ts-data-row-border)',
  cursor: 'pointer',
  transition: 'background 100ms',
};

const symbolCellStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  padding: '0 var(--ts-data-row-padding-x)',
  height: 'var(--ts-data-row-height)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-data-row-text)',
  position: 'sticky',
  left: 0,
  background: 'inherit',
  zIndex: 1,
};

const rateCellWrapperStyle: CSSProperties = {
  padding: '0 var(--ts-data-row-padding-x)',
  height: 'var(--ts-data-row-height)',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'flex-end',
};

const sortIconStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  marginLeft: 'var(--ts-space-1)',
  color: 'var(--ts-data-header-sort-icon)',
};

const sortIconActiveStyle: CSSProperties = {
  ...sortIconStyle,
  color: 'var(--ts-data-header-sort-icon-active)',
};

const weightedAvgStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-secondary)',
  fontFamily: 'var(--ts-font-data)',
  fontVariantNumeric: 'tabular-nums slashed-zero',
};

type FundingRow = {
  id: string;
  symbol: string;
  iconUrl?: string;
  rates: Record<string, number | null>;
};

export const FundingRatePanel = forwardRef<HTMLDivElement, FundingRatePanelProps>(
  function FundingRatePanel(
    {
      exchanges,
      data,
      timePeriod,
      onTimePeriodChange,
      marginType,
      onMarginTypeChange,
      onSymbolSelect,
      onCellClick,
      weightedAverageRate,
      showCellBackground = false,
    },
    ref,
  ) {
    const [sorting, setSorting] = useState<SortingState>([]);

    const columns = useMemo<ColumnDef<FundingRow, unknown>[]>(() => {
      const cols: ColumnDef<FundingRow, unknown>[] = [
        {
          id: 'symbol',
          header: 'Symbol',
          accessorFn: (row) => row.symbol,
          enableSorting: true,
        },
      ];

      for (const exchange of exchanges) {
        cols.push({
          id: exchange,
          header: exchange,
          accessorFn: (row) => row.rates[exchange] ?? null,
          enableSorting: true,
          sortingFn: (rowA, rowB) => {
            const a = rowA.original.rates[exchange];
            const b = rowB.original.rates[exchange];
            if (a === null && b === null) return 0;
            if (a === null) return 1;
            if (b === null) return -1;
            return a! - b!;
          },
        });
      }

      return cols;
    }, [exchanges]);

    const table = useReactTable({
      data,
      columns,
      state: { sorting },
      onSortingChange: setSorting,
      getCoreRowModel: getCoreRowModel(),
      getSortedRowModel: getSortedRowModel(),
    });

    const handleRowClick = useCallback(
      (symbol: string) => {
        onSymbolSelect?.(symbol);
      },
      [onSymbolSelect],
    );

    const handleCellClick = useCallback(
      (symbol: string, exchange: string, e: React.MouseEvent) => {
        e.stopPropagation();
        onCellClick?.(symbol, exchange);
      },
      [onCellClick],
    );

    return (
      <div ref={ref} data-ts-funding-rate-panel="">
        <Panel
          title="Funding Rates"
          actions={
            weightedAverageRate !== undefined ? (
              <span style={weightedAvgStyle}>
                Weighted Avg: {(weightedAverageRate * 100).toFixed(4)}%
              </span>
            ) : undefined
          }
        >
          <Toolbar>
            <Toolbar.Group>
              {TIME_PERIOD_OPTIONS.map((opt) => (
                <Toolbar.Item
                  key={opt.value}
                  active={timePeriod === opt.value}
                  onClick={() => onTimePeriodChange(opt.value as FundingTimePeriod)}
                  aria-label={`Time period ${opt.label}`}
                >
                  {opt.label}
                </Toolbar.Item>
              ))}
            </Toolbar.Group>

            <Toolbar.Separator />

            <Toolbar.Group>
              <Select
                options={MARGIN_TYPE_OPTIONS}
                value={marginType}
                onValueChange={(v) => onMarginTypeChange(v as MarginType)}
                size="sm"
                label="Margin type"
              />
            </Toolbar.Group>
          </Toolbar>

          <div style={tableContainerStyle}>
            <table style={tableStyle} role="grid">
              <thead>
                {table.getHeaderGroups().map((headerGroup) => (
                  <tr key={headerGroup.id}>
                    {headerGroup.headers.map((header) => {
                      const isSorted = header.column.getIsSorted();
                      const isSymbolCol = header.column.id === 'symbol';
                      return (
                        <th
                          key={header.id}
                          data-ts-fr-header-cell=""
                          data-sortable=""
                          style={isSymbolCol ? symbolHeaderStyle : headerCellStyle}
                          onClick={header.column.getToggleSortingHandler()}
                          aria-sort={
                            isSorted === 'asc'
                              ? 'ascending'
                              : isSorted === 'desc'
                                ? 'descending'
                                : 'none'
                          }
                        >
                          {flexRender(
                            header.column.columnDef.header,
                            header.getContext(),
                          )}
                          <span style={isSorted ? sortIconActiveStyle : sortIconStyle}>
                            {isSorted === 'asc' ? (
                              <ArrowUp size={12} />
                            ) : isSorted === 'desc' ? (
                              <ArrowDown size={12} />
                            ) : (
                              <ArrowUpDown size={12} />
                            )}
                          </span>
                        </th>
                      );
                    })}
                  </tr>
                ))}
              </thead>
              <tbody>
                {table.getRowModel().rows.map((row) => (
                  <tr
                    key={row.id}
                    data-ts-fr-row=""
                    style={rowStyle}
                    onClick={() => handleRowClick(row.original.symbol)}
                  >
                    <td>
                      <div style={symbolCellStyle}>
                        {row.original.symbol}
                      </div>
                    </td>
                    {exchanges.map((exchange) => (
                      <td
                        key={exchange}
                        onClick={(e) =>
                          handleCellClick(row.original.symbol, exchange, e)
                        }
                      >
                        <div style={rateCellWrapperStyle}>
                          <FundingRateCell
                            rate={row.original.rates[exchange] ?? null}
                            showBackground={showCellBackground}
                          />
                        </div>
                      </td>
                    ))}
                  </tr>
                ))}
              </tbody>
            </table>
          </div>
        </Panel>
      </div>
    );
  },
);

FundingRatePanel.displayName = 'FundingRatePanel';
