import {
  forwardRef,
  useCallback,
  useRef,
  useState,
  type CSSProperties,
  type KeyboardEvent,
} from 'react';

export interface ResizeHandleProps {
  /** Resize direction */
  direction: 'horizontal' | 'vertical';
  /** Called during drag with pixel delta since last event */
  onResize: (delta: number) => void;
  /** Called when drag ends */
  onResizeEnd?: () => void;
  /** Additional class name */
  className?: string;
}

function getBaseStyle(direction: 'horizontal' | 'vertical'): CSSProperties {
  const isHorizontal = direction === 'horizontal';
  return {
    position: 'relative',
    flexShrink: 0,
    width: isHorizontal ? 'var(--ts-panel-resize-handle-width)' : '100%',
    height: isHorizontal ? '100%' : 'var(--ts-panel-resize-handle-width)',
    cursor: isHorizontal ? 'col-resize' : 'row-resize',
    background: 'var(--ts-panel-resize-handle)',
    transition: `background var(--ts-duration-micro) ease`,
    touchAction: 'none',
    outline: 'none',
  };
}

const KEYBOARD_STEP = 4;

export const ResizeHandle = forwardRef<HTMLDivElement, ResizeHandleProps>(
  function ResizeHandle({ direction, onResize, onResizeEnd, className }, ref) {
    const [dragging, setDragging] = useState(false);
    const [hovered, setHovered] = useState(false);
    const lastPosRef = useRef(0);

    const handlePointerDown = useCallback(
      (event: React.PointerEvent<HTMLDivElement>) => {
        event.preventDefault();
        const target = event.currentTarget;
        target.setPointerCapture(event.pointerId);
        setDragging(true);
        lastPosRef.current =
          direction === 'horizontal' ? event.clientX : event.clientY;
      },
      [direction],
    );

    const handlePointerMove = useCallback(
      (event: React.PointerEvent<HTMLDivElement>) => {
        if (!dragging) return;
        const currentPos =
          direction === 'horizontal' ? event.clientX : event.clientY;
        const delta = currentPos - lastPosRef.current;
        lastPosRef.current = currentPos;
        if (delta !== 0) {
          onResize(delta);
        }
      },
      [dragging, direction, onResize],
    );

    const handlePointerUp = useCallback(
      (event: React.PointerEvent<HTMLDivElement>) => {
        event.currentTarget.releasePointerCapture(event.pointerId);
        setDragging(false);
        onResizeEnd?.();
      },
      [onResizeEnd],
    );

    const handleKeyDown = useCallback(
      (event: KeyboardEvent<HTMLDivElement>) => {
        const isHorizontal = direction === 'horizontal';
        let delta = 0;

        if (isHorizontal) {
          if (event.key === 'ArrowLeft') delta = -KEYBOARD_STEP;
          else if (event.key === 'ArrowRight') delta = KEYBOARD_STEP;
        } else {
          if (event.key === 'ArrowUp') delta = -KEYBOARD_STEP;
          else if (event.key === 'ArrowDown') delta = KEYBOARD_STEP;
        }

        if (delta !== 0) {
          event.preventDefault();
          onResize(delta);
          onResizeEnd?.();
        }
      },
      [direction, onResize, onResizeEnd],
    );

    const active = dragging || hovered;
    const style: CSSProperties = {
      ...getBaseStyle(direction),
      background: active
        ? 'var(--ts-panel-resize-handle-hover)'
        : 'var(--ts-panel-resize-handle)',
    };

    return (
      <div
        ref={ref}
        className={className}
        role="separator"
        aria-orientation={direction}
        aria-valuenow={0}
        tabIndex={0}
        style={style}
        onPointerDown={handlePointerDown}
        onPointerMove={handlePointerMove}
        onPointerUp={handlePointerUp}
        onPointerCancel={handlePointerUp}
        onMouseEnter={() => setHovered(true)}
        onMouseLeave={() => setHovered(false)}
        onKeyDown={handleKeyDown}
      />
    );
  },
);
