import { forwardRef, useRef, useCallback, useEffect, useMemo, type CSSProperties } from 'react';
import { useNumberField } from '@react-aria/numberfield';
import { useNumberFieldState } from '@react-stately/numberfield';
import { ChevronUp, ChevronDown } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  NumberInput                                                               */
/*  Numeric input with step buttons and keyboard control.                     */
/*  Uses --ts-number-input-* tokens + base --ts-input-* tokens.              */
/* -------------------------------------------------------------------------- */

type NumberInputSize = 'sm' | 'md' | 'lg';

export interface NumberInputProps {
  /** Current value. */
  value?: number;
  /** Called when the value changes. */
  onChange?: (value: number) => void;
  /** Minimum allowed value. */
  min?: number;
  /** Maximum allowed value. */
  max?: number;
  /** Step increment for buttons and keyboard arrows. */
  step?: number;
  /** Number of decimal places to display. */
  precision?: number;
  /** Input size controlling height. */
  size?: NumberInputSize;
  /** Whether the input is disabled. */
  disabled?: boolean;
  /** Accessible label. */
  label?: string;
}

/* ----- Style injection for hover/focus states ---------------------------- */

const NUMBER_INPUT_STYLE_ID = 'ts-number-input-styles';

function ensureNumberInputStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(NUMBER_INPUT_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = NUMBER_INPUT_STYLE_ID;
  sheet.textContent = `
    [data-ts-number-input]:not([data-disabled]):hover {
      border-color: var(--ts-input-border-hover);
    }
    [data-ts-number-input]:not([data-disabled]):focus-within {
      border-color: var(--ts-input-border-focus);
      outline: 1px solid var(--ts-input-border-focus);
      outline-offset: -1px;
    }
    [data-ts-number-input][data-disabled] {
      background: var(--ts-input-bg-disabled);
      color: var(--ts-input-text-disabled);
      cursor: not-allowed;
    }
    [data-ts-number-step]:not(:disabled):hover {
      background: var(--ts-number-input-step-bg-hover);
    }
    [data-ts-number-step]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-number-input-field]::placeholder {
      color: var(--ts-input-placeholder);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureNumberInputStyles();
}

/* ----- Size styles ------------------------------------------------------- */

const SIZE_HEIGHTS: Record<NumberInputSize, string> = {
  sm: 'var(--ts-input-height-sm)',
  md: 'var(--ts-input-height-md)',
  lg: 'var(--ts-input-height-lg)',
};

const wrapperStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  background: 'var(--ts-input-bg)',
  color: 'var(--ts-input-text)',
  border: '1px solid var(--ts-input-border)',
  borderRadius: 'var(--ts-input-radius)',
  boxSizing: 'border-box',
  transition: 'border-color 150ms',
  overflow: 'hidden',
};

const inputFieldStyle: CSSProperties = {
  all: 'unset',
  flex: 1,
  minWidth: 0,
  height: '100%',
  padding: '0 var(--ts-input-padding-x)',
  color: 'inherit',
  fontSize: 'var(--ts-input-font-size)',
  fontFamily: 'var(--ts-number-input-font)',
  boxSizing: 'border-box',
  textAlign: 'left',
};

const stepGroupStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  alignSelf: 'stretch',
  flexShrink: 0,
  borderLeft: '1px solid var(--ts-input-border)',
};

const stepButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  flex: 1,
  width: 20,
  background: 'var(--ts-number-input-step-bg)',
  color: 'var(--ts-number-input-step-text)',
  cursor: 'pointer',
  boxSizing: 'border-box',
};

const stepButtonDisabledStyle: CSSProperties = {
  ...stepButtonStyle,
  cursor: 'not-allowed',
  opacity: 0.4,
};

export const NumberInput = forwardRef<HTMLInputElement, NumberInputProps>(
  function NumberInput(
    { value, onChange, min, max, step = 1, precision, size = 'md', disabled = false, label },
    ref,
  ) {
    const internalRef = useRef<HTMLInputElement>(null);
    const inputRef = (ref as React.RefObject<HTMLInputElement>) ?? internalRef;

    /* Stabilize the onChange callback using a ref so that react-aria hooks
       don't trigger infinite re-render loops when the parent re-creates onChange
       on every render (e.g., when onChange depends on external state). */
    const onChangeRef = useRef(onChange);
    useEffect(() => {
      onChangeRef.current = onChange;
    });
    const stableOnChange = useCallback((v: number) => {
      onChangeRef.current?.(v);
    }, []);

    const formatOptions: Intl.NumberFormatOptions | undefined = useMemo(
      () =>
        precision !== undefined
          ? { minimumFractionDigits: precision, maximumFractionDigits: precision }
          : undefined,
      [precision],
    );

    const state = useNumberFieldState({
      value,
      onChange: stableOnChange,
      minValue: min,
      maxValue: max,
      step,
      formatOptions,
      isDisabled: disabled,
      locale: 'en-US',
      label: label ?? 'Number input',
    });

    const { inputProps, incrementButtonProps, decrementButtonProps, groupProps, labelProps } =
      useNumberField(
        {
          value,
          onChange: stableOnChange,
          minValue: min,
          maxValue: max,
          step,
          formatOptions,
          isDisabled: disabled,
          label: label ?? 'Number input',
        },
        state,
        inputRef,
      );

    /* Extract only DOM-safe aria/id attributes from React Aria button props. */
    const extractAriaProps = useCallback(
      (props: Record<string, unknown>): Record<string, unknown> => {
        const result: Record<string, unknown> = {};
        for (const key of Object.keys(props)) {
          if (key.startsWith('aria-') || key === 'id') {
            result[key] = props[key];
          }
        }
        return result;
      },
      [],
    );

    const incAriaProps = extractAriaProps(
      incrementButtonProps as unknown as Record<string, unknown>,
    );
    const decAriaProps = extractAriaProps(
      decrementButtonProps as unknown as Record<string, unknown>,
    );

    const handleIncrement = useCallback(() => {
      if (!disabled) {
        state.increment();
      }
    }, [disabled, state]);

    const handleDecrement = useCallback(() => {
      if (!disabled) {
        state.decrement();
      }
    }, [disabled, state]);

    return (
      <div
        {...groupProps}
        data-ts-number-input=""
        {...(disabled ? { 'data-disabled': '' } : {})}
        style={{
          ...wrapperStyle,
          height: SIZE_HEIGHTS[size],
        }}
      >
        {label && (
          <label {...labelProps} style={{ position: 'absolute', clip: 'rect(0 0 0 0)' }}>
            {label}
          </label>
        )}
        <input
          {...inputProps}
          ref={inputRef}
          data-ts-number-input-field=""
          style={inputFieldStyle}
        />
        <div style={stepGroupStyle}>
          <button
            type="button"
            {...incAriaProps}
            data-ts-number-step=""
            disabled={disabled}
            onClick={handleIncrement}
            style={disabled ? stepButtonDisabledStyle : stepButtonStyle}
            tabIndex={-1}
          >
            <ChevronUp size={12} aria-hidden />
          </button>
          <button
            type="button"
            {...decAriaProps}
            data-ts-number-step=""
            disabled={disabled}
            onClick={handleDecrement}
            style={{
              ...(disabled ? stepButtonDisabledStyle : stepButtonStyle),
              borderTop: '1px solid var(--ts-input-border)',
            }}
            tabIndex={-1}
          >
            <ChevronDown size={12} aria-hidden />
          </button>
        </div>
      </div>
    );
  },
);

NumberInput.displayName = 'NumberInput';
