import { useCallback, type CSSProperties, type ReactNode } from 'react';
import { Popover } from '../primitives';
import type { ToolConfig } from './ToolCategory';

/* -------------------------------------------------------------------------- */
/*  ToolFlyout                                                                */
/*  Popover flyout showing all tools in a category.                          */
/*  Anchored to the ToolCategory arrow, opens to the right.                  */
/*  Uses Popover primitive with --ts-overlay-* tokens.                       */
/* -------------------------------------------------------------------------- */

export interface ToolFlyoutProps {
  /** All tools available in this category. */
  tools: ToolConfig[];
  /** Currently selected tool value. */
  selectedValue?: string;
  /** Called when a tool is selected from the flyout. */
  onToolSelect: (toolValue: string) => void;
  /** Whether the flyout is open. */
  open: boolean;
  /** Called when the open state changes. */
  onOpenChange: (open: boolean) => void;
  /** Trigger element (the category arrow button). */
  children: ReactNode;
  /** Category label for the flyout header. */
  label: string;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-tool-flyout-styles';

function ensureToolFlyoutStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-tool-flyout-item]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -1px;
    }
    [data-ts-tool-flyout-item]:not([data-selected]):hover {
      background: var(--ts-menu-item-bg-hover);
    }
    [data-ts-tool-flyout-item][data-selected] {
      background: var(--ts-selector-active-bg);
      color: var(--ts-selector-active-text);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureToolFlyoutStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const contentStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  padding: 'var(--ts-menu-padding-y) 0',
  minWidth: 200,
  maxWidth: 260,
};

const headerStyle: CSSProperties = {
  fontSize: 'var(--ts-menu-label-font-size)',
  fontWeight: 'var(--ts-menu-label-font-weight)' as unknown as number,
  color: 'var(--ts-menu-label-text)',
  padding: '0 var(--ts-menu-item-padding-x)',
  height: 'var(--ts-menu-item-height)',
  display: 'flex',
  alignItems: 'center',
  fontFamily: 'inherit',
  userSelect: 'none',
};

const itemStyle: CSSProperties = {
  all: 'unset',
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-menu-item-height)',
  padding: '0 var(--ts-menu-item-padding-x)',
  gap: '8px',
  fontSize: 'var(--ts-font-md)',
  fontFamily: 'inherit',
  color: 'var(--ts-menu-item-text)',
  cursor: 'pointer',
  userSelect: 'none',
  boxSizing: 'border-box',
  transition: 'background 100ms',
};

const iconSlotStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 16,
  height: 16,
  flexShrink: 0,
  color: 'var(--ts-menu-item-icon)',
};

const labelSlotStyle: CSSProperties = {
  flex: 1,
};

/* ----- Component --------------------------------------------------------- */

export function ToolFlyout({
  tools,
  selectedValue,
  onToolSelect,
  open,
  onOpenChange,
  children,
  label,
}: ToolFlyoutProps): React.JSX.Element {
  const handleSelect = useCallback(
    (toolValue: string) => {
      onToolSelect(toolValue);
      onOpenChange(false);
    },
    [onToolSelect, onOpenChange],
  );

  return (
    <Popover open={open} onOpenChange={onOpenChange}>
      <Popover.Trigger>{children}</Popover.Trigger>
      <Popover.Content side="right" align="start" sideOffset={4}>
        <div data-ts-tool-flyout="" style={contentStyle}>
          <div style={headerStyle}>{label}</div>
          {tools.map((tool) => {
            const isSelected = tool.value === selectedValue;
            return (
              <button
                key={tool.value}
                type="button"
                data-ts-tool-flyout-item=""
                {...(isSelected ? { 'data-selected': '' } : {})}
                style={itemStyle}
                onClick={() => handleSelect(tool.value)}
                role="menuitem"
                tabIndex={0}
                aria-label={tool.label}
              >
                <span style={iconSlotStyle}>{tool.icon}</span>
                <span style={labelSlotStyle}>{tool.label}</span>
              </button>
            );
          })}
        </div>
      </Popover.Content>
    </Popover>
  );
}

ToolFlyout.displayName = 'ToolFlyout';
