import { forwardRef, useCallback, type CSSProperties, type KeyboardEvent } from 'react';

/* -------------------------------------------------------------------------- */
/*  Toggle                                                                    */
/*  Sliding switch for binary on/off settings.                                */
/*  Uses --ts-toggle-* tokens. Accessible switch role.                        */
/* -------------------------------------------------------------------------- */

export interface ToggleProps {
  /** Whether the toggle is on. */
  checked?: boolean;
  /** Called when the toggle state changes. */
  onCheckedChange?: (checked: boolean) => void;
  /** Whether the toggle is disabled. */
  disabled?: boolean;
  /** Text label rendered beside the toggle. */
  label?: string;
}

/* ----- Style injection for hover/focus states ---------------------------- */

const TOGGLE_STYLE_ID = 'ts-toggle-styles';

function ensureToggleStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(TOGGLE_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = TOGGLE_STYLE_ID;
  sheet.textContent = `
    [data-ts-toggle]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-toggle-label] {
      cursor: pointer;
      user-select: none;
    }
    [data-ts-toggle-label][data-disabled] {
      cursor: not-allowed;
      opacity: 0.5;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureToggleStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const trackStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  width: 'var(--ts-toggle-width)',
  height: 'var(--ts-toggle-height)',
  borderRadius: 'calc(var(--ts-toggle-height) / 2)',
  padding: '2px',
  cursor: 'pointer',
  boxSizing: 'border-box',
  transition: 'background 150ms',
  flexShrink: 0,
  position: 'relative',
};

const trackUncheckedStyle: CSSProperties = {
  ...trackStyle,
  background: 'var(--ts-toggle-bg)',
};

const trackCheckedStyle: CSSProperties = {
  ...trackStyle,
  background: 'var(--ts-toggle-bg-checked)',
};

const trackDisabledStyle: CSSProperties = {
  background: 'var(--ts-toggle-bg-disabled)',
  cursor: 'not-allowed',
};

const thumbBaseStyle: CSSProperties = {
  display: 'block',
  borderRadius: '50%',
  transition: 'transform 150ms ease, background 150ms',
  boxSizing: 'border-box',
};

const THUMB_SIZE = 'calc(var(--ts-toggle-height) - 4px)';

const thumbUncheckedStyle: CSSProperties = {
  ...thumbBaseStyle,
  width: THUMB_SIZE,
  height: THUMB_SIZE,
  background: 'var(--ts-toggle-thumb)',
  transform: 'translateX(0)',
};

const thumbCheckedStyle: CSSProperties = {
  ...thumbBaseStyle,
  width: THUMB_SIZE,
  height: THUMB_SIZE,
  background: 'var(--ts-toggle-thumb)',
  transform: 'translateX(calc(var(--ts-toggle-width) - var(--ts-toggle-height)))',
};

const thumbDisabledStyle: CSSProperties = {
  background: 'var(--ts-toggle-thumb-disabled)',
};

const labelWrapperStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const labelTextStyle: CSSProperties = {
  fontSize: 'var(--ts-font-md)',
  fontFamily: 'inherit',
  color: 'var(--ts-text-primary)',
};

export const Toggle = forwardRef<HTMLButtonElement, ToggleProps>(
  function Toggle({ checked = false, onCheckedChange, disabled = false, label }, ref) {
    const handleClick = useCallback(() => {
      if (!disabled && onCheckedChange) {
        onCheckedChange(!checked);
      }
    }, [checked, disabled, onCheckedChange]);

    const handleKeyDown = useCallback(
      (e: KeyboardEvent<HTMLButtonElement>) => {
        if (disabled) return;
        if (e.key === 'Enter' || e.key === ' ') {
          e.preventDefault();
          onCheckedChange?.(!checked);
        }
      },
      [checked, disabled, onCheckedChange],
    );

    const currentTrackStyle: CSSProperties = {
      ...(checked ? trackCheckedStyle : trackUncheckedStyle),
      ...(disabled ? trackDisabledStyle : {}),
    };

    const currentThumbStyle: CSSProperties = {
      ...(checked ? thumbCheckedStyle : thumbUncheckedStyle),
      ...(disabled ? thumbDisabledStyle : {}),
    };

    const toggleElement = (
      <button
        ref={ref}
        type="button"
        role="switch"
        data-ts-toggle=""
        aria-checked={checked}
        aria-label={label}
        disabled={disabled}
        onClick={handleClick}
        onKeyDown={handleKeyDown}
        style={currentTrackStyle}
      >
        <span style={currentThumbStyle} aria-hidden />
      </button>
    );

    if (label) {
      return (
        <label
          data-ts-toggle-label=""
          {...(disabled ? { 'data-disabled': '' } : {})}
          style={labelWrapperStyle}
        >
          {toggleElement}
          <span style={labelTextStyle}>{label}</span>
        </label>
      );
    }

    return toggleElement;
  },
);

Toggle.displayName = 'Toggle';
