import {
  useState,
  useCallback,
  useEffect,
  useRef,
  useMemo,
  forwardRef,
  type CSSProperties,
} from 'react';
import {
  VirtualList,
  Badge,
  TradeRow,
  type Trade,
  type TradeSide,
} from '@deskmodal/ui-components';
import {
  BarChart3,
  Activity,
  List,
  Settings2,
  ChevronDown,
} from 'lucide-react';
import type { DeltaBucket } from '../services/delta-aggregator';
import type { SizeTier } from '../services/large-trade-detector';
import { CVDPanel } from './CVDPanel';
import { DeltaBarRow } from './DeltaBarRow';

/* -------------------------------------------------------------------------- */
/*  EnhancedTradeHistory                                                       */
/*  Trade history panel with three modes: raw trades, delta bars, CVD chart.   */
/*  Integrates delta aggregation and large trade detection.                    */
/* -------------------------------------------------------------------------- */

export type TradeViewMode = 'raw' | 'delta' | 'cvd';

export interface ClassifiedTrade extends Trade {
  /** The detected size tier for this trade. */
  readonly tier: SizeTier;
}

export interface EnhancedTradeHistoryProps {
  /** Instrument symbol. */
  readonly symbol: string;
  /** Array of trades with tier classification, newest first. */
  readonly trades: readonly ClassifiedTrade[];
  /** Completed delta buckets. */
  readonly buckets: readonly DeltaBucket[];
  /** In-progress delta bucket. */
  readonly currentBucket: DeltaBucket | null;
  /** Current cumulative volume delta. */
  readonly cvdValue: number;
  /** Called to reset CVD. */
  readonly onResetCVD: () => void;
  /** Price precision. */
  readonly precision: number;
  /** Size precision. */
  readonly sizePrecision: number;
  /** Minimum trade size filter. */
  readonly sizeFilter: number;
  /** Called when size filter changes. */
  readonly onSizeFilterChange: (size: number) => void;
  /** Side filter. */
  readonly sideFilter: TradeSide | null;
  /** Called when side filter changes. */
  readonly onSideFilterChange: (side: TradeSide | null) => void;
  /** Whether the feed is paused. */
  readonly paused: boolean;
  /** Called when pause state changes. */
  readonly onPausedChange: (paused: boolean) => void;
  /** Display density mode. */
  readonly densityMode: 'compact' | 'expanded';
}

/* ----- Style injection --------------------------------------------------- */

const ENHANCED_TRADES_STYLE_ID = 'ts-enhanced-trade-history-styles';

function ensureEnhancedTradeHistoryStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(ENHANCED_TRADES_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = ENHANCED_TRADES_STYLE_ID;
  sheet.textContent = `
    [data-ts-trade-mode-btn]:hover:not([data-active]) {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-trade-mode-btn]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-trade-mode-btn][data-active] {
      background: var(--ts-button-ghost-bg-active);
      color: var(--ts-text-primary);
    }
    [data-ts-enhanced-trade-row][data-highlight] {
      animation: ts-trade-flash 300ms ease-out;
    }
    @keyframes ts-trade-flash {
      0% { background-color: rgba(59, 130, 246, 0.15); }
      100% { background-color: transparent; }
    }
    [data-ts-new-trades-badge-enhanced]:hover {
      filter: brightness(1.1);
    }
    [data-ts-settings-btn]:hover {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-settings-btn]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-side-filter-btn-enhanced]:hover:not([data-active]) {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-side-filter-btn-enhanced]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-pause-btn-enhanced]:hover {
      background: var(--ts-button-ghost-bg-hover);
    }
    [data-ts-pause-btn-enhanced]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureEnhancedTradeHistoryStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  height: '100%',
  background: 'var(--ts-panel-bg)',
  border: '1px solid var(--ts-panel-border)',
  borderRadius: 'var(--ts-radius-sm)',
  overflow: 'hidden',
};

const headerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-panel-header-height)',
  padding: '0 var(--ts-space-2)',
  background: 'var(--ts-panel-header-bg)',
  color: 'var(--ts-panel-header-text)',
  fontSize: 'var(--ts-font-md)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  borderBottom: '1px solid var(--ts-panel-border)',
  gap: 'var(--ts-space-1)',
  userSelect: 'none',
  flexShrink: 0,
};

const modeGroupStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '1px',
  marginLeft: 'auto',
};

const modeBtnStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: '24px',
  height: '20px',
  borderRadius: 'var(--ts-radius-sm)',
  color: 'var(--ts-text-tertiary)',
  cursor: 'pointer',
  boxSizing: 'border-box',
};

const controlsRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-1) var(--ts-space-2)',
  borderBottom: '1px solid var(--ts-toolbar-border)',
  background: 'var(--ts-toolbar-bg)',
  flexShrink: 0,
  flexWrap: 'wrap',
};

const sizeInputStyle: CSSProperties = {
  all: 'unset',
  width: 50,
  height: 'var(--ts-input-height-sm)',
  padding: '0 var(--ts-space-1)',
  fontSize: 'var(--ts-font-sm)',
  fontFamily: 'var(--ts-font-data)',
  fontVariantNumeric: 'tabular-nums',
  color: 'var(--ts-input-text)',
  background: 'var(--ts-input-bg)',
  border: '1px solid var(--ts-input-border)',
  borderRadius: 'var(--ts-input-radius)',
  boxSizing: 'border-box',
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  whiteSpace: 'nowrap',
  userSelect: 'none',
};

const segmentGroupStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: '1px',
  borderRadius: 'var(--ts-radius-sm)',
};

function segmentBtnStyle(active: boolean): CSSProperties {
  return {
    all: 'unset',
    display: 'inline-flex',
    alignItems: 'center',
    justifyContent: 'center',
    height: 'var(--ts-input-height-sm)',
    padding: '0 var(--ts-space-2)',
    fontSize: 'var(--ts-font-xs)',
    fontFamily: 'inherit',
    color: active ? 'var(--ts-text-primary)' : 'var(--ts-text-secondary)',
    background: active ? 'var(--ts-button-ghost-bg-active)' : 'var(--ts-button-ghost-bg)',
    cursor: 'pointer',
    userSelect: 'none',
    boxSizing: 'border-box',
    borderRadius: 'var(--ts-radius-sm)',
  };
}

const pauseBtnStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  width: 'var(--ts-icon-button-size-sm)',
  height: 'var(--ts-icon-button-size-sm)',
  borderRadius: 'var(--ts-button-radius)',
  color: 'var(--ts-text-secondary)',
  cursor: 'pointer',
  boxSizing: 'border-box',
};

const columnHeaderRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-ob-column-header-height)',
  background: 'var(--ts-ob-column-header-bg)',
  color: 'var(--ts-ob-column-header-text)',
  fontSize: 'var(--ts-ob-column-header-font-size)',
  padding: '0 var(--ts-space-2)',
  textTransform: 'uppercase',
  userSelect: 'none',
  flexShrink: 0,
};

const colCellStyle: CSSProperties = {
  flex: 1,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const bodyStyle: CSSProperties = {
  flex: '1 1 0',
  position: 'relative',
  overflow: 'hidden',
};

const emptyStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: '100%',
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-font-sm)',
  userSelect: 'none',
};

const pausedIndicatorStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-status-warning)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
};

const countStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  fontVariantNumeric: 'tabular-nums',
  whiteSpace: 'nowrap',
};

const badgeContainerStyle: CSSProperties = {
  position: 'absolute',
  top: 'var(--ts-space-1)',
  left: '50%',
  transform: 'translateX(-50%)',
  zIndex: 10,
  cursor: 'pointer',
};

const badgeStyle: CSSProperties = {
  background: 'var(--ts-trade-new-badge-bg)',
  color: 'var(--ts-trade-new-badge-text)',
  fontSize: 'var(--ts-font-xs)',
  padding: '2px var(--ts-space-2)',
  borderRadius: 'var(--ts-radius-sm)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  whiteSpace: 'nowrap',
  userSelect: 'none',
  boxShadow: 'var(--ts-shadow-sm)',
};

const spacerStyle: CSSProperties = { flex: '1 1 auto' };

/* ----- Side filter options ----------------------------------------------- */

const SIDE_OPTIONS: ReadonlyArray<{ value: TradeSide | null; label: string }> = [
  { value: null, label: 'All' },
  { value: 'buy', label: 'Buy' },
  { value: 'sell', label: 'Sell' },
];

/* ----- Mode tab config --------------------------------------------------- */

const MODE_TABS: ReadonlyArray<{ mode: TradeViewMode; icon: typeof List; label: string }> = [
  { mode: 'raw', icon: List, label: 'Raw trades' },
  { mode: 'delta', icon: BarChart3, label: 'Delta bars' },
  { mode: 'cvd', icon: Activity, label: 'CVD chart' },
];

/* ----- Component --------------------------------------------------------- */

export const EnhancedTradeHistory = forwardRef<HTMLDivElement, EnhancedTradeHistoryProps>(
  function EnhancedTradeHistory(
    {
      symbol,
      trades,
      buckets,
      currentBucket,
      cvdValue,
      onResetCVD,
      precision,
      sizePrecision,
      sizeFilter,
      onSizeFilterChange,
      sideFilter,
      onSideFilterChange,
      paused,
      onPausedChange,
      densityMode,
    },
    ref,
  ) {
    const [viewMode, setViewMode] = useState<TradeViewMode>('raw');
    const [cvdCollapsed, setCvdCollapsed] = useState(false);
    const [newTradeCount, setNewTradeCount] = useState(0);
    const [isScrolledAway, setIsScrolledAway] = useState(false);
    const prevTradeCountRef = useRef(trades.length);

    // Track new trades arriving while scrolled away
    useEffect(() => {
      if (isScrolledAway && trades.length > prevTradeCountRef.current) {
        setNewTradeCount((c) => c + (trades.length - prevTradeCountRef.current));
      }
      prevTradeCountRef.current = trades.length;
    }, [trades.length, isScrolledAway]);

    // Filter trades
    const filteredTrades = useMemo(() => {
      let result: readonly ClassifiedTrade[] = trades;
      if (sizeFilter > 0) {
        result = result.filter((t) => t.size >= sizeFilter);
      }
      if (sideFilter !== null) {
        result = result.filter((t) => t.side === sideFilter);
      }
      return result;
    }, [trades, sizeFilter, sideFilter]);

    // Compute max absolute delta for bar normalization
    const maxAbsDelta = useMemo(() => {
      let max = 0;
      for (const b of buckets) {
        const abs = Math.abs(b.netDelta);
        if (abs > max) max = abs;
      }
      if (currentBucket) {
        const abs = Math.abs(currentBucket.netDelta);
        if (abs > max) max = abs;
      }
      return max;
    }, [buckets, currentBucket]);

    // Combine completed + current buckets for delta bar rendering
    const allBuckets = useMemo(() => {
      if (!currentBucket) return buckets;
      return [...buckets, currentBucket];
    }, [buckets, currentBucket]);

    const handleSizeChange = useCallback(
      (e: React.ChangeEvent<HTMLInputElement>) => {
        const val = parseFloat(e.target.value);
        onSizeFilterChange(Number.isNaN(val) ? 0 : val);
      },
      [onSizeFilterChange],
    );

    const handleScrollToTop = useCallback(() => {
      setNewTradeCount(0);
      setIsScrolledAway(false);
    }, []);

    const itemHeight = densityMode === 'compact' ? 22 : 28;

    return (
      <div
        ref={ref}
        data-ts-enhanced-trade-history=""
        data-density={densityMode}
        style={rootStyle}
        data-testid="enhanced-trade-history"
      >
        {/* Header */}
        <div style={headerStyle}>
          <span>Time &amp; Sales</span>
          {paused && (
            <span style={pausedIndicatorStyle} data-testid="trade-paused-indicator">
              Paused
            </span>
          )}
          <div style={modeGroupStyle} data-testid="mode-selector">
            {MODE_TABS.map(({ mode, icon: Icon, label }) => (
              <button
                key={mode}
                type="button"
                data-ts-trade-mode-btn=""
                data-active={viewMode === mode ? '' : undefined}
                style={modeBtnStyle}
                onClick={() => setViewMode(mode)}
                aria-label={label}
                aria-pressed={viewMode === mode}
                data-testid={`mode-${mode}`}
              >
                <Icon size={13} aria-hidden />
              </button>
            ))}
          </div>
        </div>

        {/* CVD Panel (shown in all modes for context) */}
        <CVDPanel
          buckets={buckets}
          currentBucket={currentBucket}
          cvdValue={cvdValue}
          onReset={onResetCVD}
          collapsed={cvdCollapsed}
          onCollapsedChange={setCvdCollapsed}
        />

        {/* Controls (for raw & delta modes) */}
        {viewMode !== 'cvd' && (
          <div style={controlsRowStyle} data-testid="trade-controls">
            <span style={labelStyle}>Min</span>
            <input
              type="number"
              value={sizeFilter || ''}
              onChange={handleSizeChange}
              placeholder="0"
              style={sizeInputStyle}
              aria-label="Minimum trade size"
              data-testid="trade-size-filter"
              min={0}
              step="any"
            />

            <div style={segmentGroupStyle} role="radiogroup" aria-label="Side filter">
              {SIDE_OPTIONS.map(({ value, label }) => {
                const active = sideFilter === value;
                return (
                  <button
                    key={label}
                    type="button"
                    role="radio"
                    data-ts-side-filter-btn-enhanced=""
                    data-active={active ? '' : undefined}
                    aria-checked={active}
                    aria-label={`Show ${label.toLowerCase()} trades`}
                    style={segmentBtnStyle(active)}
                    onClick={() => onSideFilterChange(value)}
                    data-testid={`side-filter-${label.toLowerCase()}`}
                  >
                    {label}
                  </button>
                );
              })}
            </div>

            <button
              type="button"
              data-ts-pause-btn-enhanced=""
              style={pauseBtnStyle}
              onClick={() => onPausedChange(!paused)}
              aria-label={paused ? 'Resume feed' : 'Pause feed'}
              data-testid="trade-pause-btn"
            >
              {paused ? (
                <Activity size={14} aria-hidden />
              ) : (
                <Settings2 size={14} aria-hidden />
              )}
            </button>

            <div style={spacerStyle} />

            <span style={countStyle} data-testid="trade-count">
              {viewMode === 'raw'
                ? `${filteredTrades.length.toLocaleString()} trades`
                : `${allBuckets.length.toLocaleString()} buckets`}
            </span>
          </div>
        )}

        {/* Column headers */}
        {viewMode === 'raw' && (
          <div style={columnHeaderRowStyle} data-testid="trade-column-headers">
            <span style={colCellStyle}>Time</span>
            <span style={{ ...colCellStyle, textAlign: 'right' }}>Price</span>
            <span style={{ ...colCellStyle, textAlign: 'right' }}>Size</span>
          </div>
        )}
        {viewMode === 'delta' && (
          <div style={columnHeaderRowStyle} data-testid="delta-column-headers">
            <span style={{ ...colCellStyle, width: '48px', flex: 'none' }}>Time</span>
            <span style={{ ...colCellStyle, textAlign: 'center' }}>Delta</span>
            <span style={{ ...colCellStyle, width: '60px', flex: 'none', textAlign: 'right' }}>VWAP</span>
            <span style={{ ...colCellStyle, width: '52px', flex: 'none', textAlign: 'right' }}>Net</span>
          </div>
        )}

        {/* Body */}
        <div style={bodyStyle}>
          {/* New trades badge */}
          {viewMode === 'raw' && newTradeCount > 0 && (
            <div
              data-ts-new-trades-badge-enhanced=""
              style={badgeContainerStyle}
              onClick={handleScrollToTop}
              role="button"
              tabIndex={0}
              onKeyDown={(e) => {
                if (e.key === 'Enter' || e.key === ' ') {
                  e.preventDefault();
                  handleScrollToTop();
                }
              }}
              aria-label={`${newTradeCount} new trades, click to scroll to top`}
              data-testid="new-trades-badge"
            >
              <span style={badgeStyle}>
                {newTradeCount} new trade{newTradeCount !== 1 ? 's' : ''}
              </span>
            </div>
          )}

          {/* Raw trades view */}
          {viewMode === 'raw' && (
            filteredTrades.length === 0 ? (
              <div style={emptyStyle} data-testid="trade-empty-state">
                No trades
              </div>
            ) : (
              <VirtualList
                items={filteredTrades as ClassifiedTrade[]}
                itemHeight={itemHeight}
                overscan={5}
                renderItem={(trade) => (
                  <div
                    data-ts-enhanced-trade-row=""
                    data-highlight={trade.tier.highlight ? '' : undefined}
                    style={{
                      borderLeft: `2px solid ${trade.tier.color}`,
                    }}
                  >
                    <TradeRow
                      time={trade.time}
                      price={trade.price}
                      size={trade.size}
                      side={trade.side}
                      precision={precision}
                      sizePrecision={sizePrecision}
                      significant={trade.tier.highlight}
                    />
                  </div>
                )}
              />
            )
          )}

          {/* Delta bars view */}
          {viewMode === 'delta' && (
            allBuckets.length === 0 ? (
              <div style={emptyStyle} data-testid="delta-empty-state">
                No delta data
              </div>
            ) : (
              <VirtualList
                items={allBuckets as DeltaBucket[]}
                itemHeight={itemHeight}
                overscan={5}
                renderItem={(bucket) => (
                  <DeltaBarRow
                    bucket={bucket}
                    maxAbsDelta={maxAbsDelta}
                    precision={precision}
                    height={itemHeight}
                  />
                )}
              />
            )
          )}

          {/* CVD view: full-height chart canvas */}
          {viewMode === 'cvd' && (
            <div style={{ height: '100%', padding: 'var(--ts-space-2)' }}>
              <CVDPanel
                buckets={buckets}
                currentBucket={currentBucket}
                cvdValue={cvdValue}
                onReset={onResetCVD}
                collapsed={false}
                onCollapsedChange={() => {}}
              />
            </div>
          )}
        </div>
      </div>
    );
  },
);

EnhancedTradeHistory.displayName = 'EnhancedTradeHistory';
