import type { CSSProperties, MouseEventHandler } from 'react';

/* -------------------------------------------------------------------------- */
/*  SymbolChip                                                                */
/*  Ticker badge with optional exchange info.                                 */
/*  Uses --ts-symbol-chip-* tokens.                                           */
/* -------------------------------------------------------------------------- */

export interface SymbolChipProps {
  /** Ticker symbol, e.g. "BTCUSDT". */
  symbol: string;
  /** Exchange name, e.g. "Binance". */
  exchange?: string;
  /** Click handler. */
  onClick?: MouseEventHandler<HTMLButtonElement>;
  /** Whether the chip is in an active/selected state. */
  active?: boolean;
}

/* ----- Style injection for hover/active states --------------------------- */

const CHIP_STYLE_ID = 'ts-symbol-chip-styles';

function ensureChipStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(CHIP_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = CHIP_STYLE_ID;
  sheet.textContent = `
    [data-ts-symbol-chip]:hover:not([data-active]) {
      background: var(--ts-symbol-chip-bg-hover);
    }
    [data-ts-symbol-chip]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 1px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureChipStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const chipBaseStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  gap: '4px',
  height: 'var(--ts-symbol-chip-height)',
  padding: `0 var(--ts-symbol-chip-padding-x)`,
  background: 'var(--ts-symbol-chip-bg)',
  color: 'var(--ts-symbol-chip-text)',
  border: '1px solid var(--ts-symbol-chip-border)',
  borderRadius: 'var(--ts-symbol-chip-radius)',
  fontSize: 'var(--ts-symbol-chip-font-size)',
  fontWeight: 'var(--ts-symbol-chip-font-weight)' as unknown as number,
  fontFamily: 'inherit',
  lineHeight: 1,
  whiteSpace: 'nowrap',
  cursor: 'pointer',
  userSelect: 'none',
  boxSizing: 'border-box',
  transition: 'background 150ms',
};

const chipActiveStyle: CSSProperties = {
  ...chipBaseStyle,
  background: 'var(--ts-accent-subtle)',
  borderColor: 'var(--ts-accent-default)',
  color: 'var(--ts-accent-default)',
};

const exchangeStyle: CSSProperties = {
  color: 'var(--ts-symbol-chip-exchange-text)',
  fontWeight: 'normal' as const,
};

/* ----- Component --------------------------------------------------------- */

export function SymbolChip({
  symbol,
  exchange,
  onClick,
  active = false,
}: SymbolChipProps): React.JSX.Element {
  return (
    <button
      type="button"
      data-ts-symbol-chip=""
      {...(active ? { 'data-active': '' } : {})}
      style={active ? chipActiveStyle : chipBaseStyle}
      onClick={onClick}
      data-testid="symbol-chip"
    >
      <span>{symbol}</span>
      {exchange !== undefined && (
        <span style={exchangeStyle} data-testid="symbol-chip-exchange">
          {exchange}
        </span>
      )}
    </button>
  );
}

SymbolChip.displayName = 'SymbolChip';
