/**
 * Maps a numeric value to a background CSS color for heat map visualization.
 * Uses CSS custom properties for theme compatibility.
 */
export type HeatPalette = 'diverging' | 'sequential';

export function getHeatColor(
  value: number | null | undefined,
  min: number,
  max: number,
  palette: HeatPalette = 'diverging',
): string {
  if (value == null || isNaN(value) || min === max) return 'transparent';

  if (palette === 'diverging') {
    // Diverging: negative = bearish red, zero = transparent, positive = bullish green
    const intensity = Math.min(Math.abs(value) / Math.max(Math.abs(min), Math.abs(max), 1), 1);
    const alpha = intensity * 0.25; // Max 25% opacity for subtlety
    if (value > 0) return `rgba(var(--ts-heatmap-positive-rgb, 34, 197, 94), ${alpha})`;
    if (value < 0) return `rgba(var(--ts-heatmap-negative-rgb, 239, 68, 68), ${alpha})`;
    return 'transparent';
  }

  // Sequential: low = transparent, high = accent color
  const normalized = (value - min) / (max - min);
  const alpha = Math.max(0, Math.min(normalized * 0.3, 0.3));
  return `rgba(var(--ts-heatmap-accent-rgb, 59, 130, 246), ${alpha})`;
}

/** Compute min/max for a column across all visible symbols. */
export function computeColumnRange(
  values: Array<number | null | undefined>,
): { min: number; max: number } {
  let min = 0;
  let max = 0;
  for (const v of values) {
    if (v != null && !isNaN(v)) {
      if (v < min) min = v;
      if (v > max) max = v;
    }
  }
  return { min, max };
}
