/**
 * Subscribe to the `deskmodal.orderbook` FDC3 app channel for orderbook
 * snapshots from the price-feed service. Transforms incoming contexts
 * into `AggregatedOrderbook` and pushes them into the depth Zustand store.
 *
 * The price-feed service broadcasts orderbook data as `deskmodal.orderbook`
 * contexts with bids/asks as `[[price, qty], ...]` arrays. This hook
 * converts them to the `AggregatedLevel[]` format the store expects.
 */

import { useEffect, useRef, useCallback } from 'react';
import { useChannel, CHANNELS, createMessagePackCodec } from '@deskmodal/fdc3';
import type { Context, Listener } from '@deskmodal/fdc3';
import type { AggregatedOrderbook, AggregatedLevel } from '@deskmodal/data-layer';
import { useDepthStore, type DepthOrderbookLevel } from '../store/depth-store';
import { useShallow } from 'zustand/react/shallow';

export interface OrderbookData {
  readonly bids: DepthOrderbookLevel[];
  readonly asks: DepthOrderbookLevel[];
  readonly spread: number | null;
  readonly midPrice: number | null;
  readonly imbalance: number;
  readonly lastUpdate: number;
}

/**
 * Subscribe to the orderbook FDC3 channel and gate updates through
 * requestAnimationFrame so React never re-renders faster than the
 * display refresh rate (~16ms). Intermediate snapshots are coalesced:
 * only the latest book state is flushed each frame.
 */
export function useOrderbookData(symbol: string): OrderbookData {
  const channel = useChannel(CHANNELS.ORDERBOOK);
  const codecRef = useRef(createMessagePackCodec());
  const setOrderbook = useDepthStore((s) => s.setOrderbook);

  // rAF coalescing: accumulate latest book in a ref, flush once per frame
  const pendingBookRef = useRef<AggregatedOrderbook | null>(null);
  const rafIdRef = useRef<number | null>(null);

  const flushToStore = useCallback(() => {
    rafIdRef.current = null;
    if (pendingBookRef.current) {
      setOrderbook(pendingBookRef.current);
      pendingBookRef.current = null;
    }
  }, [setOrderbook]);

  const scheduleFlush = useCallback((book: AggregatedOrderbook) => {
    pendingBookRef.current = book;
    if (rafIdRef.current === null) {
      rafIdRef.current = requestAnimationFrame(flushToStore);
    }
  }, [flushToStore]);

  const data = useDepthStore(useShallow((s) => ({
    bids: s.bids,
    asks: s.asks,
    spread: s.spread,
    midPrice: s.midPrice,
    imbalance: s.imbalance,
    lastUpdate: s.lastUpdate,
  })));

  useEffect(() => {
    if (!channel) return;

    let listener: Listener | undefined;
    let cancelled = false;

    const listenerPromise = channel.addContextListener(
      null,
      (ctx: Context) => {
        if (cancelled) return;

        let book: AggregatedOrderbook;
        const raw = ctx as unknown as Record<string, unknown>;

        // Skip non-orderbook contexts (quote, trade, etc.)
        if (!raw.bids && raw.dataType !== 'orderbook') return;

        if (
          raw['deskmodal.encoding'] === 'msgpack' &&
          raw['deskmodal.binary']
        ) {
          const binary = new Uint8Array(raw['deskmodal.binary'] as number[]).buffer;
          book = codecRef.current.decode<AggregatedOrderbook>(binary);
        } else {
          const ticker = (raw.id as Record<string, string> | undefined)?.ticker ??
                         (raw as { symbol?: string }).symbol ?? '';
          const exchange = (raw.exchange as string) ?? 'unknown';
          const rawBids = (raw.bids as Array<[number, number]>) ?? [];
          const rawAsks = (raw.asks as Array<[number, number]>) ?? [];

          const toLevel = (levels: Array<[number, number]>): AggregatedLevel[] =>
            levels.map(([price, quantity]) => ({
              price,
              quantity,
              exchanges: [{ exchangeId: exchange as never, quantity }],
            }));

          book = {
            symbol: ticker,
            bids: toLevel(rawBids),
            asks: toLevel(rawAsks),
            timestamp: (raw.timestamp as number) ?? Date.now(),
            sourceCount: 1,
          } as AggregatedOrderbook;
        }

        // Normalize for comparison: service sends "BTCUSDT", app uses "BTC/USDT"
        const norm = (s: string) => s.replace(/[/-]/g, '').toUpperCase();
        if (symbol && norm(book.symbol) !== norm(symbol)) return;

        // Gate through rAF — coalesce rapid updates, flush once per frame
        scheduleFlush(book);
      },
    );

    listenerPromise.then(
      (l) => {
        if (cancelled) {
          l.unsubscribe();
        } else {
          listener = l;
        }
      },
      () => {},
    );

    return () => {
      cancelled = true;
      listener?.unsubscribe();
      // Cancel any pending rAF to prevent stale updates after unmount
      if (rafIdRef.current !== null) {
        cancelAnimationFrame(rafIdRef.current);
        rafIdRef.current = null;
      }
      pendingBookRef.current = null;
    };
  }, [channel, symbol, scheduleFlush]);

  return data;
}
