import { forwardRef, type CSSProperties, type ReactNode, type ButtonHTMLAttributes } from 'react';
import { usePress } from '@react-aria/interactions';
import { Loader2 } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  Button                                                                    */
/*  Primary action trigger with variant, size, and loading states.            */
/*  Uses --ts-button-{variant}-* tokens.                                      */
/* -------------------------------------------------------------------------- */

type ButtonVariant = 'primary' | 'secondary' | 'ghost' | 'danger';
type ButtonSize = 'sm' | 'md' | 'lg';

export interface ButtonProps extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, 'children'> {
  /** Visual style variant. */
  variant?: ButtonVariant;
  /** Button size controlling height and padding. */
  size?: ButtonSize;
  /** Whether the button is in a loading state. Disables interaction and shows spinner. */
  loading?: boolean;
  /** Button content. */
  children: ReactNode;
}

/* ----- Style injection for hover/active/focus states --------------------- */

const BUTTON_STYLE_ID = 'ts-button-styles';

function ensureButtonStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(BUTTON_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = BUTTON_STYLE_ID;
  sheet.textContent = `
    [data-ts-button]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-button][data-variant="primary"]:not(:disabled):hover {
      background: var(--ts-button-primary-bg-hover);
    }
    [data-ts-button][data-variant="primary"]:not(:disabled):active,
    [data-ts-button][data-variant="primary"]:not(:disabled)[data-pressed] {
      background: var(--ts-button-primary-bg-active);
    }
    [data-ts-button][data-variant="primary"]:disabled {
      background: var(--ts-button-primary-bg-disabled);
      color: var(--ts-button-primary-text-disabled);
      cursor: not-allowed;
    }
    [data-ts-button][data-variant="secondary"]:not(:disabled):hover {
      background: var(--ts-button-secondary-bg-hover);
    }
    [data-ts-button][data-variant="secondary"]:not(:disabled):active,
    [data-ts-button][data-variant="secondary"]:not(:disabled)[data-pressed] {
      background: var(--ts-button-secondary-bg-active);
    }
    [data-ts-button][data-variant="secondary"]:disabled {
      background: var(--ts-button-secondary-bg-disabled);
      color: var(--ts-button-secondary-text-disabled);
      cursor: not-allowed;
    }
    [data-ts-button][data-variant="ghost"]:not(:disabled):hover {
      background: var(--ts-button-ghost-bg-hover);
      color: var(--ts-button-ghost-text-hover);
    }
    [data-ts-button][data-variant="ghost"]:not(:disabled):active,
    [data-ts-button][data-variant="ghost"]:not(:disabled)[data-pressed] {
      background: var(--ts-button-ghost-bg-active);
    }
    [data-ts-button][data-variant="ghost"]:disabled {
      background: var(--ts-button-ghost-bg-disabled);
      color: var(--ts-button-ghost-text-disabled);
      cursor: not-allowed;
    }
    [data-ts-button][data-variant="danger"]:not(:disabled):hover {
      background: var(--ts-button-danger-bg-hover);
    }
    [data-ts-button][data-variant="danger"]:not(:disabled):active,
    [data-ts-button][data-variant="danger"]:not(:disabled)[data-pressed] {
      background: var(--ts-button-danger-bg-active);
    }
    [data-ts-button][data-variant="danger"]:disabled {
      background: var(--ts-button-danger-bg-disabled);
      color: var(--ts-button-danger-text-disabled);
      cursor: not-allowed;
    }
    @keyframes ts-button-spin {
      from { transform: rotate(0deg); }
      to { transform: rotate(360deg); }
    }
    [data-ts-button-spinner] {
      animation: ts-button-spin 700ms linear infinite;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureButtonStyles();
}

/* ----- Variant base styles ----------------------------------------------- */

const VARIANT_STYLES: Record<ButtonVariant, CSSProperties> = {
  primary: {
    background: 'var(--ts-button-primary-bg)',
    color: 'var(--ts-button-primary-text)',
    border: '1px solid var(--ts-button-primary-border)',
  },
  secondary: {
    background: 'var(--ts-button-secondary-bg)',
    color: 'var(--ts-button-secondary-text)',
    border: '1px solid var(--ts-button-secondary-border)',
  },
  ghost: {
    background: 'var(--ts-button-ghost-bg)',
    color: 'var(--ts-button-ghost-text)',
    border: '1px solid var(--ts-button-ghost-border)',
  },
  danger: {
    background: 'var(--ts-button-danger-bg)',
    color: 'var(--ts-button-danger-text)',
    border: '1px solid var(--ts-button-danger-border)',
  },
};

const SIZE_STYLES: Record<ButtonSize, CSSProperties> = {
  sm: {
    height: 'var(--ts-button-height-sm)',
    padding: '0 var(--ts-button-padding-x-sm)',
  },
  md: {
    height: 'var(--ts-button-height-md)',
    padding: '0 var(--ts-button-padding-x-md)',
  },
  lg: {
    height: 'var(--ts-button-height-lg)',
    padding: '0 var(--ts-button-padding-x-lg)',
  },
};

const baseStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  gap: 'var(--ts-button-gap)',
  borderRadius: 'var(--ts-button-radius)',
  fontSize: 'var(--ts-button-font-size)',
  fontWeight: 'var(--ts-button-font-weight)' as unknown as number,
  fontFamily: 'inherit',
  lineHeight: 1,
  whiteSpace: 'nowrap',
  userSelect: 'none',
  cursor: 'pointer',
  boxSizing: 'border-box',
  transition: 'background 150ms, color 150ms',
};

const spinnerStyle: CSSProperties = {
  flexShrink: 0,
};

export const Button = forwardRef<HTMLButtonElement, ButtonProps>(
  function Button(
    {
      variant = 'primary',
      size = 'md',
      loading = false,
      disabled,
      children,
      onClick,
      style,
      ...rest
    },
    ref,
  ) {
    const isDisabled = disabled || loading;

    const { pressProps } = usePress({
      isDisabled,
      onPress: (e) => {
        if (onClick) {
          onClick(e as unknown as React.MouseEvent<HTMLButtonElement>);
        }
      },
    });

    return (
      <button
        ref={ref}
        type="button"
        data-ts-button=""
        data-variant={variant}
        disabled={isDisabled}
        {...pressProps}
        {...rest}
        style={{
          ...baseStyle,
          ...VARIANT_STYLES[variant],
          ...SIZE_STYLES[size],
          ...style,
        }}
      >
        {loading && (
          <Loader2
            size={14}
            data-ts-button-spinner=""
            style={spinnerStyle}
            aria-hidden
          />
        )}
        {children}
      </button>
    );
  },
);

Button.displayName = 'Button';
