import {
  forwardRef,
  useCallback,
  type CSSProperties,
  type ReactNode,
} from 'react';
import { X, ChevronDown } from 'lucide-react';
import { Popover } from '../../primitives';

/* -------------------------------------------------------------------------- */
/*  FilterChip                                                                */
/*  Pill-shaped filter button with popover panel for screener filters.        */
/*  Composes Tag + Popover. Uses --ts-screener-filter-chip-* tokens.          */
/* -------------------------------------------------------------------------- */

export interface FilterChipProps {
  /** Display label for the filter (e.g., "Market cap", "Volume"). */
  label: string;
  /** Current filter value summary (e.g., ">$1B", "50-100"). Null when inactive. */
  valueSummary: string | null;
  /** Whether the filter is actively applied. */
  active: boolean;
  /** Content rendered inside the popover dropdown when the chip is clicked. */
  children: ReactNode;
  /** Called when the filter is cleared via the remove button. */
  onClear: () => void;
  /** Whether the chip is disabled. */
  disabled?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-filter-chip-styles';

function ensureFilterChipStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-filter-chip]:not([data-disabled]):hover {
      border-color: var(--ts-screener-filter-chip-border-active);
    }
    [data-ts-filter-chip]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-filter-chip-clear]:hover {
      color: var(--ts-screener-filter-chip-text-active);
      opacity: 1;
    }
    [data-ts-filter-chip-clear]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -1px;
      border-radius: 50%;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureFilterChipStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const chipBaseStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  height: 'var(--ts-screener-filter-chip-height, 28px)',
  padding: '0 var(--ts-screener-filter-chip-padding-x, 10px)',
  background: 'var(--ts-screener-filter-chip-bg, var(--ts-tag-bg))',
  color: 'var(--ts-screener-filter-chip-text, var(--ts-tag-text))',
  border: '1px solid var(--ts-screener-filter-chip-border, var(--ts-tag-border))',
  borderRadius: 'var(--ts-screener-filter-chip-radius, 9999px)',
  fontSize: 'var(--ts-screener-filter-chip-font-size, var(--ts-font-sm))',
  fontFamily: 'inherit',
  cursor: 'pointer',
  whiteSpace: 'nowrap',
  userSelect: 'none',
  boxSizing: 'border-box',
  transition: 'background 150ms, border-color 150ms, color 150ms',
};

const chipActiveStyle: CSSProperties = {
  ...chipBaseStyle,
  background: 'var(--ts-screener-filter-chip-bg-active, var(--ts-accent-subtle))',
  color: 'var(--ts-screener-filter-chip-text-active, var(--ts-accent-default))',
  borderColor: 'var(--ts-screener-filter-chip-border-active, var(--ts-accent-default))',
};

const chipDisabledStyle: CSSProperties = {
  ...chipBaseStyle,
  opacity: 0.5,
  cursor: 'not-allowed',
};

const clearButtonStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  cursor: 'pointer',
  padding: 0,
  marginLeft: '2px',
  flexShrink: 0,
  opacity: 0.7,
  transition: 'opacity 150ms, color 150ms',
};

const chevronStyle: CSSProperties = {
  flexShrink: 0,
  opacity: 0.6,
  transition: 'opacity 150ms',
};

const popoverContentStyle: CSSProperties = {
  padding: 'var(--ts-space-3)',
  minWidth: 200,
};

/* ----- Component --------------------------------------------------------- */

export const FilterChip = forwardRef<HTMLButtonElement, FilterChipProps>(
  function FilterChip(
    { label, valueSummary, active, children, onClear, disabled = false },
    ref,
  ) {
    const handleClear = useCallback(
      (e: React.MouseEvent) => {
        e.stopPropagation();
        e.preventDefault();
        onClear();
      },
      [onClear],
    );

    const handleClearKeyDown = useCallback(
      (e: React.KeyboardEvent) => {
        if (e.key === 'Enter' || e.key === ' ') {
          e.stopPropagation();
          e.preventDefault();
          onClear();
        }
      },
      [onClear],
    );

    const chipStyle = disabled
      ? chipDisabledStyle
      : active
        ? chipActiveStyle
        : chipBaseStyle;

    const displayText = active && valueSummary !== null
      ? `${label}: ${valueSummary}`
      : label;

    if (disabled) {
      return (
        <button
          ref={ref}
          type="button"
          data-ts-filter-chip=""
          data-disabled=""
          disabled
          style={chipStyle}
          aria-label={`Filter: ${label}`}
        >
          <span>{displayText}</span>
          <ChevronDown size={12} style={chevronStyle} aria-hidden />
        </button>
      );
    }

    return (
      <Popover>
        <Popover.Trigger>
          <button
            ref={ref}
            type="button"
            data-ts-filter-chip=""
            {...(active ? { 'data-active': '' } : {})}
            style={chipStyle}
            aria-label={`Filter: ${label}${active && valueSummary !== null ? `, current value: ${valueSummary}` : ''}`}
          >
            <span>{displayText}</span>
            {active ? (
              <span
                role="button"
                data-ts-filter-chip-clear=""
                style={clearButtonStyle}
                onClick={handleClear}
                onKeyDown={handleClearKeyDown}
                aria-label={`Clear ${label} filter`}
                tabIndex={0}
              >
                <X size={12} aria-hidden />
              </span>
            ) : (
              <ChevronDown size={12} style={chevronStyle} aria-hidden />
            )}
          </button>
        </Popover.Trigger>
        <Popover.Content side="bottom" align="start" sideOffset={4}>
          <div style={popoverContentStyle} data-ts-filter-chip-content="">
            {children}
          </div>
        </Popover.Content>
      </Popover>
    );
  },
);

FilterChip.displayName = 'FilterChip';
