import { useCallback, useMemo, useRef, type CSSProperties, type MouseEvent } from 'react';

/* -------------------------------------------------------------------------- */
/*  DepthChart                                                                 */
/*  SVG-rendered cumulative depth chart showing bid/ask curves with gradient.  */
/*  Uses --ts-depth-chart-* and --ts-depth-* tokens.                           */
/* -------------------------------------------------------------------------- */

export interface DepthLevel {
  /** Price at this level. */
  price: number;
  /** Cumulative volume up to this level from the best price. */
  cumulativeVolume: number;
}

export interface DepthChartProps {
  /** Bid levels sorted by price descending (best bid first). */
  bids: DepthLevel[];
  /** Ask levels sorted by price ascending (best ask first). */
  asks: DepthLevel[];
  /** Current mid-price for the center line. */
  midPrice: number;
  /** Width in CSS pixels. If omitted, fills container. */
  width?: number;
  /** Height in CSS pixels. Default 200. */
  height?: number;
  /** Price precision for tooltip formatting. */
  precision?: number;
  /** Whether to use smooth curve interpolation. Default false (step function). */
  smooth?: boolean;
  /** Called when the user clicks on the chart at a specific price. */
  onPriceClick?: (price: number) => void;
  /** Called with hover position for external tooltip rendering. */
  onHover?: (data: { price: number; volume: number; side: 'bid' | 'ask'; x: number; y: number } | null) => void;
  /** Additional class name. */
  className?: string;
}

/* ----- Styles ------------------------------------------------------------ */

const rootStyle: CSSProperties = {
  position: 'relative',
  overflow: 'hidden',
};

const emptyStateStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  height: '100%',
  color: 'var(--ts-text-tertiary)',
  fontSize: 'var(--ts-font-sm)',
  fontStyle: 'italic',
  userSelect: 'none',
};

/* ----- Path generation --------------------------------------------------- */

function buildStepPath(
  levels: DepthLevel[],
  side: 'bid' | 'ask',
  minPrice: number,
  maxPrice: number,
  maxVolume: number,
  chartWidth: number,
  chartHeight: number,
): string {
  if (levels.length === 0) return '';

  const priceRange = maxPrice - minPrice;
  if (priceRange <= 0 || maxVolume <= 0) return '';

  const toX = (price: number) =>
    ((price - minPrice) / priceRange) * chartWidth;
  const toY = (vol: number) =>
    chartHeight - (vol / maxVolume) * chartHeight;

  const sorted =
    side === 'bid'
      ? [...levels].sort((a, b) => b.price - a.price)
      : [...levels].sort((a, b) => a.price - b.price);

  const parts: string[] = [];
  parts.push(`M ${toX(sorted[0]!.price).toFixed(2)} ${chartHeight}`);
  parts.push(`L ${toX(sorted[0]!.price).toFixed(2)} ${toY(sorted[0]!.cumulativeVolume).toFixed(2)}`);

  for (let i = 1; i < sorted.length; i++) {
    const prev = sorted[i - 1]!;
    const curr = sorted[i]!;
    parts.push(`L ${toX(curr.price).toFixed(2)} ${toY(prev.cumulativeVolume).toFixed(2)}`);
    parts.push(`L ${toX(curr.price).toFixed(2)} ${toY(curr.cumulativeVolume).toFixed(2)}`);
  }

  const lastLevel = sorted[sorted.length - 1]!;
  parts.push(`L ${toX(lastLevel.price).toFixed(2)} ${chartHeight}`);
  parts.push('Z');

  return parts.join(' ');
}

function buildStrokePath(
  levels: DepthLevel[],
  side: 'bid' | 'ask',
  minPrice: number,
  maxPrice: number,
  maxVolume: number,
  chartWidth: number,
  chartHeight: number,
): string {
  if (levels.length === 0) return '';

  const priceRange = maxPrice - minPrice;
  if (priceRange <= 0 || maxVolume <= 0) return '';

  const toX = (price: number) =>
    ((price - minPrice) / priceRange) * chartWidth;
  const toY = (vol: number) =>
    chartHeight - (vol / maxVolume) * chartHeight;

  const sorted =
    side === 'bid'
      ? [...levels].sort((a, b) => b.price - a.price)
      : [...levels].sort((a, b) => a.price - b.price);

  const parts: string[] = [];
  parts.push(`M ${toX(sorted[0]!.price).toFixed(2)} ${toY(sorted[0]!.cumulativeVolume).toFixed(2)}`);

  for (let i = 1; i < sorted.length; i++) {
    const prev = sorted[i - 1]!;
    const curr = sorted[i]!;
    parts.push(`L ${toX(curr.price).toFixed(2)} ${toY(prev.cumulativeVolume).toFixed(2)}`);
    parts.push(`L ${toX(curr.price).toFixed(2)} ${toY(curr.cumulativeVolume).toFixed(2)}`);
  }

  return parts.join(' ');
}

/* ----- Component --------------------------------------------------------- */

export function DepthChart({
  bids,
  asks,
  midPrice,
  width,
  height = 200,
  precision = 2,
  smooth: _smooth = false,
  onPriceClick,
  onHover,
  className,
}: DepthChartProps): React.JSX.Element {
  const svgRef = useRef<SVGSVGElement>(null);

  const chartWidth = width ?? 400;

  // FROZEN axis ranges — axes only update every 2 seconds, not on every tick.
  // This eliminates chart jumping entirely. Data paths render within fixed axes.
  const axisRef = useRef({
    minPrice: midPrice * 0.995,
    maxPrice: midPrice * 1.005,
    maxVolume: 1,
    lastUpdate: 0,
  });

  // Update axes on a slow cadence (every 2s) or on first data
  const now = Date.now();
  const needsAxisUpdate =
    now - axisRef.current.lastUpdate > 2000 ||
    axisRef.current.lastUpdate === 0;

  if (needsAxisUpdate && (bids.length > 0 || asks.length > 0)) {
    const spreadPct = 0.005;
    const dataMin = bids.length > 0 ? Math.min(...bids.map((l) => l.price)) : midPrice * (1 - spreadPct);
    const dataMax = asks.length > 0 ? Math.max(...asks.map((l) => l.price)) : midPrice * (1 + spreadPct);
    const allVolumes = [...bids.map((l) => l.cumulativeVolume), ...asks.map((l) => l.cumulativeVolume)];
    const rawMax = allVolumes.length > 0 ? Math.max(...allVolumes) : 1;

    axisRef.current = {
      minPrice: Math.min(dataMin, midPrice * (1 - spreadPct)),
      maxPrice: Math.max(dataMax, midPrice * (1 + spreadPct)),
      maxVolume: Math.max(rawMax, 0.001),
      lastUpdate: now,
    };
  }

  const { minPrice, maxPrice, maxVolume } = axisRef.current;

  const bidFillPath = useMemo(
    () => buildStepPath(bids, 'bid', minPrice, maxPrice, maxVolume, chartWidth, height),
    [bids, minPrice, maxPrice, maxVolume, chartWidth, height],
  );

  const askFillPath = useMemo(
    () => buildStepPath(asks, 'ask', minPrice, maxPrice, maxVolume, chartWidth, height),
    [asks, minPrice, maxPrice, maxVolume, chartWidth, height],
  );

  const bidStrokePath = useMemo(
    () => buildStrokePath(bids, 'bid', minPrice, maxPrice, maxVolume, chartWidth, height),
    [bids, minPrice, maxPrice, maxVolume, chartWidth, height],
  );

  const askStrokePath = useMemo(
    () => buildStrokePath(asks, 'ask', minPrice, maxPrice, maxVolume, chartWidth, height),
    [asks, minPrice, maxPrice, maxVolume, chartWidth, height],
  );

  const midX = useMemo(() => {
    const priceRange = maxPrice - minPrice;
    return priceRange > 0 ? ((midPrice - minPrice) / priceRange) * chartWidth : chartWidth / 2;
  }, [midPrice, minPrice, maxPrice, chartWidth]);

  const getPriceAtX = useCallback(
    (clientX: number) => {
      const svg = svgRef.current;
      if (!svg) return null;
      const rect = svg.getBoundingClientRect();
      const x = clientX - rect.left;
      const priceRange = maxPrice - minPrice;
      if (priceRange <= 0) return null;
      const price = minPrice + (x / chartWidth) * priceRange;
      return { price, x, side: (price < midPrice ? 'bid' : 'ask') as 'bid' | 'ask' };
    },
    [minPrice, maxPrice, chartWidth, midPrice],
  );

  const findNearestVolume = useCallback(
    (price: number, side: 'bid' | 'ask'): number => {
      const levels = side === 'bid' ? bids : asks;
      if (levels.length === 0) return 0;

      let nearest = levels[0]!;
      let minDist = Math.abs(price - levels[0]!.price);
      for (let i = 1; i < levels.length; i++) {
        const dist = Math.abs(price - levels[i]!.price);
        if (dist < minDist) {
          minDist = dist;
          nearest = levels[i]!;
        }
      }
      return nearest.cumulativeVolume;
    },
    [bids, asks],
  );

  const handleMouseMove = useCallback(
    (e: MouseEvent<SVGSVGElement>) => {
      if (!onHover) return;
      const result = getPriceAtX(e.clientX);
      if (!result) {
        onHover(null);
        return;
      }
      const volume = findNearestVolume(result.price, result.side);
      const rect = svgRef.current?.getBoundingClientRect();
      onHover({
        price: parseFloat(result.price.toFixed(precision)),
        volume,
        side: result.side,
        x: result.x,
        y: rect ? e.clientY - rect.top : 0,
      });
    },
    [onHover, getPriceAtX, findNearestVolume, precision],
  );

  const handleMouseLeave = useCallback(() => {
    onHover?.(null);
  }, [onHover]);

  const handleClick = useCallback(
    (e: MouseEvent<SVGSVGElement>) => {
      if (!onPriceClick) return;
      const result = getPriceAtX(e.clientX);
      if (result) {
        onPriceClick(parseFloat(result.price.toFixed(precision)));
      }
    },
    [onPriceClick, getPriceAtX, precision],
  );

  const hasData = bids.length > 0 || asks.length > 0;

  if (!hasData) {
    return (
      <div
        data-ts-depth-chart=""
        className={className}
        style={{
          ...rootStyle,
          width: width ? `${width}px` : '100%',
          height: `${height}px`,
          background: 'var(--ts-depth-chart-bg)',
        }}
        data-testid="depth-chart"
      >
        <div style={emptyStateStyle} data-testid="depth-chart-empty">
          Awaiting depth data...
        </div>
      </div>
    );
  }

  return (
    <div
      data-ts-depth-chart=""
      className={className}
      style={{
        ...rootStyle,
        width: width ? `${width}px` : '100%',
        height: `${height}px`,
        background: 'var(--ts-depth-chart-bg)',
      }}
      data-testid="depth-chart"
    >
      <svg
        ref={svgRef}
        width={chartWidth}
        height={height}
        viewBox={`0 0 ${chartWidth} ${height}`}
        style={{ display: 'block', width: '100%', height: '100%' }}
        onMouseMove={handleMouseMove}
        onMouseLeave={handleMouseLeave}
        onClick={handleClick}
        data-testid="depth-chart-svg"
      >
        {/* Bid fill — green gradient area under the bid curve */}
        {bidFillPath && (
          <path
            d={bidFillPath}
            style={{ fill: 'rgba(34, 197, 94, 0.12)' }}
            data-testid="depth-bid-fill"
          />
        )}
        {/* Ask fill — red gradient area under the ask curve */}
        {askFillPath && (
          <path
            d={askFillPath}
            style={{ fill: 'rgba(239, 68, 68, 0.12)' }}
            data-testid="depth-ask-fill"
          />
        )}

        {/* Bid stroke — green line for bid curve */}
        {bidStrokePath && (
          <path
            d={bidStrokePath}
            fill="none"
            style={{ stroke: '#22c55e', strokeWidth: 2 }}
            data-testid="depth-bid-stroke"
          />
        )}
        {/* Ask stroke — red line for ask curve */}
        {askStrokePath && (
          <path
            d={askStrokePath}
            fill="none"
            style={{ stroke: '#ef4444', strokeWidth: 2 }}
            data-testid="depth-ask-stroke"
          />
        )}

        {/* Mid-price vertical dashed line */}
        <line
          x1={midX.toFixed(2)}
          y1="0"
          x2={midX.toFixed(2)}
          y2={height}
          style={{ stroke: '#555', strokeWidth: 1, strokeDasharray: '4 3' }}
          data-testid="depth-mid-line"
        />
      </svg>
    </div>
  );
}

DepthChart.displayName = 'DepthChart';
