import {
  type CSSProperties,
} from 'react';
import { Dialog, Tabs, Select, Checkbox, Toggle, Button } from '../primitives';
import { ColorPicker } from './ColorPicker';
import { CandlestickChart, BarChart3, SlidersHorizontal, Paintbrush } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  ChartSettingsDialog                                                       */
/*  Modal dialog for configuring chart appearance, candle colors, scales,     */
/*  status line, and appearance settings.                                     */
/*  Uses --ts-dialog-*, --ts-settings-panel-* tokens.                        */
/* -------------------------------------------------------------------------- */

export interface CandleColorSettings {
  /** Whether to color bars based on previous close. */
  colorByPreviousClose: boolean;
  /** Whether candle body is visible. */
  bodyVisible: boolean;
  /** Bullish body color. */
  bodyBullish: string;
  /** Bearish body color. */
  bodyBearish: string;
  /** Whether borders are visible. */
  bordersVisible: boolean;
  /** Bullish border color. */
  borderBullish: string;
  /** Bearish border color. */
  borderBearish: string;
  /** Whether wicks are visible. */
  wicksVisible: boolean;
  /** Bullish wick color. */
  wickBullish: string;
  /** Bearish wick color. */
  wickBearish: string;
}

export interface ScaleSettings {
  /** Price scale mode. */
  scaleMode: 'normal' | 'percentage' | 'logarithmic' | 'indexed';
  /** Whether to show grid lines. */
  showGridLines: boolean;
  /** Whether to show last price line. */
  showLastPriceLine: boolean;
  /** Whether to show bid/ask lines. */
  showBidAskLines: boolean;
  /** Whether to show countdown to bar close. */
  showCountdown: boolean;
}

export interface AppearanceSettings {
  /** Background type. */
  backgroundType: 'solid' | 'gradient';
  /** Background color. */
  backgroundColor: string;
  /** Gradient top color (when gradient). */
  gradientTopColor?: string;
  /** Whether to show watermark. */
  showWatermark: boolean;
  /** Whether to show navigation buttons. */
  showNavigationButtons: boolean;
  /** Whether to show top margin. */
  topMargin: boolean;
  /** Whether to show bottom margin. */
  bottomMargin: boolean;
}

export interface StatusLineSettings {
  /** Whether to show symbol name. */
  showSymbol: boolean;
  /** Whether to show OHLCV values. */
  showOHLCV: boolean;
  /** Whether to show change values. */
  showChange: boolean;
  /** Whether to show volume. */
  showVolume: boolean;
  /** Whether to show indicator values. */
  showIndicatorValues: boolean;
  /** Whether to show indicator arguments. */
  showIndicatorArguments: boolean;
}

export type SettingsTab = 'symbol' | 'status-line' | 'scales' | 'appearance';

export interface ChartSettingsDialogProps {
  /** Whether the dialog is open. */
  open: boolean;
  /** Called when the open state changes. */
  onOpenChange: (open: boolean) => void;
  /** Active settings tab. */
  activeTab: SettingsTab;
  /** Called when the active tab changes. */
  onTabChange: (tab: SettingsTab) => void;
  /** Candle/symbol color settings. */
  candleSettings: CandleColorSettings;
  /** Called when candle settings change. */
  onCandleSettingsChange: (settings: Partial<CandleColorSettings>) => void;
  /** Scale and line settings. */
  scaleSettings: ScaleSettings;
  /** Called when scale settings change. */
  onScaleSettingsChange: (settings: Partial<ScaleSettings>) => void;
  /** Appearance/canvas settings. */
  appearanceSettings: AppearanceSettings;
  /** Called when appearance settings change. */
  onAppearanceSettingsChange: (settings: Partial<AppearanceSettings>) => void;
  /** Status line display settings. */
  statusLineSettings: StatusLineSettings;
  /** Called when status line settings change. */
  onStatusLineSettingsChange: (settings: Partial<StatusLineSettings>) => void;
  /** Called when Apply/Ok is clicked. */
  onApply: () => void;
  /** Called when Cancel is clicked. */
  onCancel: () => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-chart-settings-styles';

function ensureChartSettingsStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-chart-settings-sidebar-item]:hover {
      background: var(--ts-command-item-bg-hover);
    }
    [data-ts-chart-settings-sidebar-item]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-chart-settings-sidebar-item][data-active] {
      background: var(--ts-command-item-bg-selected);
      color: var(--ts-accent-default);
      font-weight: var(--ts-font-weight-medium);
      border-left: 2px solid var(--ts-accent-default);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureChartSettingsStyles();
}

/* ----- Constants --------------------------------------------------------- */

const SIDEBAR_TABS: Array<{ value: SettingsTab; label: string; icon: React.ReactNode }> = [
  { value: 'symbol', label: 'Symbol', icon: <CandlestickChart size={16} /> },
  { value: 'status-line', label: 'Status Line', icon: <BarChart3 size={16} /> },
  { value: 'scales', label: 'Scales', icon: <SlidersHorizontal size={16} /> },
  { value: 'appearance', label: 'Appearance', icon: <Paintbrush size={16} /> },
];

const SCALE_MODE_OPTIONS = [
  { value: 'normal', label: 'Normal' },
  { value: 'percentage', label: 'Percentage' },
  { value: 'logarithmic', label: 'Logarithmic' },
  { value: 'indexed', label: 'Indexed to 100' },
];

const BACKGROUND_TYPE_OPTIONS = [
  { value: 'solid', label: 'Solid' },
  { value: 'gradient', label: 'Gradient' },
];

/* ----- Styles ------------------------------------------------------------ */

const visuallyHiddenStyle: CSSProperties = {
  position: 'absolute',
  width: 1,
  height: 1,
  padding: 0,
  margin: -1,
  overflow: 'hidden',
  clip: 'rect(0, 0, 0, 0)',
  whiteSpace: 'nowrap',
  borderWidth: 0,
};

const dialogContentStyle: CSSProperties = {
  maxWidth: 600,
  width: '90vw',
  padding: 0,
  display: 'flex',
  flexDirection: 'column',
  maxHeight: 500,
  overflow: 'hidden',
};

const bodyStyle: CSSProperties = {
  display: 'flex',
  flex: 1,
  minHeight: 0,
  overflow: 'hidden',
};

const sidebarStyle: CSSProperties = {
  width: 160,
  flexShrink: 0,
  borderRight: '1px solid var(--ts-border-subtle)',
  display: 'flex',
  flexDirection: 'column',
  paddingTop: 'var(--ts-space-2)',
  overflow: 'hidden',
};

const sidebarItemStyle: CSSProperties = {
  all: 'unset',
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  height: 36,
  padding: '0 var(--ts-space-3)',
  fontSize: 'var(--ts-font-sm)',
  fontFamily: 'inherit',
  color: 'var(--ts-text-primary)',
  cursor: 'pointer',
  whiteSpace: 'nowrap',
  transition: 'background 100ms, color 100ms',
  boxSizing: 'border-box',
  borderLeft: '2px solid transparent',
};

const sidebarIconStyle: CSSProperties = {
  width: 16,
  height: 16,
  flexShrink: 0,
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  color: 'var(--ts-text-secondary)',
};

const contentAreaStyle: CSSProperties = {
  flex: 1,
  overflowY: 'auto',
  padding: 'var(--ts-space-4)',
  scrollbarWidth: 'thin',
};

const sectionTitleStyle: CSSProperties = {
  fontSize: 'var(--ts-settings-panel-section-title-font-size)',
  fontWeight: 'var(--ts-settings-panel-section-title-font-weight)' as unknown as number,
  color: 'var(--ts-settings-panel-section-title)',
  fontFamily: 'inherit',
  textTransform: 'uppercase',
  letterSpacing: '0.05em',
  marginBottom: 'var(--ts-space-2)',
  marginTop: 'var(--ts-space-3)',
};

const settingRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  gap: 'var(--ts-space-3)',
  padding: 'var(--ts-space-2) 0',
};

const settingLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-primary)',
  fontFamily: 'inherit',
  flex: 1,
};

const colorPairStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const colorLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  fontFamily: 'inherit',
  whiteSpace: 'nowrap',
};

const footerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'flex-end',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-3) var(--ts-space-4)',
  borderTop: '1px solid var(--ts-border-subtle)',
};

/* ----- Component --------------------------------------------------------- */

export function ChartSettingsDialog({
  open,
  onOpenChange,
  activeTab,
  onTabChange,
  candleSettings,
  onCandleSettingsChange,
  scaleSettings,
  onScaleSettingsChange,
  appearanceSettings,
  onAppearanceSettingsChange,
  statusLineSettings,
  onStatusLineSettingsChange,
  onApply,
  onCancel,
}: ChartSettingsDialogProps): React.JSX.Element {

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content
        data-ts-chart-settings=""
        style={dialogContentStyle}
        showClose
        aria-describedby={undefined}
      >
        <Dialog.Title style={visuallyHiddenStyle}>Chart Settings</Dialog.Title>
        <div style={bodyStyle}>
          {/* Sidebar */}
          <div style={sidebarStyle} data-ts-chart-settings-sidebar="" role="navigation" aria-label="Settings tabs">
            {SIDEBAR_TABS.map((tab) => (
              <button
                key={tab.value}
                type="button"
                data-ts-chart-settings-sidebar-item=""
                {...(activeTab === tab.value ? { 'data-active': '' } : {})}
                aria-current={activeTab === tab.value ? 'true' : undefined}
                style={sidebarItemStyle}
                onClick={() => onTabChange(tab.value)}
              >
                <span style={sidebarIconStyle}>{tab.icon}</span>
                {tab.label}
              </button>
            ))}
          </div>

          {/* Content */}
          <div style={contentAreaStyle} data-ts-chart-settings-content="">
            {/* Symbol tab */}
            {activeTab === 'symbol' && (
              <div>
                <div style={sectionTitleStyle}>Candle Colors</div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={candleSettings.colorByPreviousClose}
                    onCheckedChange={(v) => onCandleSettingsChange({ colorByPreviousClose: v as boolean })}
                    label="Color bars based on previous close"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={candleSettings.bodyVisible}
                    onCheckedChange={(v) => onCandleSettingsChange({ bodyVisible: v as boolean })}
                    label="Body"
                  />
                  <div style={colorPairStyle}>
                    <span style={colorLabelStyle}>Bull</span>
                    <ColorPicker
                      value={candleSettings.bodyBullish}
                      onValueChange={(v) => onCandleSettingsChange({ bodyBullish: v })}
                      side="left"
                    />
                    <span style={colorLabelStyle}>Bear</span>
                    <ColorPicker
                      value={candleSettings.bodyBearish}
                      onValueChange={(v) => onCandleSettingsChange({ bodyBearish: v })}
                      side="left"
                    />
                  </div>
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={candleSettings.bordersVisible}
                    onCheckedChange={(v) => onCandleSettingsChange({ bordersVisible: v as boolean })}
                    label="Borders"
                  />
                  <div style={colorPairStyle}>
                    <span style={colorLabelStyle}>Bull</span>
                    <ColorPicker
                      value={candleSettings.borderBullish}
                      onValueChange={(v) => onCandleSettingsChange({ borderBullish: v })}
                      side="left"
                    />
                    <span style={colorLabelStyle}>Bear</span>
                    <ColorPicker
                      value={candleSettings.borderBearish}
                      onValueChange={(v) => onCandleSettingsChange({ borderBearish: v })}
                      side="left"
                    />
                  </div>
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={candleSettings.wicksVisible}
                    onCheckedChange={(v) => onCandleSettingsChange({ wicksVisible: v as boolean })}
                    label="Wicks"
                  />
                  <div style={colorPairStyle}>
                    <span style={colorLabelStyle}>Bull</span>
                    <ColorPicker
                      value={candleSettings.wickBullish}
                      onValueChange={(v) => onCandleSettingsChange({ wickBullish: v })}
                      side="left"
                    />
                    <span style={colorLabelStyle}>Bear</span>
                    <ColorPicker
                      value={candleSettings.wickBearish}
                      onValueChange={(v) => onCandleSettingsChange({ wickBearish: v })}
                      side="left"
                    />
                  </div>
                </div>
              </div>
            )}

            {/* Status Line tab */}
            {activeTab === 'status-line' && (
              <div>
                <div style={sectionTitleStyle}>Display</div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={statusLineSettings.showSymbol}
                    onCheckedChange={(v) => onStatusLineSettingsChange({ showSymbol: v as boolean })}
                    label="Symbol name"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={statusLineSettings.showOHLCV}
                    onCheckedChange={(v) => onStatusLineSettingsChange({ showOHLCV: v as boolean })}
                    label="OHLCV values"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={statusLineSettings.showChange}
                    onCheckedChange={(v) => onStatusLineSettingsChange({ showChange: v as boolean })}
                    label="Change values"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={statusLineSettings.showVolume}
                    onCheckedChange={(v) => onStatusLineSettingsChange({ showVolume: v as boolean })}
                    label="Volume"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={statusLineSettings.showIndicatorValues}
                    onCheckedChange={(v) => onStatusLineSettingsChange({ showIndicatorValues: v as boolean })}
                    label="Indicator values"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={statusLineSettings.showIndicatorArguments}
                    onCheckedChange={(v) => onStatusLineSettingsChange({ showIndicatorArguments: v as boolean })}
                    label="Indicator arguments"
                  />
                </div>
              </div>
            )}

            {/* Scales tab */}
            {activeTab === 'scales' && (
              <div>
                <div style={sectionTitleStyle}>Price Scale</div>

                <div style={settingRowStyle}>
                  <span style={settingLabelStyle}>Scale mode</span>
                  <div style={{ minWidth: 140 }}>
                    <Select
                      options={SCALE_MODE_OPTIONS}
                      value={scaleSettings.scaleMode}
                      onValueChange={(v) => onScaleSettingsChange({ scaleMode: v as ScaleSettings['scaleMode'] })}
                      size="sm"
                      label="Scale mode"
                    />
                  </div>
                </div>

                <div style={sectionTitleStyle}>Lines</div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={scaleSettings.showGridLines}
                    onCheckedChange={(v) => onScaleSettingsChange({ showGridLines: v as boolean })}
                    label="Grid lines"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={scaleSettings.showLastPriceLine}
                    onCheckedChange={(v) => onScaleSettingsChange({ showLastPriceLine: v as boolean })}
                    label="Last price line"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={scaleSettings.showBidAskLines}
                    onCheckedChange={(v) => onScaleSettingsChange({ showBidAskLines: v as boolean })}
                    label="Bid/Ask lines"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={scaleSettings.showCountdown}
                    onCheckedChange={(v) => onScaleSettingsChange({ showCountdown: v as boolean })}
                    label="Bar close countdown"
                  />
                </div>
              </div>
            )}

            {/* Appearance tab */}
            {activeTab === 'appearance' && (
              <div>
                <div style={sectionTitleStyle}>Background</div>

                <div style={settingRowStyle}>
                  <span style={settingLabelStyle}>Type</span>
                  <div style={{ minWidth: 120 }}>
                    <Select
                      options={BACKGROUND_TYPE_OPTIONS}
                      value={appearanceSettings.backgroundType}
                      onValueChange={(v) => onAppearanceSettingsChange({ backgroundType: v as AppearanceSettings['backgroundType'] })}
                      size="sm"
                      label="Background type"
                    />
                  </div>
                </div>

                <div style={settingRowStyle}>
                  <span style={settingLabelStyle}>Color</span>
                  <ColorPicker
                    value={appearanceSettings.backgroundColor}
                    onValueChange={(v) => onAppearanceSettingsChange({ backgroundColor: v })}
                    side="left"
                  />
                </div>

                {appearanceSettings.backgroundType === 'gradient' && (
                  <div style={settingRowStyle}>
                    <span style={settingLabelStyle}>Gradient top</span>
                    <ColorPicker
                      value={appearanceSettings.gradientTopColor ?? appearanceSettings.backgroundColor}
                      onValueChange={(v) => onAppearanceSettingsChange({ gradientTopColor: v })}
                      side="left"
                    />
                  </div>
                )}

                <div style={sectionTitleStyle}>Elements</div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={appearanceSettings.showWatermark}
                    onCheckedChange={(v) => onAppearanceSettingsChange({ showWatermark: v as boolean })}
                    label="Watermark"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={appearanceSettings.showNavigationButtons}
                    onCheckedChange={(v) => onAppearanceSettingsChange({ showNavigationButtons: v as boolean })}
                    label="Navigation buttons"
                  />
                </div>

                <div style={sectionTitleStyle}>Margins</div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={appearanceSettings.topMargin}
                    onCheckedChange={(v) => onAppearanceSettingsChange({ topMargin: v as boolean })}
                    label="Top margin"
                  />
                </div>

                <div style={settingRowStyle}>
                  <Checkbox
                    checked={appearanceSettings.bottomMargin}
                    onCheckedChange={(v) => onAppearanceSettingsChange({ bottomMargin: v as boolean })}
                    label="Bottom margin"
                  />
                </div>
              </div>
            )}
          </div>
        </div>

        {/* Footer */}
        <div style={footerStyle}>
          <Button variant="secondary" size="sm" onClick={onCancel}>
            Cancel
          </Button>
          <Button variant="primary" size="sm" onClick={onApply}>
            Ok
          </Button>
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

ChartSettingsDialog.displayName = 'ChartSettingsDialog';
