/** App channel identifiers used by Deskmodal for data distribution. */
export const CHANNELS = {
  /** High-frequency price ticks for all subscribed instruments. */
  PRICES: "deskmodal.prices",
  /** Order book snapshots and incremental updates. */
  ORDERBOOK: "deskmodal.orderbook",
  /** Recent trades stream. */
  TRADES: "deskmodal.trades",
  /** Alert trigger notifications broadcast to all apps. */
  ALERTS: "deskmodal.alerts",
  /** Custom indicator compilation results and output. */
  INDICATORS: "deskmodal.indicators",
  /** Internal workspace state synchronization between apps. */
  WORKSPACE_SYNC: "deskmodal.workspace-sync",
  /** Feed service status (exchange connection state, tick counts). */
  STATUS: "deskmodal.status",
  /** Data quality, connection health, and DQS updates (every 5s). */
  QUALITY: "deskmodal.quality",
  /** Derivatives data (funding rates, open interest, liquidations). */
  DERIVATIVES: "deskmodal.derivatives",
  /** DeFi protocol metrics and pool data. */
  DEFI: "deskmodal.defi",
} as const;

/** Type for any Deskmodal channel name. */
export type ChannelName = (typeof CHANNELS)[keyof typeof CHANNELS];

/** The prefix all Deskmodal app channel names share. */
export const CHANNEL_PREFIX = "deskmodal." as const;
